import { Stats, Attribute, Stroke, StartListEntry } from '../types';

// Helper to format time
export const formatTime = (seconds: number): string => {
    if (seconds >= 3599) return "59:59.99";

    const min = Math.floor(seconds / 60);
    const sec = Math.floor(seconds % 60);
    const ms = Math.floor((seconds - Math.floor(seconds)) * 100);
    return `${min > 0 ? `${min}:` : ''}${sec.toString().padStart(2, '0')}.${ms.toString().padStart(2, '0')}`;
};

// Physics Constants for simulation
const WORLD_RECORDS: Record<number, number> = { 50: 20.91, 100: 46.80, 200: 102.00 };
const BASE_TIMES: Record<number, number> = { 50: 45.0, 100: 105.0, 200: 240.0 }; // Times for a novice (stats ~10)

// Attribute Weights per Distance
// This defines the "DNA" of each race type
const DISTANCE_WEIGHTS: Record<number, Partial<Record<Attribute, number>>> = {
    50: {
        [Attribute.Strength]: 0.35,  // Explosive start & power
        [Attribute.Speed]: 0.35,     // Stroke rate
        [Attribute.Technique]: 0.20, // Efficiency
        [Attribute.Stamina]: 0.10,   // Barely matters
    },
    100: {
        [Attribute.Strength]: 0.20,
        [Attribute.Speed]: 0.25,
        [Attribute.Technique]: 0.30, // Technique becomes vital
        [Attribute.Stamina]: 0.25,   // Endurance starts to matter
    },
    200: {
        [Attribute.Strength]: 0.10,  // Muscle bulk can be drag
        [Attribute.Speed]: 0.15,
        [Attribute.Technique]: 0.35, // Efficiency is king
        [Attribute.Stamina]: 0.40,   // Aerobic capacity is queen
    }
};

export const calculateTime = (stats: Stats, distance: number, stroke: Stroke): number => {
    const weights = DISTANCE_WEIGHTS[distance] || DISTANCE_WEIGHTS[100];
    const baseTime = BASE_TIMES[distance] || 120;
    const minTime = WORLD_RECORDS[distance] || 50;

    // 1. Calculate Weighted Performance Score
    // We treat stats as if 100 is "Elite". The game allows going higher, which beats records.
    let performanceScore = 0;

    performanceScore += (stats[Attribute.Strength] * (weights[Attribute.Strength] || 0));
    performanceScore += (stats[Attribute.Speed] * (weights[Attribute.Speed] || 0));
    performanceScore += (stats[Attribute.Technique] * (weights[Attribute.Technique] || 0));
    performanceScore += (stats[Attribute.Stamina] * (weights[Attribute.Stamina] || 0));

    // 2. Mental Stat Logic (Variance)
    // High Mental = Consistent times close to your potential.
    // Low Mental = High volatility (could be great, usually bad).
    const mentalStat = stats[Attribute.Mental];
    const mentalFactor = Math.min(1, mentalStat / 100); // 0 to 1

    // Base variance is +/- 3% of the time for a novice, decreasing to +/- 0.5% for a pro
    const maxVariancePct = 0.05 - (mentalFactor * 0.04); 
    const randomVariance = (Math.random() * 2 - 1) * maxVariancePct; // -0.05 to +0.05

    // "In The Zone" Bonus: Very small chance to get a massive boost if Mental is high
    let zoneBonus = 0;
    if (Math.random() < (mentalStat / 500)) { // e.g. 50 Mental = 10% chance
        zoneBonus = 0.02; // 2% faster
    }

    // 3. Map Score to Time
    // We use a logarithmic decay curve. Gaining stats at low level helps A LOT.
    // Gaining stats at high level helps a little.

    // Normalize score roughly relative to 100.
    // If score is 10, improvement is small. If score is 100, improvement is huge.
    // Formula: Time = Base - (Diff * (1 - 1/(1 + k*Score)))
    // Where Diff = Base - Min
    const maxImprovement = baseTime - minTime;

    // Curve factor 'k'. 
    // If Score = 10, we want time to be approx Base.
    // If Score = 100, we want time to be approx Min.
    const k = 0.025; 
    const improvementRatio = 1 - (1 / (1 + (k * performanceScore)));

    let calculatedTime = baseTime - (maxImprovement * improvementRatio);

    // Apply Variance & Bonus
    calculatedTime = calculatedTime * (1 + randomVariance - zoneBonus);

    // Hard floor just in case (World Record - 10%)
    const hardFloor = minTime * 0.9;
    if (calculatedTime < hardFloor) calculatedTime = hardFloor + Math.random();

    return calculatedTime;
};

// Generate Heat Sheets with Spearhead seeding (Center lanes are fastest)
export const organizeHeats = (entries: StartListEntry[]): { heat: number, lane: number, entry: StartListEntry }[] => {
    // 1. Sort by entry time (Fastest to Slowest)
    const sorted = [...entries].sort((a, b) => a.entryTime - b.entryTime);

    // 2. Chunk into heats of 8
    const heats: StartListEntry[][] = [];
    for (let i = 0; i < sorted.length; i += 8) {
        heats.push(sorted.slice(i, i + 8));
    }

    // 3. Reverse heats so fastest heat is last
    heats.reverse();

    const result: { heat: number, lane: number, entry: StartListEntry }[] = [];
    const laneOrder = [4, 5, 3, 6, 2, 7, 1, 8]; // 1-based index

    heats.forEach((heatEntries, heatIndex) => {
        // heatEntries are sorted fast -> slow.
        // Assign to laneOrder.
        heatEntries.forEach((entry, idx) => {
            result.push({
                heat: heatIndex + 1,
                lane: laneOrder[idx],
                entry
            });
        });
    });

    return result;
};

import { Club, Swimmer, CompetitionTier, StartListEntry, RaceResult, Stroke } from '../types';
import { calculateTime } from './gameLogic';
import { PRESTIGE_REWARDS, DEFAULT_TIME, CASH_REWARDS } from '../constants';

const DB_KEY = 'NADARPRO_DB_V2';

interface Database {
    players: Record<string, Swimmer>;
    clubs: Record<string, Club>;
    // Key format: "TIER-DISTANCE-TIMESTAMP"
    raceEntries: Record<string, StartListEntry[]>; 
    // Key format: "TIER-DISTANCE-TIMESTAMP"
    raceResults: Record<string, RaceResult[]>;
}

const getDB = (): Database => {
    const raw = localStorage.getItem(DB_KEY);
    if (!raw) {
        return { players: {}, clubs: {}, raceEntries: {}, raceResults: {} };
    }
    const db = JSON.parse(raw);
    // Ensure raceResults exists for migration
    if (!db.raceResults) db.raceResults = {};
    return db;
};

const saveDB = (db: Database) => {
    localStorage.setItem(DB_KEY, JSON.stringify(db));
};

export const storageService = {
    // Player Methods
    getPlayer: (name: string): Swimmer | null => {
        const db = getDB();
        // FIX: Search through values (player objects) to find the name, 
        // as keys are timestamp IDs, not names.
        const player = Object.values(db.players).find(p => p.name.toLowerCase() === name.toLowerCase());
        return player || null;
    },

    getAllPlayers: (): Swimmer[] => {
        const db = getDB();
        return Object.values(db.players);
    },

    savePlayer: (swimmer: Swimmer) => {
        const db = getDB();
        db.players[swimmer.id] = swimmer;
        saveDB(db);
    },

    // Club Methods
    getClubs: (): Club[] => {
        const db = getDB();
        return Object.values(db.clubs);
    },

    getClub: (id: string): Club | null => {
        const db = getDB();
        return db.clubs[id] || null;
    },

    saveClub: (club: Club) => {
        const db = getDB();
        db.clubs[club.id] = club;
        saveDB(db);
    },

    deleteClub: (clubId: string) => {
        const db = getDB();
        if (db.clubs[clubId]) {
            delete db.clubs[clubId];
            saveDB(db);
        }
    },

    getClubMemberCount: (clubId: string): number => {
        const db = getDB();
        return Object.values(db.players).filter(p => p.clubId === clubId).length;
    },

    getClubMembers: (clubId: string): Swimmer[] => {
        const db = getDB();
        return Object.values(db.players).filter(p => p.clubId === clubId);
    },

    // Competition Methods
    registerForRace: (tier: CompetitionTier, distance: number, startTime: number, entry: StartListEntry) => {
        const db = getDB();
        const raceKey = `${tier}-${distance}-${startTime}`;

        if (!db.raceEntries[raceKey]) {
            db.raceEntries[raceKey] = [];
        }

        db.raceEntries[raceKey] = db.raceEntries[raceKey].filter(e => e.playerId !== entry.playerId);
        db.raceEntries[raceKey].push(entry);

        saveDB(db);
    },

    unregisterFromRace: (tier: CompetitionTier, distance: number, startTime: number, playerId: string) => {
        const db = getDB();
        const raceKey = `${tier}-${distance}-${startTime}`;

        if (db.raceEntries[raceKey]) {
            db.raceEntries[raceKey] = db.raceEntries[raceKey].filter(e => e.playerId !== playerId);
            saveDB(db);
        }
    },

    getRaceEntries: (tier: CompetitionTier, distance: number, startTime: number): StartListEntry[] => {
        const db = getDB();
        const raceKey = `${tier}-${distance}-${startTime}`;
        return db.raceEntries[raceKey] || [];
    },

    /**
     * PROCESS RACE RESULTS
     * This function runs when a user triggers the race result view.
     * It checks if results exist. If not, it calculates them for ALL players,
     * updates ALL players' profiles (history, PBs, XP), and saves the results permanently.
     */
    processRaceResults: (tier: CompetitionTier, distance: number, startTime: number, stroke: Stroke): RaceResult[] => {
        const db = getDB();
        const raceKey = `${tier}-${distance}-${startTime}`;

        // 1. If results already exist, return them (Persistent History)
        if (db.raceResults[raceKey]) {
            return db.raceResults[raceKey];
        }

        // 2. If not, calculate for everyone
        const entries = db.raceEntries[raceKey] || [];
        if (entries.length === 0) return [];

        const results: RaceResult[] = entries.map(entry => {
            let raceTime = entry.entryTime;

            // Check if player exists in DB to use real stats
            const player = db.players[entry.playerId];

            if (player) {
                // Calculate real time based on current stats
                raceTime = calculateTime(player.stats, distance, stroke);
            } else {
                // Bot simulation
                if (Math.abs(raceTime - DEFAULT_TIME) < 1) {
                    raceTime = (distance === 50 ? 30 : 65) + (Math.random() * 10 - 5);
                } else {
                    raceTime = entry.entryTime + (Math.random() * 1.5 - 0.75);
                }
            }

            return {
                rank: 0,
                swimmerName: entry.name,
                club: entry.club,
                time: raceTime,
                isPlayer: !!player,
                playerId: entry.playerId
            };
        });

        // Sort and Assign Ranks
        results.sort((a, b) => a.time - b.time);
        results.forEach((r, i) => r.rank = i + 1);

        // 3. UPDATE PROFILES FOR ALL PARTICIPANTS
        results.forEach(result => {
            if (result.playerId && db.players[result.playerId]) {
                const p = db.players[result.playerId];
                const pbKey = `${stroke}-${distance}`;
                const currentPB = p.personalBests[pbKey] || DEFAULT_TIME;

                // Update PB
                if (result.time < currentPB) {
                    p.personalBests[pbKey] = result.time;
                }

                // XP Calculation
                const xpGain = Math.max(10, 110 - (result.rank * 10)) * (
                    tier === CompetitionTier.World ? 5 :
                    tier === CompetitionTier.European ? 3 : 
                    1
                );

                p.xp += xpGain;
                p.level = Math.floor(p.xp / 100) + 1;

                // MONEY Calculation
                // Awards for Top 3, small award for 4th-8th (finalists)
                const rewards = CASH_REWARDS[tier] || [0, 0, 0, 0];
                let prizeMoney = 0;

                if (result.rank === 1) prizeMoney = rewards[0];
                else if (result.rank === 2) prizeMoney = rewards[1];
                else if (result.rank === 3) prizeMoney = rewards[2];
                else if (result.rank <= 8) prizeMoney = rewards[3];

                // Ensure legacy support
                if (p.money === undefined) p.money = 0;
                p.money += prizeMoney;

                // Add to History
                p.history.unshift({
                    id: raceKey,
                    tier,
                    stroke,
                    distance,
                    time: result.time,
                    rank: result.rank,
                    date: 1, // Simplified day tracking
                    realTimeDate: Date.now()
                });

                // Update Medals (Triangulars do NOT count for medals)
                if (tier !== CompetitionTier.Triangular) {
                    if (result.rank === 1) p.medals.gold++;
                    if (result.rank === 2) p.medals.silver++;
                    if (result.rank === 3) p.medals.bronze++;
                }

                // Club Prestige (Controlled by constants, but logic here applies the array)
                // Triangular rewards are set to 0 in constants.ts
                if (result.rank <= 3 && p.clubId && db.clubs[p.clubId]) {
                    const prestigeRewards = PRESTIGE_REWARDS[tier];
                    if (prestigeRewards) {
                        db.clubs[p.clubId].prestige += prestigeRewards[result.rank - 1];
                    }
                }
            }
        });

        // 4. Save everything
        db.raceResults[raceKey] = results;
        saveDB(db);

        return results;
    },

    // Get all results for a specific competition time block (for the document view)
    getOfficialResults: (tier: CompetitionTier, startTime: number): { distance: number, results: RaceResult[] }[] => {
        const db = getDB();
        const distances = [50, 100, 200];
        const output: { distance: number, results: RaceResult[] }[] = [];

        distances.forEach(dist => {
            const key = `${tier}-${dist}-${startTime}`;
            if (db.raceResults[key]) {
                output.push({ distance: dist, results: db.raceResults[key] });
            }
        });

        return output;
    }
};

import React, { useState, useEffect } from 'react';
import { COMPETITION_CONFIG, STROKES, MINIMUM_TIMES, DISTANCES, DEFAULT_TIME } from '../constants';
import { CompetitionTier, Stroke, RaceResult, PastRace, Swimmer, StartListEntry } from '../types';
import { formatTime, organizeHeats } from '../services/gameLogic';
import { storageService } from '../services/storageService';

interface CompetitionProps {
    swimmer: Swimmer;
    day: number;
    onRaceComplete: (result: PastRace) => void;
    onUpdateSwimmer: () => void;
}

export const Competition: React.FC<CompetitionProps> = ({ swimmer, day, onRaceComplete, onUpdateSwimmer }) => {
    const [selectedTier, setSelectedTier] = useState<CompetitionTier | null>(null);
    const [selectedDist, setSelectedDist] = useState<number>(100);
    const selectedStroke = Stroke.Freestyle;

    const [viewMode, setViewMode] = useState<'menu' | 'startList' | 'racing' | 'officialDocs'>('menu');
    const [raceResults, setRaceResults] = useState<RaceResult[] | null>(null);
    const [officialDocs, setOfficialDocs] = useState<{ distance: number, results: RaceResult[] }[]>([]);

    const [now, setNow] = useState(Date.now());
    const [entries, setEntries] = useState<StartListEntry[]>([]);

    useEffect(() => {
        const interval = setInterval(() => setNow(Date.now()), 1000);
        return () => clearInterval(interval);
    }, []);

    const getNextRaceTime = (tierId: CompetitionTier, interval: number) => {
        return Math.ceil(now / interval) * interval;
    };

    const getPrevRaceTime = (tierId: CompetitionTier, interval: number) => {
        return Math.floor(now / interval) * interval;
    };

    const getTimeUntil = (targetTime: number) => {
        const diff = targetTime - now;
        if (diff < 0) return "En curso";
        const hours = Math.floor(diff / 3600000);
        const minutes = Math.floor((diff % 3600000) / 60000);
        const seconds = Math.floor((diff % 60000) / 1000);
        return `${hours}h ${minutes}m ${seconds}s`;
    };

    const hasQualifyingTime = (tier: CompetitionTier, dist: number): boolean => {
        const tierMins = MINIMUM_TIMES[tier];
        if (tierMins[dist] === 999) return true;
        const pb = swimmer.personalBests[`${Stroke.Freestyle}-${dist}`] || DEFAULT_TIME;
        return pb <= tierMins[dist];
    };

    const getRegistrationStatus = (tier: CompetitionTier, dist: number) => {
        const nextStart = getNextRaceTime(tier, COMPETITION_CONFIG.find(c => c.id === tier)!.interval);
        const raceEntries = storageService.getRaceEntries(tier, dist, nextStart);
        return raceEntries.some(e => e.playerId === swimmer.id);
    };

    const getRegisteredCount = (tier: CompetitionTier) => {
        const nextStart = getNextRaceTime(tier, COMPETITION_CONFIG.find(c => c.id === tier)!.interval);
        let count = 0;
        DISTANCES.forEach(dist => {
            const raceEntries = storageService.getRaceEntries(tier, dist, nextStart);
            if (raceEntries.some(e => e.playerId === swimmer.id)) {
                count++;
            }
        });
        return count;
    };

    const handleRegister = (tier: CompetitionTier, dist: number, interval: number) => {
        const currentCount = getRegisteredCount(tier);
        if (currentCount >= 2) {
            alert("Solo puedes inscribirte en un máximo de 2 pruebas por competición.");
            return;
        }

        const myEntryTime = swimmer.personalBests[`${selectedStroke}-${dist}`] || DEFAULT_TIME;
        const nextStart = getNextRaceTime(tier, interval);
        const clubs = storageService.getClubs();
        const myClub = clubs.find(c => c.id === swimmer.clubId);

        const myEntry: StartListEntry = {
            playerId: swimmer.id,
            name: swimmer.name,
            club: myClub ? myClub.name : "Sin Club",
            entryTime: myEntryTime, 
            isPlayer: true
        };

        storageService.registerForRace(tier, dist, nextStart, myEntry);
        onUpdateSwimmer();
    };

    const handleUnregister = (tier: CompetitionTier, dist: number, interval: number) => {
        const nextStart = getNextRaceTime(tier, interval);
        storageService.unregisterFromRace(tier, dist, nextStart, swimmer.id);
        onUpdateSwimmer();
    };

    const openStartList = (tier: CompetitionTier, dist: number) => {
        setSelectedTier(tier);
        setSelectedDist(dist);
        const nextStart = getNextRaceTime(tier, COMPETITION_CONFIG.find(c => c.id === tier)!.interval);
        const raceEntries = storageService.getRaceEntries(tier, dist, nextStart);
        setEntries(raceEntries);
        setViewMode('startList');
    };

    const handleProcessRace = () => {
        if (!selectedTier) return;

        // Use nextStart logic (Assuming the race just happened or is happening)
        const interval = COMPETITION_CONFIG.find(c => c.id === selectedTier)!.interval;
        const raceTime = getNextRaceTime(selectedTier, interval);

        // This triggers the heavy calculation in Storage Service and updates DB
        const results = storageService.processRaceResults(selectedTier, selectedDist, raceTime, selectedStroke);

        setRaceResults(results);
        setViewMode('racing');

        // Find my result to trigger callback
        const myResult = results.find(r => r.playerId === swimmer.id);
        if (myResult) {
            onRaceComplete({
                id: Date.now().toString(),
                tier: selectedTier,
                stroke: selectedStroke,
                distance: selectedDist,
                time: myResult.time,
                rank: myResult.rank,
                date: day,
                realTimeDate: Date.now()
            });
        }
    };

    const handleViewOfficialDocs = (tier: CompetitionTier) => {
        const interval = COMPETITION_CONFIG.find(c => c.id === tier)!.interval;
        // Check previous block, maybe it just finished
        let targetTime = getNextRaceTime(tier, interval);

        // If "Next Race" is in the future (> 5 mins), show results from PREVIOUS race
        if (targetTime - now > 5 * 60 * 1000) {
            targetTime = getPrevRaceTime(tier, interval);
        }

        // We need to force process them if they haven't been processed
        // But usually we just want to read what's there. 
        // For this feature, let's process 50 and 100 just in case someone missed it.
        [50, 100].forEach(d => storageService.processRaceResults(tier, d, targetTime, Stroke.Freestyle));

        const docs = storageService.getOfficialResults(tier, targetTime);
        setOfficialDocs(docs);
        setSelectedTier(tier);
        setViewMode('officialDocs');
    };

    const renderOfficialDocs = () => {
        if (!selectedTier) return null;

        return (
            <div className="bg-white rounded-2xl shadow-2xl overflow-hidden animate-fade-in max-w-5xl mx-auto border border-slate-200">
                <div className="bg-slate-900 p-8 text-white flex justify-between items-center print:hidden">
                    <div>
                        <div className="uppercase tracking-widest text-xs font-bold text-slate-400 mb-2">Federación de Natación</div>
                        <h2 className="text-3xl font-serif font-bold">Acta Oficial de Resultados</h2>
                        <p className="opacity-70 mt-1">{selectedTier} - {new Date().toLocaleDateString()}</p>
                    </div>
                    <button onClick={() => setViewMode('menu')} className="bg-white text-slate-900 px-6 py-2 rounded font-bold hover:bg-slate-100">Cerrar</button>
                </div>

                <div className="p-8 bg-white min-h-[600px] overflow-y-auto">
                    {officialDocs.length === 0 ? (
                        <div className="text-center text-slate-500 py-12">
                            Aún no hay resultados oficiales procesados para este ciclo.
                        </div>
                    ) : (
                        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                            {officialDocs.map(doc => (
                                <div key={doc.distance} className="border border-slate-200 rounded-lg p-6 shadow-sm">
                                    <h3 className="text-xl font-bold border-b pb-4 mb-4 flex justify-between">
                                        <span>{doc.distance}m Libres</span>
                                        <span className="text-sm font-normal text-slate-500">{doc.results.length} Participantes</span>
                                    </h3>
                                    <table className="w-full text-sm">
                                        <thead>
                                            <tr className="text-slate-400 text-left text-xs uppercase">
                                                <th className="pb-2 w-10">Pos</th>
                                                <th className="pb-2">Nadador</th>
                                                <th className="pb-2 text-right">Tiempo</th>
                                            </tr>
                                        </thead>
                                        <tbody>
                                            {doc.results.map((r) => (
                                                <tr key={r.rank} className={`border-b last:border-0 ${r.playerId === swimmer.id ? 'bg-blue-50' : ''}`}>
                                                    <td className="py-2 font-mono font-bold text-slate-400">{r.rank}</td>
                                                    <td className="py-2">
                                                        <div className="font-bold text-slate-700">{r.swimmerName}</div>
                                                        <div className="text-xs text-slate-500">{r.club}</div>
                                                    </td>
                                                    <td className="py-2 text-right font-mono font-bold text-slate-800">{formatTime(r.time)}</td>
                                                </tr>
                                            ))}
                                        </tbody>
                                    </table>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>
        );
    }

    const renderStartList = () => {
        if (!selectedTier) return null;
        const tierConfig = COMPETITION_CONFIG.find(c => c.id === selectedTier)!;
        const nextStart = getNextRaceTime(selectedTier, tierConfig.interval);

        const seededEntries = organizeHeats(entries);
        const heats: Record<number, typeof seededEntries> = {};
        seededEntries.forEach(e => {
            if (!heats[e.heat]) heats[e.heat] = [];
            heats[e.heat].push(e);
        });

        const raceHasStarted = now >= nextStart;

        return (
            <div className="bg-white rounded-2xl shadow-xl overflow-hidden animate-fade-in max-w-4xl mx-auto">
                <div className="bg-slate-800 p-6 text-white flex justify-between items-center">
                    <div>
                        <h2 className="text-2xl font-bold">Listas de Salida</h2>
                        <p className="opacity-80">{selectedDist}m {selectedStroke} - {selectedTier}</p>
                    </div>
                    <button onClick={() => setViewMode('menu')} className="text-sm bg-white/20 px-4 py-2 rounded hover:bg-white/30">Cerrar</button>
                </div>

                <div className="p-6 overflow-y-auto max-h-[600px] space-y-8">
                    {Object.keys(heats).length === 0 && (
                        <div className="text-center text-slate-500 py-8">
                            No hay nadadores registrados aún.
                        </div>
                    )}
                    {Object.keys(heats).map(heatNum => {
                        const hEntries = heats[parseInt(heatNum)].sort((a,b) => a.lane - b.lane);
                        return (
                            <div key={heatNum} className="border rounded-xl overflow-hidden">
                                <div className="bg-slate-100 px-4 py-2 font-bold text-slate-700 border-b">
                                    Serie {heatNum}
                                </div>
                                <table className="w-full text-left text-sm">
                                    <thead>
                                        <tr className="bg-slate-50 text-slate-500">
                                            <th className="px-4 py-2 w-16">Calle</th>
                                            <th className="px-4 py-2">Nadador</th>
                                            <th className="px-4 py-2">Club</th>
                                            <th className="px-4 py-2 text-right">Marca</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {hEntries.map((row) => (
                                            <tr key={row.lane} className={`border-b last:border-0 ${row.entry.isPlayer ? 'bg-blue-100 font-bold' : ''}`}>
                                                <td className="px-4 py-3 font-mono font-bold text-center bg-slate-50 border-r">{row.lane}</td>
                                                <td className="px-4 py-3">{row.entry.name}</td>
                                                <td className="px-4 py-3 text-slate-500">{row.entry.club}</td>
                                                <td className="px-4 py-3 text-right font-mono">{formatTime(row.entry.entryTime)}</td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                        );
                    })}
                </div>
                <div className="p-4 bg-slate-50 border-t flex justify-center">
                    {raceHasStarted ? (
                        <button 
                            onClick={handleProcessRace}
                            className="bg-green-600 hover:bg-green-700 text-white font-bold py-3 px-12 rounded-full shadow-lg animate-pulse"
                        >
                            ¡Comenzar Carrera y Ver Resultados!
                        </button>
                    ) : (
                         <div className="flex flex-col items-center">
                             <div className="text-slate-500 font-bold text-sm mb-1 uppercase">La competición comienza en</div>
                             <div className="font-mono text-2xl font-bold text-blue-600">
                                {getTimeUntil(nextStart)}
                             </div>
                         </div>
                    )}
                </div>
            </div>
        );
    };

    if (viewMode === 'officialDocs') return renderOfficialDocs();
    if (viewMode === 'startList') return renderStartList();

    if (viewMode === 'racing' && raceResults) {
        return (
             <div className="max-w-3xl mx-auto bg-white rounded-2xl shadow-xl overflow-hidden animate-fade-in">
                <div className="bg-blue-600 p-6 text-white text-center">
                    <h2 className="text-3xl font-bold mb-2">Resultados Finales</h2>
                    <p className="opacity-90">{selectedDist}m {selectedStroke} - {selectedTier}</p>
                </div>
                <div className="p-6">
                    <div className="overflow-x-auto max-h-[500px]">
                        <table className="w-full text-left">
                            <thead className="sticky top-0 bg-white shadow-sm">
                                <tr className="text-sm text-slate-500 border-b">
                                    <th className="py-2">Pos</th>
                                    <th className="py-2">Nadador</th>
                                    <th className="py-2 text-right">Tiempo</th>
                                </tr>
                            </thead>
                            <tbody>
                                {raceResults.map((result) => (
                                    <tr key={result.rank} className={`border-b last:border-0 ${result.isPlayer ? 'bg-blue-50 font-bold text-blue-900' : ''}`}>
                                        <td className="py-3 pl-2">
                                            <span className={`inline-flex items-center justify-center w-8 h-8 rounded-full text-sm ${result.rank === 1 ? 'bg-yellow-400 text-yellow-900' : result.rank <= 3 ? 'bg-slate-200' : ''}`}>
                                                {result.rank}
                                            </span>
                                        </td>
                                        <td className="py-3">{result.swimmerName}</td>
                                        <td className="py-3 text-right font-mono">{formatTime(result.time)}</td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                    <button onClick={() => { setRaceResults(null); setViewMode('menu'); setSelectedTier(null); }} className="w-full mt-6 py-3 bg-slate-800 text-white rounded-lg font-bold">Volver</button>
                </div>
            </div>
        );
    }

    return (
        <div className="space-y-8 animate-fade-in">
             <div className="max-w-4xl mx-auto space-y-4">
                {COMPETITION_CONFIG.map((tier) => {
                    const nextRaceStart = getNextRaceTime(tier.id, tier.interval);
                    // Check if previous race results might be available (last 24h for example, or simply if it happened)
                    // We simply check if we are PAST the start of the previous block
                    const prevRaceStart = getPrevRaceTime(tier.id, tier.interval);

                    const registeredCount = getRegisteredCount(tier.id);

                    return (
                        <div key={tier.id} className="w-full text-left p-6 rounded-xl border relative overflow-hidden bg-white border-slate-200 shadow-sm">
                            <div className="flex flex-col md:flex-row justify-between items-start md:items-center relative z-10 gap-4">
                                <div>
                                    <h4 className="font-bold text-xl text-slate-800">{tier.name}</h4>
                                    <div className="text-sm text-slate-500 flex flex-col md:flex-row gap-2 md:gap-4 mt-1">
                                        <span className="font-mono text-blue-600 font-bold">Próxima: {getTimeUntil(nextRaceStart)}</span>
                                    </div>
                                    <div className="mt-2 text-xs font-bold text-slate-400">
                                        Inscripciones: <span className={registeredCount >= 2 ? 'text-red-500' : 'text-slate-600'}>{registeredCount}/2</span>
                                    </div>
                                    <div className="mt-2">
                                        <button 
                                            onClick={() => handleViewOfficialDocs(tier.id)}
                                            className="text-xs font-bold text-slate-500 hover:text-blue-600 underline"
                                        >
                                            📄 Ver Resultados Oficiales (Anteriores)
                                        </button>
                                    </div>
                                </div>

                                <div className="flex gap-2">
                                    {DISTANCES.map(dist => {
                                        const isUnlocked = hasQualifyingTime(tier.id, dist);
                                        const isRegistered = getRegistrationStatus(tier.id, dist);
                                        const raceHasStarted = isRegistered && now >= nextRaceStart;

                                        return (
                                            <div key={dist} className="flex flex-col items-center">
                                                <span className="text-xs font-bold text-slate-400 mb-1">{dist}m</span>
                                                {isUnlocked ? (
                                                     raceHasStarted ? (
                                                        <button onClick={() => openStartList(tier.id, dist)} className="bg-green-600 text-white px-4 py-2 rounded-lg font-bold text-sm animate-pulse shadow-green-200 shadow-lg">
                                                            COMPETIR
                                                        </button>
                                                    ) : isRegistered ? (
                                                        <div className="flex gap-1">
                                                            <button onClick={() => openStartList(tier.id, dist)} className="bg-blue-50 text-blue-600 border border-blue-200 px-3 py-2 rounded-lg font-bold text-sm hover:bg-blue-100">
                                                                Ver Listas
                                                            </button>
                                                            <button 
                                                                onClick={() => handleUnregister(tier.id, dist, tier.interval)}
                                                                className="bg-red-50 text-red-600 border border-red-200 px-2 py-2 rounded-lg font-bold text-sm hover:bg-red-100"
                                                                title="Cancelar Inscripción"
                                                            >
                                                                ✕
                                                            </button>
                                                        </div>
                                                    ) : (
                                                        <button 
                                                            onClick={() => handleRegister(tier.id, dist, tier.interval)} 
                                                            className={`px-4 py-2 rounded-lg font-bold text-sm text-white ${registeredCount >= 2 ? 'bg-slate-300 cursor-not-allowed' : 'bg-slate-800 hover:bg-slate-700'}`}
                                                            disabled={registeredCount >= 2}
                                                        >
                                                            Inscribirse
                                                        </button>
                                                    )
                                                ) : (
                                                    <div className="bg-gray-100 text-gray-400 px-4 py-2 rounded-lg font-bold text-xs border border-gray-200 text-center w-[100px]">
                                                        Bloqueado<br/>
                                                        <span className="text-[10px] opacity-75">Mín: {formatTime(MINIMUM_TIMES[tier.id][dist])}</span>
                                                    </div>
                                                )}
                                            </div>
                                        );
                                    })}
                                </div>
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
    );
};

