interface RankedPlayer {
    rank: number;
    swimmerName: string;
    clubName: string;
    time: number;
    swimmerId: string;
}

interface RankingProps {
    onViewPlayer?: (playerId: string) => void;
}

export const Ranking: React.FC<RankingProps> = ({ onViewPlayer }) => {
    const [tab, setTab] = useState<'clubs' | 'records'>('clubs');
    const [selectedDistance, setSelectedDistance] = useState<number>(50); // Default 50m
    const [clubs, setClubs] = useState<Club[]>([]);
    const [rankings, setRankings] = useState<RankedPlayer[]>([]);

    useEffect(() => {
        // Load Clubs sorted by Prestige
        const loadedClubs = storageService.getClubs().sort((a, b) => b.prestige - a.prestige);
        setClubs(loadedClubs);
    }, []);

    useEffect(() => {
        if (tab === 'records') {
            const players = storageService.getAllPlayers();
            const loadedClubs = storageService.getClubs();

            const key = `${Stroke.Freestyle}-${selectedDistance}`;

            const ranked: RankedPlayer[] = players
                .map(p => {
                    const time = p.personalBests[key];
                    if (!time) return null; // No time for this distance

                    const club = p.clubId ? loadedClubs.find(c => c.id === p.clubId) : null;

                    return {
                        swimmerName: p.name,
                        swimmerId: p.id,
                        clubName: club ? club.name : 'Sin Club',
                        time: time,
                        rank: 0
                    };
                })
                .filter((p): p is RankedPlayer => p !== null)
                .sort((a, b) => a.time - b.time);

            // Assign ranks
            ranked.forEach((p, i) => p.rank = i + 1);

            setRankings(ranked);
        }
    }, [tab, selectedDistance]);

    return (
        <div className="space-y-6 animate-fade-in">
