import React, { useState, useEffect } from 'react';
import { Attribute, Club, Swimmer } from '../types';
import { CLUB_COLORS, CLUB_ICONS } from '../constants';
import { storageService } from '../services/storageService';

interface ClubManagerProps {
    swimmer: Swimmer;
    availableClubs: Club[];
    onUpdateSwimmer: (swimmer: Swimmer) => void;
    onViewPlayer?: (playerId: string) => void;
}

export const ClubManager: React.FC<ClubManagerProps> = ({ swimmer, availableClubs, onUpdateSwimmer, onViewPlayer }) => {
    const [view, setView] = useState<'current' | 'list' | 'create' | 'edit'>('current');
    const [members, setMembers] = useState<Swimmer[]>([]);

    // Form State for Create/Edit
    const [formName, setFormName] = useState('');
    const [selectedIcon, setSelectedIcon] = useState(CLUB_ICONS[0]);
    const [selectedColorIndex, setSelectedColorIndex] = useState(0);

    const currentClub = availableClubs.find(c => c.id === swimmer.clubId);

    // Initialize edit form when opening edit view
    useEffect(() => {
        if (view === 'edit' && currentClub) {
            setFormName(currentClub.name);
            setSelectedIcon(currentClub.logo.icon);
            const colorIdx = CLUB_COLORS.findIndex(c => c.bg === currentClub.logo.bgColor);
            setSelectedColorIndex(colorIdx >= 0 ? colorIdx : 0);
        }
    }, [view, currentClub]);

    // Load members when viewing current club
    useEffect(() => {
        if (view === 'current' && currentClub) {
            setMembers(storageService.getClubMembers(currentClub.id));
        }
    }, [view, currentClub]);

    const handleCreate = (e: React.FormEvent) => {
        e.preventDefault();
        const colorData = CLUB_COLORS[selectedColorIndex];
        const newClub: Club = {
            id: Date.now().toString(),
            name: formName,
            description: `Club fundado por ${swimmer.name}`,
            prestige: 0,
            logo: {
                icon: selectedIcon,
                color: colorData.hex,
                bgColor: colorData.bg
            },
            ownerId: swimmer.id
        };

        storageService.saveClub(newClub);

        // Auto join
        const updatedSwimmer = { ...swimmer, clubId: newClub.id };
        storageService.savePlayer(updatedSwimmer);
        onUpdateSwimmer(updatedSwimmer);

        setView('current');
    };

    const handleEdit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!currentClub) return;

        const colorData = CLUB_COLORS[selectedColorIndex];
        const updatedClub: Club = {
            ...currentClub,
            name: formName,
            logo: {
                icon: selectedIcon,
                color: colorData.hex,
                bgColor: colorData.bg
            }
        };

        storageService.saveClub(updatedClub);
        onUpdateSwimmer(swimmer); // Trigger refresh
        setView('current');
    };

    const handleJoin = (club: Club) => {
        const updatedSwimmer = { ...swimmer, clubId: club.id };
        storageService.savePlayer(updatedSwimmer);
        onUpdateSwimmer(updatedSwimmer);
        setView('current');
    };

    const handleLeave = () => {
        if (!currentClub) return;
        const oldClubId = currentClub.id;

        // 1. Remove player from club
        const updatedSwimmer = { ...swimmer, clubId: null };
        storageService.savePlayer(updatedSwimmer);

        // 2. Check remaining members. Note: getClubMemberCount reads from DB, so we must save player first.
        const remainingMembers = storageService.getClubMemberCount(oldClubId);

        if (remainingMembers === 0) {
            // Delete club if empty
            storageService.deleteClub(oldClubId);
        }

        onUpdateSwimmer(updatedSwimmer);
        setView('list'); // Go to list view after leaving
    };

    return (
        <div className="space-y-6 animate-fade-in">
            <div className="text-center mb-8">
                <h2 className="text-3xl font-black sport-font text-slate-800 uppercase italic">Sede del Club</h2>
                <p className="text-sm text-slate-600 font-medium">Únete a otros jugadores reales o crea tu legado.</p>
            </div>

            <div className="flex justify-center gap-4 mb-6">
                <button 
                    onClick={() => setView('current')}
                    className={`px-5 py-2 rounded-full text-sm font-bold transition-all border ${view === 'current' ? 'bg-blue-600 text-white border-blue-600 shadow-md' : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50'}`}
                >
                    Mi Club
                </button>
                <button 
                    onClick={() => setView('list')}
                    className={`px-5 py-2 rounded-full text-sm font-bold transition-all border ${view === 'list' ? 'bg-blue-600 text-white border-blue-600 shadow-md' : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50'}`}
                >
                    Buscar Club
                </button>
                {!swimmer.clubId && (
                    <button 
                        onClick={() => { setFormName(''); setView('create'); }}
                        className={`px-5 py-2 rounded-full text-sm font-bold transition-all border ${view === 'create' ? 'bg-blue-600 text-white border-blue-600 shadow-md' : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50'}`}
                    >
                        Fundar Club
                    </button>
                )}
            </div>

            {view === 'current' && (
                <div className="space-y-8 animate-fade-in">
                    <div className="glass-panel p-8 rounded-3xl shadow-lg border border-white/50 text-center max-w-lg mx-auto relative overflow-hidden">
                         <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-blue-400 via-cyan-400 to-blue-400"></div>
                        {currentClub ? (
                            <>
                                <div className={`w-28 h-28 rounded-full mx-auto flex items-center justify-center mb-6 text-5xl shadow-2xl border-4 border-white ${currentClub.logo.bgColor}`}>
                                    <span className={currentClub.logo.color}>{currentClub.logo.icon}</span>
                                </div>
                                <h3 className="text-3xl font-black sport-font text-slate-800 mb-2 leading-none">{currentClub.name}</h3>
                                <p className="text-slate-500 mb-6 font-medium">{currentClub.description}</p>

                                <div className="flex justify-center mb-8">
                                    <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 min-w-[150px]">
                                        <div className="text-xs text-slate-400 uppercase font-bold tracking-wider mb-1">Prestigio</div>
                                        <div className="text-4xl font-black text-slate-800 mono-font">{currentClub.prestige}</div>
                                        <div className="text-[10px] text-slate-400 mt-1 uppercase font-bold">Puntos de Club</div>
                                    </div>
                                </div>

                                <div className="flex gap-4 justify-center">
                                    {swimmer.id === currentClub.ownerId && (
                                        <button 
                                            onClick={() => setView('edit')}
                                            className="px-4 py-2 bg-slate-100 text-slate-700 font-bold rounded-lg hover:bg-slate-200"
                                        >
                                            Editar Club
                                        </button>
                                    )}
                                    <button 
                                        onClick={handleLeave}
                                        className="px-4 py-2 bg-red-50 text-red-600 font-bold rounded-lg hover:bg-red-100 border border-red-100"
                                    >
                                        Abandonar
                                    </button>
                                </div>
                            </>
                        ) : (
                            <div className="py-12">
                                <p className="text-slate-500 mb-4 font-bold text-lg">No perteneces a ningún club.</p>
                                <button onClick={() => setView('list')} className="bg-blue-600 text-white px-6 py-3 rounded-full font-bold hover:bg-blue-700 shadow-lg">Buscar uno</button>
                            </div>
                        )}
                    </div>

                    {currentClub && members.length > 0 && (
                        <div className="glass-panel rounded-2xl shadow-sm overflow-hidden max-w-2xl mx-auto">
                            <div className="px-6 py-4 bg-slate-50/80 border-b border-slate-200">
                                <h3 className="font-bold text-slate-800 uppercase tracking-wide text-sm">Plantilla del Equipo ({members.length})</h3>
                            </div>
                            <div className="divide-y divide-slate-100">
                                {members.map((member) => (
                                    <div key={member.id} className="p-4 flex items-center justify-between hover:bg-white/50 transition-colors">
                                        <div className="flex items-center gap-4">
                                            <button 
                                                onClick={() => onViewPlayer && onViewPlayer(member.id)}
                                                className="w-12 h-12 bg-gradient-to-br from-blue-400 to-blue-600 rounded-full flex items-center justify-center text-white font-bold shadow-md hover:scale-105 transition-transform border-2 border-white"
                                            >
                                                {member.name.charAt(0)}
                                            </button>
                                            <div>
                                                <button 
                                                    onClick={() => onViewPlayer && onViewPlayer(member.id)}
                                                    className="font-bold text-slate-800 flex items-center gap-2 hover:text-blue-600 text-left"
                                                >
                                                    {member.name}
                                                    {member.id === currentClub.ownerId && <span className="text-[9px] bg-yellow-100 text-yellow-700 px-2 py-0.5 rounded uppercase tracking-wider font-bold">Presidente</span>}
                                                    {member.id === swimmer.id && <span className="text-[9px] bg-blue-100 text-blue-700 px-2 py-0.5 rounded uppercase tracking-wider font-bold">TÚ</span>}
                                                </button>
                                                <div className="text-xs text-slate-500 font-medium">Nivel {member.level}</div>
                                            </div>
                                        </div>
                                        <div className="text-right">
                                            <div className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">Medallas</div>
                                            <div className="flex gap-2 text-sm bg-slate-50 px-2 py-1 rounded-lg border border-slate-100">
                                                <span title="Oros">🥇 {member.medals.gold}</span>
                                                <span title="Platas">🥈 {member.medals.silver}</span>
                                                <span title="Bronces">🥉 {member.medals.bronze}</span>
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}
                </div>
            )}

            {(view === 'create' || view === 'edit') && (
                <form onSubmit={view === 'create' ? handleCreate : handleEdit} className="glass-panel p-8 rounded-3xl shadow-lg max-w-2xl mx-auto">
                    <h3 className="text-2xl font-black sport-font mb-6 text-slate-800">{view === 'create' ? 'Fundar Nuevo Equipo' : 'Editar Equipo'}</h3>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        <div className="space-y-6">
                            <div>
                                <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Nombre del Club</label>
                                <input required value={formName} onChange={e => setFormName(e.target.value)} className="w-full px-4 py-3 border border-slate-300 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 font-bold text-slate-800" placeholder="Ej. Delfines del Sur" />
                            </div>
                            <div className="bg-blue-50 p-5 rounded-xl text-sm text-blue-800 border border-blue-100 leading-relaxed">
                                Los clubes ganan <strong>Prestigio</strong> cuando sus miembros consiguen medallas en competiciones oficiales. Un mayor prestigio atrae a mejores nadadores.
                            </div>
                        </div>

                        <div className="space-y-6">
                             <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider">Diseño del Logo</label>
                             <div className="flex justify-center mb-2">
                                <div className={`w-24 h-24 rounded-full flex items-center justify-center text-4xl shadow-xl border-4 border-white transition-all ${CLUB_COLORS[selectedColorIndex].bg}`}>
                                    <span className={CLUB_COLORS[selectedColorIndex].hex}>{selectedIcon}</span>
                                </div>
                             </div>

                             <div>
                                <label className="text-[10px] font-bold text-slate-400 mb-2 block uppercase">Icono</label>
                                <div className="grid grid-cols-5 gap-2">
                                    {CLUB_ICONS.map(icon => (
                                        <button key={icon} type="button" onClick={() => setSelectedIcon(icon)} className={`p-2 rounded-lg hover:bg-slate-100 text-xl transition-all ${selectedIcon === icon ? 'bg-blue-100 ring-2 ring-blue-500 shadow-sm' : ''}`}>{icon}</button>
                                    ))}
                                </div>
                             </div>

                             <div>
                                <label className="text-[10px] font-bold text-slate-400 mb-2 block uppercase">Color</label>
                                <div className="grid grid-cols-5 gap-2">
                                    {CLUB_COLORS.map((c, i) => (
                                        <button key={c.name} type="button" onClick={() => setSelectedColorIndex(i)} className={`w-8 h-8 rounded-full border-2 transition-all ${c.bg} ${selectedColorIndex === i ? 'border-slate-800 scale-110 shadow-md ring-2 ring-offset-2 ring-slate-300' : 'border-transparent'}`} title={c.name}></button>
                                    ))}
                                </div>
                             </div>
                        </div>
                    </div>

                    <div className="flex gap-4 mt-10">
                        <button type="button" onClick={() => setView('current')} className="flex-1 bg-slate-100 text-slate-600 font-bold py-3 rounded-xl hover:bg-slate-200 transition-colors">
                            Cancelar
                        </button>
                        <button type="submit" className="flex-1 bg-gradient-to-r from-blue-600 to-cyan-600 text-white font-bold py-3 rounded-xl hover:shadow-lg hover:scale-[1.02] transition-all shadow-blue-200">
                            {view === 'create' ? 'Crear Club' : 'Guardar Cambios'}
                        </button>
                    </div>
                </form>
            )}

            {view === 'list' && (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {availableClubs.length === 0 && (
                         <div className="col-span-2 text-center py-12 bg-white/80 rounded-xl text-slate-500 font-medium">
                            No hay clubes creados. ¡Sé el primero en fundar uno!
                         </div>
                    )}
                    {availableClubs.map(club => (
                        <div key={club.id} className="glass-panel p-5 rounded-2xl flex items-center gap-4 hover:border-blue-400 transition-all hover:shadow-md cursor-pointer group">
                            <div className={`w-14 h-14 rounded-full flex items-center justify-center text-2xl shrink-0 shadow-md border-2 border-white group-hover:scale-110 transition-transform ${club.logo.bgColor}`}>
                                <span className={club.logo.color}>{club.logo.icon}</span>
                            </div>
                            <div className="flex-1">
                                <h4 className="font-bold text-slate-800 text-lg leading-tight group-hover:text-blue-700">{club.name}</h4>
                                <div className="flex justify-between items-center mt-2">
                                    <span className="text-[10px] bg-slate-100 px-2 py-0.5 rounded text-slate-500 font-bold uppercase tracking-wider">Prestigio: {club.prestige}</span>
                                </div>
                            </div>
                            {swimmer.clubId !== club.id ? (
                                <button onClick={() => handleJoin(club)} className="px-4 py-2 bg-slate-800 text-white text-xs font-bold rounded-lg hover:bg-slate-700">Unirse</button>
                            ) : (
                                <span className="text-xs font-bold text-blue-600 bg-blue-50 px-3 py-1.5 rounded-lg border border-blue-100">Tu Club</span>
                            )}
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { COMPETITION_CONFIG, STROKES, MINIMUM_TIMES, DISTANCES, DEFAULT_TIME } from '../constants';
import { CompetitionTier, Stroke, RaceResult, PastRace, Swimmer, StartListEntry } from '../types';
import { formatTime, organizeHeats } from '../services/gameLogic';
import { storageService } from '../services/storageService';

interface CompetitionProps {
    swimmer: Swimmer;
    day: number;
    onRaceComplete: (result: PastRace) => void;
    onUpdateSwimmer: () => void;
    onViewPlayer?: (playerId: string) => void;
}

export const Competition: React.FC<CompetitionProps> = ({ swimmer, day, onRaceComplete, onUpdateSwimmer, onViewPlayer }) => {
    const [selectedTier, setSelectedTier] = useState<CompetitionTier | null>(null);
    const [selectedDist, setSelectedDist] = useState<number>(100);
    const selectedStroke = Stroke.Freestyle;

    const [viewMode, setViewMode] = useState<'menu' | 'startList' | 'racing' | 'officialDocs'>('menu');
    const [raceResults, setRaceResults] = useState<RaceResult[] | null>(null);
    const [officialDocs, setOfficialDocs] = useState<{ distance: number, results: RaceResult[] }[]>([]);

    const [now, setNow] = useState(Date.now());
    const [entries, setEntries] = useState<StartListEntry[]>([]);

    useEffect(() => {
        const interval = setInterval(() => setNow(Date.now()), 1000);
        return () => clearInterval(interval);
    }, []);

    const getNextRaceTime = (tierId: CompetitionTier, interval: number) => {
        return Math.ceil(now / interval) * interval;
    };

    const getPrevRaceTime = (tierId: CompetitionTier, interval: number) => {
        return Math.floor(now / interval) * interval;
    };

    const getTimeUntil = (targetTime: number) => {
        const diff = targetTime - now;
        if (diff < 0) return "En curso";
        const hours = Math.floor(diff / 3600000);
        const minutes = Math.floor((diff % 3600000) / 60000);
        const seconds = Math.floor((diff % 60000) / 1000);
        return `${hours}h ${minutes}m ${seconds}s`;
    };

    const hasQualifyingTime = (tier: CompetitionTier, dist: number): boolean => {
        const tierMins = MINIMUM_TIMES[tier];
        if (tierMins[dist] === 999) return true;
        const pb = swimmer.personalBests[`${Stroke.Freestyle}-${dist}`] || DEFAULT_TIME;
        return pb <= tierMins[dist];
    };

    const getRegistrationStatus = (tier: CompetitionTier, dist: number) => {
        const nextStart = getNextRaceTime(tier, COMPETITION_CONFIG.find(c => c.id === tier)!.interval);
        const raceEntries = storageService.getRaceEntries(tier, dist, nextStart);
        return raceEntries.some(e => e.playerId === swimmer.id);
    };

    const getRegisteredCount = (tier: CompetitionTier) => {
        const nextStart = getNextRaceTime(tier, COMPETITION_CONFIG.find(c => c.id === tier)!.interval);
        let count = 0;
        DISTANCES.forEach(dist => {
            const raceEntries = storageService.getRaceEntries(tier, dist, nextStart);
            if (raceEntries.some(e => e.playerId === swimmer.id)) {
                count++;
            }
        });
        return count;
    };

    const handleRegister = (tier: CompetitionTier, dist: number, interval: number) => {
        const currentCount = getRegisteredCount(tier);
        if (currentCount >= 2) {
            alert("Solo puedes inscribirte en un máximo de 2 pruebas por competición.");
            return;
        }

        const myEntryTime = swimmer.personalBests[`${selectedStroke}-${dist}`] || DEFAULT_TIME;
        const nextStart = getNextRaceTime(tier, interval);
        const clubs = storageService.getClubs();
        const myClub = clubs.find(c => c.id === swimmer.clubId);

        const myEntry: StartListEntry = {
            playerId: swimmer.id,
            name: swimmer.name,
            club: myClub ? myClub.name : "Sin Club",
            entryTime: myEntryTime, 
            isPlayer: true
        };

        storageService.registerForRace(tier, dist, nextStart, myEntry);
        onUpdateSwimmer();
    };

    const handleUnregister = (tier: CompetitionTier, dist: number, interval: number) => {
        const nextStart = getNextRaceTime(tier, interval);
        storageService.unregisterFromRace(tier, dist, nextStart, swimmer.id);
        onUpdateSwimmer();
    };

    const openStartList = (tier: CompetitionTier, dist: number) => {
        setSelectedTier(tier);
        setSelectedDist(dist);
        const nextStart = getNextRaceTime(tier, COMPETITION_CONFIG.find(c => c.id === tier)!.interval);
        const raceEntries = storageService.getRaceEntries(tier, dist, nextStart);
        setEntries(raceEntries);
        setViewMode('startList');
    };

    const handleProcessRace = () => {
        if (!selectedTier) return;

        // Use nextStart logic (Assuming the race just happened or is happening)
        const interval = COMPETITION_CONFIG.find(c => c.id === selectedTier)!.interval;
        const raceTime = getNextRaceTime(selectedTier, interval);

        // This triggers the heavy calculation in Storage Service and updates DB
        const results = storageService.processRaceResults(selectedTier, selectedDist, raceTime, selectedStroke);

        setRaceResults(results);
        setViewMode('racing');

        // Find my result to trigger callback
        const myResult = results.find(r => r.playerId === swimmer.id);
        if (myResult) {
            onRaceComplete({
                id: Date.now().toString(),
                tier: selectedTier,
                stroke: selectedStroke,
                distance: selectedDist,
                time: myResult.time,
                rank: myResult.rank,
                date: day,
                realTimeDate: Date.now()
            });
        }
    };

    const handleViewOfficialDocs = (tier: CompetitionTier) => {
        const interval = COMPETITION_CONFIG.find(c => c.id === tier)!.interval;
        // Check previous block, maybe it just finished
        let targetTime = getNextRaceTime(tier, interval);

        // If "Next Race" is in the future (> 5 mins), show results from PREVIOUS race
        if (targetTime - now > 5 * 60 * 1000) {
            targetTime = getPrevRaceTime(tier, interval);
        }

        // We need to force process them if they haven't been processed
        // But usually we just want to read what's there. 
        // For this feature, let's process 50 and 100 just in case someone missed it.
        [50, 100].forEach(d => storageService.processRaceResults(tier, d, targetTime, Stroke.Freestyle));

        const docs = storageService.getOfficialResults(tier, targetTime);
        setOfficialDocs(docs);
        setSelectedTier(tier);
        setViewMode('officialDocs');
    };

    const renderOfficialDocs = () => {
        if (!selectedTier) return null;

        return (
            <div className="glass-panel rounded-2xl shadow-2xl overflow-hidden animate-fade-in max-w-5xl mx-auto border border-white/40">
                <div className="bg-slate-900 p-8 text-white flex justify-between items-center print:hidden relative overflow-hidden">
                    <div className="absolute top-0 right-0 w-64 h-full bg-gradient-to-l from-cyan-900 to-transparent opacity-50"></div>
                    <div className="relative z-10">
                        <div className="uppercase tracking-widest text-xs font-bold text-cyan-400 mb-2">Federación de Natación</div>
                        <h2 className="text-4xl font-black sport-font uppercase">Acta Oficial</h2>
                        <p className="opacity-70 mt-1 font-mono text-sm">{selectedTier} • {new Date().toLocaleDateString()}</p>
                    </div>
                    <button onClick={() => setViewMode('menu')} className="bg-white/10 backdrop-blur-md text-white px-6 py-2 rounded-lg font-bold hover:bg-white/20 border border-white/20">Cerrar</button>
                </div>

                <div className="p-8 bg-white/90 min-h-[600px] overflow-y-auto">
                    {officialDocs.length === 0 ? (
                        <div className="text-center text-slate-500 py-12">
                            Aún no hay resultados oficiales procesados para este ciclo.
                        </div>
                    ) : (
                        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                            {officialDocs.map(doc => (
                                <div key={doc.distance} className="border border-slate-200 rounded-xl p-6 shadow-sm bg-white">
                                    <h3 className="text-xl font-bold border-b pb-4 mb-4 flex justify-between">
                                        <span className="sport-font text-slate-800">{doc.distance}m Libres</span>
                                        <span className="text-xs font-bold bg-slate-100 px-2 py-1 rounded text-slate-500">{doc.results.length} Participantes</span>
                                    </h3>
                                    <table className="w-full text-sm">
                                        <thead>
                                            <tr className="text-slate-400 text-left text-[10px] uppercase font-bold tracking-wider">
                                                <th className="pb-2 w-10">Pos</th>
                                                <th className="pb-2">Nadador</th>
                                                <th className="pb-2 text-right">Tiempo</th>
                                            </tr>
                                        </thead>
                                        <tbody>
                                            {doc.results.map((r) => (
                                                <tr key={r.rank} className={`border-b last:border-0 ${r.playerId === swimmer.id ? 'bg-cyan-50' : ''}`}>
                                                    <td className="py-2 font-mono font-bold text-slate-400">{r.rank}</td>
                                                    <td className="py-2">
                                                        <button 
                                                            onClick={() => r.playerId && onViewPlayer && onViewPlayer(r.playerId)}
                                                            className="font-bold text-slate-700 hover:text-cyan-600 text-left"
                                                        >
                                                            {r.swimmerName}
                                                        </button>
                                                        <div className="text-[10px] text-slate-500 font-bold uppercase">{r.club}</div>
                                                    </td>
                                                    <td className="py-2 text-right font-mono font-bold text-slate-800">{formatTime(r.time)}</td>
                                                </tr>
                                            ))}
                                        </tbody>
                                    </table>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>
        );
    }

    const renderStartList = () => {
        if (!selectedTier) return null;
        const tierConfig = COMPETITION_CONFIG.find(c => c.id === selectedTier)!;
        const nextStart = getNextRaceTime(selectedTier, tierConfig.interval);

        const seededEntries = organizeHeats(entries);
        const heats: Record<number, typeof seededEntries> = {};
        seededEntries.forEach(e => {
            if (!heats[e.heat]) heats[e.heat] = [];
            heats[e.heat].push(e);
        });

        const raceHasStarted = now >= nextStart;

        return (
            <div className="glass-panel rounded-2xl shadow-xl overflow-hidden animate-fade-in max-w-4xl mx-auto border border-white/50">
                <div className="bg-slate-800 p-6 text-white flex justify-between items-center relative overflow-hidden">
                    <div className="relative z-10">
