                                    <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
                                </svg>
                            </div>
                            <div className="ml-3">
                                <p className="text-sm text-red-700 font-bold">{error}</p>
                            </div>
                        </div>
                    </div>
                )}

                {!isRegistering && existingPlayers.length > 0 && (
                    <div className="mb-8">
                        <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-3">Cuentas Existentes</h3>
                        <div className="grid grid-cols-1 gap-2 max-h-48 overflow-y-auto pr-1 custom-scrollbar">
                            {existingPlayers.map(player => (
                                <button
                                    key={player.id}
                                    onClick={() => onAuth(player.name, false)}
                                    className="flex items-center gap-3 w-full p-3 bg-slate-50 hover:bg-blue-50 border border-slate-200 hover:border-blue-200 rounded-xl transition-all text-left group"
                                >
                                    <div className="w-8 h-8 bg-blue-100 text-blue-600 rounded-full flex items-center justify-center font-bold text-sm group-hover:bg-blue-600 group-hover:text-white transition-colors">
                                        {player.name.charAt(0)}
                                    </div>
                                    <div className="flex-1">
                                        <div className="font-bold text-slate-700 group-hover:text-blue-700">{player.name}</div>
                                        <div className="text-[10px] text-slate-500">Nivel {player.level}</div>
                                    </div>
                                    <div className="text-slate-300 group-hover:text-blue-400">➜</div>
                                </button>
                            ))}
                        </div>
                        <div className="relative flex py-5 items-center">
                            <div className="flex-grow border-t border-slate-200"></div>
                            <span className="flex-shrink-0 mx-4 text-slate-400 text-xs font-medium">O inicia sesión manualmente</span>
                            <div className="flex-grow border-t border-slate-200"></div>
                        </div>
