                )}

                <form onSubmit={handleSubmit} className="space-y-6">
                    <div>
                        <label className="block text-sm font-bold text-slate-700 mb-2">
                            {isRegistering ? 'Crear Nuevo Nadador' : 'Nombre de Usuario'}
                        </label>
                        <input
                            type="text"
                            value={name}
                            onChange={handleChange}
                            className={`w-full px-4 py-3 rounded-lg border ${error ? 'border-red-300 ring-red-200' : 'border-slate-300 focus:ring-blue-500 focus:border-blue-500'} focus:ring-2 outline-none transition-all`}
