                                <div className="glass-panel p-6 rounded-2xl hover:shadow-lg transition-all">
                                    <h3 className="font-bold text-slate-800 uppercase tracking-wider text-xs mb-3">Último Resultado</h3>
                                    {swimmer.history.length > 0 ? (
                                        <div className="flex items-center gap-4">
                                            <div className={`
                                                w-16 h-16 flex items-center justify-center rounded-2xl font-black text-2xl text-white shadow-md
                                                ${swimmer.history[0].rank === 1 ? 'bg-yellow-400' : 
                                                  swimmer.history[0].rank === 2 ? 'bg-slate-300' : 
                                                  swimmer.history[0].rank === 3 ? 'bg-orange-400' : 'bg-slate-800'}
                                            `}>
                                                {swimmer.history[0].rank}º
                                            </div>
                                            <div>
                                                <div className="font-bold text-lg text-slate-800">{swimmer.history[0].tier}</div>
                                                <div className="text-sm text-slate-600 font-medium">
                                                    {swimmer.history[0].distance}m {swimmer.history[0].stroke}
                                                </div>
                                                <div className="text-xl font-bold text-blue-600 mono-font mt-1">
                                                    {formatTime(swimmer.history[0].time)}
                                                </div>
                                            </div>
                                        </div>
                                    ) : (
                                        <p className="text-slate-400 text-sm py-4">Aún no has competido. ¡Ve a la piscina!</p>
                                    )}
                                </div>
                            </div>
                        </div>
                    )}

                    {selectedTab === 'training' && (
                        <Training 
                            energy={swimmer.energy} 
                            onTrain={handleTrain} 
                            lastEnergyUpdate={swimmer.lastEnergyUpdate} 
                        />
                    )}

                    {selectedTab === 'shop' && (
                        <Shop swimmer={swimmer} onPurchase={handleUpdateSwimmer} />
                    )}

                    {selectedTab === 'club' && (
                        <ClubManager 
                            swimmer={swimmer} 
                            availableClubs={gameState.clubs}
                            onUpdateSwimmer={handleUpdateSwimmer}
                            onViewPlayer={setViewedPlayerId}
                        />
                    )}

                    {selectedTab === 'competition' && (
                        <Competition 
                            swimmer={swimmer}
                            day={day} 
                            onRaceComplete={handleRaceComplete} 
                            onUpdateSwimmer={() => setRefreshTrigger(t => t+1)}
                            onViewPlayer={setViewedPlayerId}
                        />
                    )}

                    {selectedTab === 'ranking' && (
                        <Ranking onViewPlayer={setViewedPlayerId} />
                    )}

                    {selectedTab === 'profile' && (
                        <Profile swimmer={swimmer} onLogout={handleLogout} />
                    )}
                </div>
            </main>
        </div>
    );
}

import { Club, Swimmer, CompetitionTier, StartListEntry, RaceResult, Stroke } from '../types';
import { calculateTime } from './gameLogic';
import { PRESTIGE_REWARDS, DEFAULT_TIME, CASH_REWARDS } from '../constants';

const DB_KEY = 'NADARPRO_DB_V2';

interface Database {
    players: Record<string, Swimmer>;
    clubs: Record<string, Club>;
    // Key format: "TIER-DISTANCE-TIMESTAMP"
    raceEntries: Record<string, StartListEntry[]>; 
    // Key format: "TIER-DISTANCE-TIMESTAMP"
    raceResults: Record<string, RaceResult[]>;
}

const getDB = (): Database => {
    const raw = localStorage.getItem(DB_KEY);
    if (!raw) {
        return { players: {}, clubs: {}, raceEntries: {}, raceResults: {} };
    }
    const db = JSON.parse(raw);
    // Ensure raceResults exists for migration
    if (!db.raceResults) db.raceResults = {};
    return db;
};

const saveDB = (db: Database) => {
    localStorage.setItem(DB_KEY, JSON.stringify(db));
};

export const storageService = {
    // Player Methods
    getPlayer: (name: string): Swimmer | null => {
        const db = getDB();
        // FIX: Search through values (player objects) to find the name, 
        // as keys are timestamp IDs, not names.
        const player = Object.values(db.players).find(p => p.name.toLowerCase() === name.toLowerCase());
        return player || null;
    },

    getAllPlayers: (): Swimmer[] => {
        const db = getDB();
        return Object.values(db.players);
    },

    savePlayer: (swimmer: Swimmer) => {
        const db = getDB();
        db.players[swimmer.id] = swimmer;
        saveDB(db);
    },

    // Club Methods
    getClubs: (): Club[] => {
        const db = getDB();
        return Object.values(db.clubs);
    },

    getClub: (id: string): Club | null => {
        const db = getDB();
        return db.clubs[id] || null;
    },

    saveClub: (club: Club) => {
        const db = getDB();
        db.clubs[club.id] = club;
        saveDB(db);
    },

    deleteClub: (clubId: string) => {
        const db = getDB();
        if (db.clubs[clubId]) {
            delete db.clubs[clubId];
            saveDB(db);
        }
    },

    getClubMemberCount: (clubId: string): number => {
        const db = getDB();
        return Object.values(db.players).filter(p => p.clubId === clubId).length;
    },

    getClubMembers: (clubId: string): Swimmer[] => {
        const db = getDB();
        return Object.values(db.players).filter(p => p.clubId === clubId);
    },

    // Competition Methods
    registerForRace: (tier: CompetitionTier, distance: number, startTime: number, entry: StartListEntry) => {
        const db = getDB();
        const raceKey = `${tier}-${distance}-${startTime}`;

        if (!db.raceEntries[raceKey]) {
            db.raceEntries[raceKey] = [];
        }

        db.raceEntries[raceKey] = db.raceEntries[raceKey].filter(e => e.playerId !== entry.playerId);
        db.raceEntries[raceKey].push(entry);

        saveDB(db);
    },

    unregisterFromRace: (tier: CompetitionTier, distance: number, startTime: number, playerId: string) => {
        const db = getDB();
        const raceKey = `${tier}-${distance}-${startTime}`;

        if (db.raceEntries[raceKey]) {
            db.raceEntries[raceKey] = db.raceEntries[raceKey].filter(e => e.playerId !== playerId);
            saveDB(db);
        }
    },

    getRaceEntries: (tier: CompetitionTier, distance: number, startTime: number): StartListEntry[] => {
        const db = getDB();
        const raceKey = `${tier}-${distance}-${startTime}`;
        const rawEntries = db.raceEntries[raceKey] || [];

        // AUTO-UPDATE LOGIC:
        // Iterate through entries. If it's a real player, look up their CURRENT stats/club/name
        // and return a modified entry. This ensures start lists are always up to date.
        return rawEntries.map(entry => {
            if (entry.isPlayer && entry.playerId && db.players[entry.playerId]) {
                const player = db.players[entry.playerId];
                const club = player.clubId ? db.clubs[player.clubId] : null;

                // Get current PB for this distance (Assuming Freestyle as per current app logic)
                const pbKey = `${Stroke.Freestyle}-${distance}`;
                const currentPB = player.personalBests[pbKey] || DEFAULT_TIME;

                return {
                    ...entry,
                    name: player.name, // Update name if changed
                    club: club ? club.name : "Sin Club", // Update club if changed
                    entryTime: currentPB // Update time if improved
                };
            }
            return entry; // Return bot entry as is
        });
    },

    /**
     * PROCESS RACE RESULTS
     * This function runs when a user triggers the race result view.
     * It checks if results exist. If not, it calculates them for ALL players,
     * updates ALL players' profiles (history, PBs, XP), and saves the results permanently.
     */
    processRaceResults: (tier: CompetitionTier, distance: number, startTime: number, stroke: Stroke): RaceResult[] => {
        const db = getDB();
        const raceKey = `${tier}-${distance}-${startTime}`;

        // 1. If results already exist, return them (Persistent History)
        if (db.raceResults[raceKey]) {
            return db.raceResults[raceKey];
        }

        // 2. If not, calculate for everyone
        const entries = db.raceEntries[raceKey] || [];
        if (entries.length === 0) return [];

        const results: RaceResult[] = entries.map(entry => {
            let raceTime = entry.entryTime;
            let clubName = entry.club;

            // Check if player exists in DB to use real stats
            const player = db.players[entry.playerId];

            if (player) {
                // Calculate real time based on current stats
                raceTime = calculateTime(player.stats, distance, stroke);

                // Ensure we use the LATEST club name for the permanent result record
                if (player.clubId && db.clubs[player.clubId]) {
                    clubName = db.clubs[player.clubId].name;
                } else {
                    clubName = "Sin Club";
                }
            } else {
                // Bot simulation
                if (Math.abs(raceTime - DEFAULT_TIME) < 1) {
                    raceTime = (distance === 50 ? 30 : 65) + (Math.random() * 10 - 5);
                } else {
                    raceTime = entry.entryTime + (Math.random() * 1.5 - 0.75);
                }
            }

            return {
                rank: 0,
                swimmerName: entry.name,
                club: clubName,
                time: raceTime,
                isPlayer: !!player,
                playerId: entry.playerId
            };
        });

        // Sort and Assign Ranks
        results.sort((a, b) => a.time - b.time);
        results.forEach((r, i) => r.rank = i + 1);

        // 3. UPDATE PROFILES FOR ALL PARTICIPANTS
        results.forEach(result => {
            if (result.playerId && db.players[result.playerId]) {
                const p = db.players[result.playerId];
                const pbKey = `${stroke}-${distance}`;
                const currentPB = p.personalBests[pbKey] || DEFAULT_TIME;

                // Update PB (This happens for ALL tiers, including Triangular)
                if (result.time < currentPB) {
                    p.personalBests[pbKey] = result.time;
                }

                // LOGIC FOR OFFICIAL COMPETITIONS (Not Triangular)
                // Triangulars only update PB, nothing else.
                if (tier !== CompetitionTier.Triangular) {

                    // XP Calculation
                    const xpGain = Math.max(10, 110 - (result.rank * 10)) * (
                        tier === CompetitionTier.World ? 5 :
                        tier === CompetitionTier.European ? 3 : 
                        1
                    );

                    p.xp += xpGain;
                    p.level = Math.floor(p.xp / 100) + 1;

                    // MONEY Calculation
                    const rewards = CASH_REWARDS[tier] || [0, 0, 0, 0];
                    let prizeMoney = 0;

                    if (result.rank === 1) prizeMoney = rewards[0];
                    else if (result.rank === 2) prizeMoney = rewards[1];
                    else if (result.rank === 3) prizeMoney = rewards[2];
                    else if (result.rank <= 8) prizeMoney = rewards[3];

                    if (p.money === undefined) p.money = 0;
                    p.money += prizeMoney;

                    // Add to History
                    p.history.unshift({
                        id: raceKey,
                        tier,
                        stroke,
                        distance,
                        time: result.time,
                        rank: result.rank,
                        date: 1, // Simplified day tracking
                        realTimeDate: Date.now()
                    });

                    // Update Medals
                    if (result.rank === 1) p.medals.gold++;
                    if (result.rank === 2) p.medals.silver++;
                    if (result.rank === 3) p.medals.bronze++;

                    // Club Prestige
                    if (result.rank <= 3 && p.clubId && db.clubs[p.clubId]) {
                        const prestigeRewards = PRESTIGE_REWARDS[tier];
                        if (prestigeRewards) {
                            db.clubs[p.clubId].prestige += prestigeRewards[result.rank - 1];
                        }
                    }
                }
            }
        });

        // 4. Save everything
        db.raceResults[raceKey] = results;
        saveDB(db);

        return results;
    },

    // Get all results for a specific competition time block (for the document view)
    getOfficialResults: (tier: CompetitionTier, startTime: number): { distance: number, results: RaceResult[] }[] => {
        const db = getDB();
        const distances = [50, 100, 200];
        const output: { distance: number, results: RaceResult[] }[] = [];

        distances.forEach(dist => {
            const key = `${tier}-${dist}-${startTime}`;
            if (db.raceResults[key]) {
                output.push({ distance: dist, results: db.raceResults[key] });
            }
        });

        return output;
    }
};

