import React from 'react';
import { Swimmer } from '../types';
import { formatTime } from '../services/gameLogic';
import { storageService } from '../services/storageService';

interface ProfileProps {
    swimmer: Swimmer;
    onLogout: () => void;
}

export const Profile: React.FC<ProfileProps> = ({ swimmer, onLogout }) => {
    // Fetch club name freshly
    const club = swimmer.clubId ? storageService.getClub(swimmer.clubId) : null;

    // Filter for medals
    const medalHistory = swimmer.history.filter(race => race.rank <= 3);

    // Sort Personal Bests by distance (extracted from key "Stroke-Distance")
    const sortedPBs = Object.entries(swimmer.personalBests).sort((a, b) => {
        const distA = parseInt(a[0].split('-')[1]);
        const distB = parseInt(b[0].split('-')[1]);
        return distA - distB;
    });

    return (
        <div className="space-y-8 animate-fade-in">
            <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100 flex justify-between items-center">
                <div className="flex items-center gap-4">
                    <div className="w-16 h-16 bg-gradient-to-br from-blue-400 to-blue-600 rounded-full flex items-center justify-center text-white text-2xl font-bold shadow-lg">
                        {swimmer.name.charAt(0)}
                    </div>
                    <div>
                        <h2 className="text-2xl font-bold text-slate-800">{swimmer.name}</h2>
                        <p className="text-slate-500">{club ? club.name : 'Agente Libre'}</p>
                    </div>
                </div>
                <button onClick={onLogout} className="text-red-500 hover:text-red-700 font-bold text-sm">
                    Cerrar Sesión
                </button>
            </div>

            {/* Medals Summary */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="bg-gradient-to-br from-yellow-50 to-yellow-100 p-6 rounded-2xl border border-yellow-200 flex items-center gap-4">
                    <div className="text-4xl">🥇</div>
                    <div>
                        <div className="text-3xl font-black text-yellow-700">{swimmer.medals.gold}</div>
                        <div className="text-xs font-bold text-yellow-600 uppercase tracking-wider">Oros</div>
                    </div>
                </div>
                <div className="bg-gradient-to-br from-slate-50 to-slate-100 p-6 rounded-2xl border border-slate-200 flex items-center gap-4">
                    <div className="text-4xl">🥈</div>
                    <div>
                        <div className="text-3xl font-black text-slate-600">{swimmer.medals.silver}</div>
                        <div className="text-xs font-bold text-slate-500 uppercase tracking-wider">Platas</div>
                    </div>
                </div>
                <div className="bg-gradient-to-br from-orange-50 to-orange-100 p-6 rounded-2xl border border-orange-200 flex items-center gap-4">
                    <div className="text-4xl">🥉</div>
                    <div>
                        <div className="text-3xl font-black text-orange-700">{swimmer.medals.bronze}</div>
                        <div className="text-xs font-bold text-orange-600 uppercase tracking-wider">Bronces</div>
                    </div>
                </div>
            </div>

            {/* Detailed Medal List */}
            {medalHistory.length > 0 && (
                <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-8">
                    <h2 className="text-2xl font-bold mb-6 text-slate-800">Vitrina de Trofeos</h2>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 max-h-96 overflow-y-auto pr-2">
                        {medalHistory.map((race) => (
                            <div key={race.id} className={`p-4 rounded-xl border flex items-center gap-4 ${
                                race.rank === 1 ? 'bg-yellow-50 border-yellow-200' :
                                race.rank === 2 ? 'bg-slate-50 border-slate-200' :
                                'bg-orange-50 border-orange-200'
                            }`}>
                                <div className="text-3xl filter drop-shadow-sm">
                                    {race.rank === 1 ? '🥇' : race.rank === 2 ? '🥈' : '🥉'}
                                </div>
                                <div>
                                    <div className="font-bold text-slate-800 leading-tight">{race.tier}</div>
                                    <div className="text-sm font-semibold text-slate-600">
                                        {race.distance}m {race.stroke}
                                    </div>
                                    <div className="text-xs text-slate-500 mt-1 flex gap-2">
                                        <span>📅 {new Date(race.realTimeDate).toLocaleDateString()}</span>
                                        <span className="font-mono font-bold text-blue-600">⏱ {formatTime(race.time)}</span>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-8">
                <h2 className="text-2xl font-bold mb-6 text-slate-800">Mejores Marcas Personales</h2>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                    {sortedPBs.length === 0 && (
                        <p className="text-slate-400">Sin tiempos registrados.</p>
                    )}
                    {sortedPBs.map(([key, time]) => {
                        const [stroke, dist] = key.split('-');
                        return (
                            <div key={key} className="flex justify-between items-center p-4 bg-slate-50 rounded-xl border border-slate-100">
                                <span className="font-bold text-slate-700 capitalize">{dist}m {stroke}</span>
                                <span className="font-mono text-blue-600 font-bold">{formatTime(time as number)}</span>
                            </div>
                        );
                    })}
                </div>
            </div>

            <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-8">
                <h2 className="text-2xl font-bold mb-6 text-slate-800">Historial Reciente</h2>
                <div className="space-y-4 max-h-96 overflow-y-auto pr-2">
                    {swimmer.history.map((race) => (
                        <div key={race.id} className="border-l-4 border-blue-500 bg-slate-50 pl-4 py-3 rounded-r-lg">
                            <div className="flex justify-between">
                                <span className="font-bold text-slate-800">{race.tier}</span>
                                <span className="text-sm text-slate-500">{new Date(race.realTimeDate).toLocaleDateString()}</span>
                            </div>
                            <div className="text-sm text-slate-600 mt-1">
                                {race.distance}m {race.stroke} | <span className="font-mono font-bold">{formatTime(race.time)}</span> | Posición: {race.rank}
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        </div>
    );
};

import React, { useEffect, useState } from 'react';
import { Swimmer, Club } from '../types';
import { storageService } from '../services/storageService';
import { formatTime } from '../services/gameLogic';
import { Attribute } from '../types';

interface PlayerModalProps {
    playerId: string;
    onClose: () => void;
}

export const PlayerModal: React.FC<PlayerModalProps> = ({ playerId, onClose }) => {
    const [player, setPlayer] = useState<Swimmer | null>(null);
    const [club, setClub] = useState<Club | null>(null);
    const [sortedPBs, setSortedPBs] = useState<[string, number][]>([]);

    useEffect(() => {
        const p = storageService.getAllPlayers().find(p => p.id === playerId);
        if (p) {
            setPlayer(p);
            if (p.clubId) {
                setClub(storageService.getClub(p.clubId));
            }
            // Sort PBs
            const sorted = Object.entries(p.personalBests).sort((a, b) => {
                const distA = parseInt(a[0].split('-')[1]);
                const distB = parseInt(b[0].split('-')[1]);
                return distA - distB;
            });
            setSortedPBs(sorted);
        }
    }, [playerId]);

    if (!player) return null;

    // Helper for Stat Bars
    const StatBar = ({ label, value, color }: { label: string, value: number, color: string }) => (
        <div className="mb-2">
            <div className="flex justify-between text-xs uppercase font-bold text-slate-500 mb-1">
                <span>{label}</span>
                <span>{value}</span>
            </div>
            <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden">
                <div 
                    className={`h-full ${color}`} 
                    style={{ width: `${Math.min(100, value)}%` }}
                ></div>
            </div>
        </div>
    );

    return (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fade-in" onClick={onClose}>
            <div 
                className="bg-white rounded-3xl shadow-2xl w-full max-w-lg overflow-hidden border-4 border-white relative"
                onClick={e => e.stopPropagation()}
            >
                {/* Header Card Style */}
                <div className="bg-gradient-to-r from-blue-600 to-cyan-500 p-6 text-white relative wet-shine">
                    <button 
                        onClick={onClose}
                        className="absolute top-4 right-4 bg-white/20 hover:bg-white/30 rounded-full w-8 h-8 flex items-center justify-center font-bold text-sm"
                    >
                        ✕
                    </button>

                    <div className="flex items-center gap-6">
                        <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center text-blue-600 text-3xl font-black shadow-lg border-4 border-blue-200">
                            {player.name.charAt(0)}
                        </div>
                        <div>
                            <h2 className="text-3xl font-black sport-font leading-none">{player.name}</h2>
                            <p className="text-blue-100 font-bold opacity-90">{club ? club.name : 'Agente Libre'}</p>
                            <div className="mt-2 flex gap-2">
                                <span className="bg-white/20 px-3 py-0.5 rounded-full text-xs font-bold uppercase tracking-wider">
                                    Nivel {player.level}
                                </span>
                            </div>
                        </div>
                    </div>
                </div>

                <div className="p-6 space-y-6 max-h-[70vh] overflow-y-auto">

                    {/* Medals */}
                    <div className="flex justify-between bg-slate-50 p-4 rounded-xl border border-slate-100">
                        <div className="text-center flex-1 border-r border-slate-200 last:border-0">
                            <div className="text-2xl">🥇</div>
                            <div className="font-bold text-slate-800">{player.medals.gold}</div>
                        </div>
                        <div className="text-center flex-1 border-r border-slate-200 last:border-0">
                            <div className="text-2xl">🥈</div>
                            <div className="font-bold text-slate-800">{player.medals.silver}</div>
                        </div>
                        <div className="text-center flex-1">
                            <div className="text-2xl">🥉</div>
                            <div className="font-bold text-slate-800">{player.medals.bronze}</div>
                        </div>
                    </div>

                    {/* Stats Grid */}
                    <div>
                        <h3 className="font-bold text-slate-800 mb-3 sport-font text-lg border-b pb-1">Atributos Físicos</h3>
                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <StatBar label="Fuerza" value={player.stats[Attribute.Strength]} color="bg-red-500" />
                                <StatBar label="Velocidad" value={player.stats[Attribute.Speed]} color="bg-yellow-500" />
                            </div>
                            <div>
                                <StatBar label="Técnica" value={player.stats[Attribute.Technique]} color="bg-purple-500" />
                                <StatBar label="Resistencia" value={player.stats[Attribute.Stamina]} color="bg-lime-500" />
                            </div>
                        </div>
                        <div className="mt-2">
                             <StatBar label="Mentalidad" value={player.stats[Attribute.Mental]} color="bg-blue-500" />
                        </div>
                    </div>

                    {/* Personal Bests */}
                    <div>
                        <h3 className="font-bold text-slate-800 mb-3 sport-font text-lg border-b pb-1">Mejores Marcas</h3>
                        <div className="space-y-2">
                            {sortedPBs.length === 0 ? (
                                <p className="text-sm text-slate-400 italic">Sin registros oficiales.</p>
                            ) : (
                                sortedPBs.map(([key, time]) => {
                                    const [stroke, dist] = key.split('-');
                                    return (
                                        <div key={key} className="flex justify-between items-center text-sm">
                                            <span className="font-bold text-slate-600 capitalize">{dist}m {stroke}</span>
                                            <span className="mono-font font-bold text-blue-600">{formatTime(time as number)}</span>
                                        </div>
                                    );
                                })
                            )}
                        </div>
                    </div>

                    {/* Recent History */}
                    <div>
                        <h3 className="font-bold text-slate-800 mb-3 sport-font text-lg border-b pb-1">Última Carrera</h3>
                        {player.history.length > 0 ? (
                            <div className="bg-blue-50 p-3 rounded-lg border border-blue-100">
                                <div className="flex justify-between items-center">
                                    <span className="font-bold text-blue-900 text-sm">{player.history[0].tier}</span>
                                    <span className="text-xs text-blue-400">{new Date(player.history[0].realTimeDate).toLocaleDateString()}</span>
                                </div>
                                <div className="mt-1 flex justify-between items-end">
                                    <span className="text-xs text-blue-600 uppercase font-bold">{player.history[0].distance}m {player.history[0].stroke}</span>
                                    <span className="mono-font font-bold text-blue-800">{formatTime(player.history[0].time)}</span>
                                </div>
                                <div className="mt-1 text-xs text-center font-bold bg-white rounded py-1 text-slate-500 shadow-sm">
                                    Posición: {player.history[0].rank}º
                                </div>
                            </div>
                        ) : (
                            <p className="text-sm text-slate-400 italic">No ha competido aún.</p>
                        )}
                    </div>

                </div>
            </div>
        </div>
    );
};

export enum Attribute {
    Strength = 'Fuerza',
    Technique = 'Técnica',
    Stamina = 'Resistencia',
    Mental = 'Mentalidad',
    Speed = 'Velocidad'
}

export enum CompetitionTier {
    Triangular = 'Triangular',
    Provincial = 'Provincial',
    Regional = 'Regional',
    National = 'Nacional',
    InternationalClub = 'Copa Internacional', // New Tier
    European = 'Europeo',
    World = 'Mundial'
}

export enum Stroke {
    Freestyle = 'Crol'
}

export interface Stats {
    [Attribute.Strength]: number;
    [Attribute.Technique]: number;
    [Attribute.Stamina]: number;
    [Attribute.Mental]: number;
    [Attribute.Speed]: number;
}

export interface ClubLogo {
    icon: string;
    color: string;
    bgColor: string;
}

export interface ClubLocation {
    countryId: string; // 'ES', 'US', 'FR', etc.
    regionId?: string; // 'CLM', 'MAD', etc. (Only for Spain)
    zoneId?: string;   // 'Z1', 'Z2' (Provincial zones)
    cityName: string;
}

export interface Club {
    id: string;
    name: string;
    prestige: number;
    description: string;
    logo: ClubLogo;
    location: ClubLocation; // New Location Data
    ownerId: string; 
}

export interface RaceResult {
    rank: number;
    swimmerName: string;
    club: string;
    time: number;
    isPlayer: boolean;
    playerId?: string;
    lane?: number;
    heat?: number;
    entryTime?: number;
}

export interface StartListEntry {
    playerId: string;
    name: string;
    club: string;
    entryTime: number;
    isPlayer: boolean;
}

export interface PastRace {
    id: string;
    tier: CompetitionTier;
    stroke: Stroke;
    distance: number;
    time: number;
    rank: number;
    date: number; 
    realTimeDate: number; 
    zoneName?: string; // To store where it happened (e.g. "Zona 1")
}

export interface Medals {
    gold: number;
    silver: number;
    bronze: number;
}

export interface Swimmer {
    id: string;
    name: string;
    clubId: string | null; 
    stats: Stats;
    level: number;
    xp: number;
    personalBests: Record<string, number>; 
    history: PastRace[];
    medals: Medals;
    energy: number;
    lastEnergyUpdate: number;
    money: number; 
}

export interface GameState {
    day: number;
    swimmer: Swimmer | null;
    selectedTab: 'dashboard' | 'training' | 'competition' | 'profile' | 'club' | 'ranking' | 'shop';
