import { Club, Swimmer, CompetitionTier, StartListEntry, RaceResult, Stroke } from '../types';
import { calculateTime } from './gameLogic';
import { PRESTIGE_REWARDS, DEFAULT_TIME, CASH_REWARDS } from '../constants';

const DB_KEY = 'NADARPRO_DB_V2';

interface Database {
    players: Record<string, Swimmer>;
    clubs: Record<string, Club>;
    raceEntries: Record<string, StartListEntry[]>; 
    raceResults: Record<string, RaceResult[]>;
}

const getDB = (): Database => {
    const raw = localStorage.getItem(DB_KEY);
    if (!raw) {
        return { players: {}, clubs: {}, raceEntries: {}, raceResults: {} };
    }
    const db = JSON.parse(raw);
    if (!db.raceResults) db.raceResults = {};
    return db;
};

const saveDB = (db: Database) => {
    localStorage.setItem(DB_KEY, JSON.stringify(db));
};

export const storageService = {
    // Player Methods
    getPlayer: (name: string): Swimmer | null => {
        const db = getDB();
        const player = Object.values(db.players).find(p => p.name.toLowerCase() === name.toLowerCase());
        return player || null;
    },

    getAllPlayers: (): Swimmer[] => {
        const db = getDB();
        return Object.values(db.players);
    },

    savePlayer: (swimmer: Swimmer) => {
        const db = getDB();
        db.players[swimmer.id] = swimmer;
        saveDB(db);
    },

    updatePlayerFields: (id: string, fields: Partial<Swimmer>) => {
        const db = getDB();
        if (db.players[id]) {
            db.players[id] = { ...db.players[id], ...fields };
            saveDB(db);
        }
    },

    // Club Methods
    getClubs: (): Club[] => {
        const db = getDB();
        return Object.values(db.clubs);
    },

    getClub: (id: string): Club | null => {
        const db = getDB();
        return db.clubs[id] || null;
    },

    saveClub: (club: Club) => {
        const db = getDB();
        db.clubs[club.id] = club;
        saveDB(db);
    },

    deleteClub: (clubId: string) => {
        const db = getDB();
        if (db.clubs[clubId]) {
            delete db.clubs[clubId];
            saveDB(db);
        }
    },

    getClubMemberCount: (clubId: string): number => {
        const db = getDB();
        return Object.values(db.players).filter(p => p.clubId === clubId).length;
    },

    getClubMembers: (clubId: string): Swimmer[] => {
        const db = getDB();
        return Object.values(db.players).filter(p => p.clubId === clubId);
    },

    // Helper to generate geographic keys
    getRaceKey: (tier: CompetitionTier, distance: number, startTime: number, club?: Club | null): string => {
        let suffix = '';

        if (club) {
            if (tier === CompetitionTier.Provincial) {
                // Key: Provincial-Z1-50-123456
                suffix = club.location.countryId === 'ES' && club.location.zoneId ? `-${club.location.zoneId}` : '-GEN'; 
            } else if (tier === CompetitionTier.Regional) {
                // Key: Regional-CLM-50-123456
                suffix = club.location.countryId === 'ES' && club.location.regionId ? `-${club.location.regionId}` : '-GEN';
            } else if (tier === CompetitionTier.National) {
                // Key: National-ES-50-123456
                suffix = `-${club.location.countryId}`;
            }
        } else {
             // Fallback for players without club (they shouldn't be here in UI, but safe backend)
             if (tier === CompetitionTier.Provincial || tier === CompetitionTier.Regional || tier === CompetitionTier.National) {
                 suffix = '-OPEN';
             }
        }

        // International Club Cup and others are global
        return `${tier}${suffix}-${distance}-${startTime}`;
    },

    // Competition Methods
    registerForRace: (tier: CompetitionTier, distance: number, startTime: number, entry: StartListEntry) => {
        const db = getDB();

        // Find player club to determine location key
        const player = db.players[entry.playerId];
        const club = player && player.clubId ? db.clubs[player.clubId] : null;

        const raceKey = storageService.getRaceKey(tier, distance, startTime, club);

        if (!db.raceEntries[raceKey]) {
            db.raceEntries[raceKey] = [];
        }

        db.raceEntries[raceKey] = db.raceEntries[raceKey].filter(e => e.playerId !== entry.playerId);
        db.raceEntries[raceKey].push(entry);

        saveDB(db);
    },

    unregisterFromRace: (tier: CompetitionTier, distance: number, startTime: number, playerId: string) => {
        const db = getDB();

        // We need to reconstruct the key. Assuming the player is still in the same club.
        const player = db.players[playerId];
        const club = player && player.clubId ? db.clubs[player.clubId] : null;
        const raceKey = storageService.getRaceKey(tier, distance, startTime, club);

        if (db.raceEntries[raceKey]) {
            db.raceEntries[raceKey] = db.raceEntries[raceKey].filter(e => e.playerId !== playerId);
            saveDB(db);
        }
    },

    getRaceEntries: (tier: CompetitionTier, distance: number, startTime: number, contextClub?: Club | null): StartListEntry[] => {
        const db = getDB();
        // The UI passes the current user's club as context so we know which list to fetch
        const raceKey = storageService.getRaceKey(tier, distance, startTime, contextClub);
        const rawEntries = db.raceEntries[raceKey] || [];

        return rawEntries.map(entry => {
            if (entry.isPlayer && entry.playerId && db.players[entry.playerId]) {
                const player = db.players[entry.playerId];
                const club = player.clubId ? db.clubs[player.clubId] : null;
                const pbKey = `${Stroke.Freestyle}-${distance}`;
                const currentPB = player.personalBests[pbKey] || DEFAULT_TIME;

                return {
                    ...entry,
                    name: player.name,
                    club: club ? club.name : "Sin Club",
                    entryTime: currentPB
                };
            }
            return entry;
        });
    },

    processRaceResults: (tier: CompetitionTier, distance: number, startTime: number, stroke: Stroke, contextClub?: Club | null): RaceResult[] => {
        const db = getDB();
        const raceKey = storageService.getRaceKey(tier, distance, startTime, contextClub);

        if (db.raceResults[raceKey]) {
            return db.raceResults[raceKey];
        }

        const entries = db.raceEntries[raceKey] || [];
        if (entries.length === 0) return [];

        const results: RaceResult[] = entries.map(entry => {
            let raceTime = entry.entryTime;
            let clubName = entry.club;
            const player = db.players[entry.playerId];

            if (player) {
                raceTime = calculateTime(player.stats, distance, stroke);
                if (player.clubId && db.clubs[player.clubId]) {
                    clubName = db.clubs[player.clubId].name;
                } else {
                    clubName = "Sin Club";
                }
            } else {
                if (Math.abs(raceTime - DEFAULT_TIME) < 1) {
                    raceTime = (distance === 50 ? 30 : 65) + (Math.random() * 10 - 5);
                } else {
                    raceTime = entry.entryTime + (Math.random() * 1.5 - 0.75);
                }
            }

            return {
                rank: 0,
                swimmerName: entry.name,
                club: clubName,
                time: raceTime,
                isPlayer: !!player,
                playerId: entry.playerId
            };
        });

        results.sort((a, b) => a.time - b.time);
        results.forEach((r, i) => r.rank = i + 1);

        results.forEach(result => {
            if (result.playerId && db.players[result.playerId]) {
                const p = db.players[result.playerId];
                const pbKey = `${stroke}-${distance}`;
                const currentPB = p.personalBests[pbKey] || DEFAULT_TIME;

                if (result.time < currentPB) {
                    p.personalBests[pbKey] = result.time;
                }

                if (tier !== CompetitionTier.Triangular) {
                    const xpGain = Math.max(10, 110 - (result.rank * 10)) * (
                        tier === CompetitionTier.World ? 5 :
                        tier === CompetitionTier.European ? 3 : 
                        1
                    );

                    p.xp += xpGain;
                    p.level = Math.floor(p.xp / 100) + 1;

                    const rewards = CASH_REWARDS[tier] || [0, 0, 0, 0];
                    let prizeMoney = 0;
                    if (result.rank === 1) prizeMoney = rewards[0];
                    else if (result.rank === 2) prizeMoney = rewards[1];
                    else if (result.rank === 3) prizeMoney = rewards[2];
                    else if (result.rank <= 8) prizeMoney = rewards[3];

                    if (p.money === undefined) p.money = 0;
                    p.money += prizeMoney;

                    // Generate a zone name for history
                    let zoneLabel = "";
                    if (contextClub && tier === CompetitionTier.Provincial) zoneLabel = contextClub.location.zoneId || "";
                    if (contextClub && tier === CompetitionTier.Regional) zoneLabel = contextClub.location.regionId || "";
                    if (contextClub && tier === CompetitionTier.National) zoneLabel = contextClub.location.countryId || "";

                    p.history.unshift({
                        id: raceKey,
                        tier,
                        stroke,
                        distance,
                        time: result.time,
                        rank: result.rank,
                        date: 1, 
                        realTimeDate: Date.now(),
                        zoneName: zoneLabel
                    });

                    if (result.rank === 1) p.medals.gold++;
                    if (result.rank === 2) p.medals.silver++;
                    if (result.rank === 3) p.medals.bronze++;

                    if (result.rank <= 3 && p.clubId && db.clubs[p.clubId]) {
                        const prestigeRewards = PRESTIGE_REWARDS[tier];
                        if (prestigeRewards) {
                            db.clubs[p.clubId].prestige += prestigeRewards[result.rank - 1];
                        }
                    }
                }
            }
        });

        db.raceResults[raceKey] = results;
        saveDB(db);

        return results;
    },

    getOfficialResults: (tier: CompetitionTier, startTime: number, contextClub?: Club | null): { distance: number, results: RaceResult[] }[] => {
        const db = getDB();
        const distances = [50, 100, 200];
        const output: { distance: number, results: RaceResult[] }[] = [];

        distances.forEach(dist => {
            const raceKey = storageService.getRaceKey(tier, dist, startTime, contextClub);
            if (db.raceResults[raceKey]) {
                output.push({ distance: dist, results: db.raceResults[raceKey] });
            }
        });

        return output;
    }
};

import React, { useState, useEffect } from 'react';
import { Attribute, Club, Swimmer } from '../types';
import { CLUB_COLORS, CLUB_ICONS, SPANISH_GEOGRAPHY, INTERNATIONAL_COUNTRIES, COUNTRY_FLAGS } from '../constants';
import { storageService } from '../services/storageService';

interface ClubManagerProps {
    swimmer: Swimmer;
    availableClubs: Club[];
    onUpdateSwimmer: (swimmer: Swimmer) => void;
    onViewPlayer?: (playerId: string) => void;
}

export const ClubManager: React.FC<ClubManagerProps> = ({ swimmer, availableClubs, onUpdateSwimmer, onViewPlayer }) => {
    const [view, setView] = useState<'current' | 'list' | 'create' | 'edit'>('current');
    const [members, setMembers] = useState<Swimmer[]>([]);

    // Form State
    const [formName, setFormName] = useState('');
    const [selectedIcon, setSelectedIcon] = useState(CLUB_ICONS[0]);
    const [selectedColorIndex, setSelectedColorIndex] = useState(0);

    // Geography Form State
    const [selectedCountry, setSelectedCountry] = useState('ES');
    const [selectedRegion, setSelectedRegion] = useState('');
    const [selectedZone, setSelectedZone] = useState('');
    const [selectedCity, setSelectedCity] = useState('');

    const currentClub = availableClubs.find(c => c.id === swimmer.clubId);

    // Initialize edit form
    useEffect(() => {
        if (view === 'edit' && currentClub) {
            setFormName(currentClub.name);
            setSelectedIcon(currentClub.logo.icon);
            const colorIdx = CLUB_COLORS.findIndex(c => c.bg === currentClub.logo.bgColor);
            setSelectedColorIndex(colorIdx >= 0 ? colorIdx : 0);

            // Geography init
            setSelectedCountry(currentClub.location.countryId);
            setSelectedRegion(currentClub.location.regionId || '');
            setSelectedZone(currentClub.location.zoneId || '');
            setSelectedCity(currentClub.location.cityName);
        } else if (view === 'create') {
            // Reset defaults
            setFormName('');
            setSelectedCountry('ES');
            setSelectedRegion('');
            setSelectedZone('');
            setSelectedCity('');
        }
    }, [view, currentClub]);

    // Load members
    useEffect(() => {
        if (view === 'current' && currentClub) {
            setMembers(storageService.getClubMembers(currentClub.id));
        }
    }, [view, currentClub]);

    const handleCreate = (e: React.FormEvent) => {
        e.preventDefault();

        // Validation for Spain
        if (selectedCountry === 'ES' && (!selectedRegion || !selectedZone || !selectedCity)) {
            alert("Debes seleccionar Comunidad, Zona y Ciudad para un club español.");
            return;
        }
        if (selectedCountry !== 'ES' && !selectedCity) {
            alert("Debes escribir una ciudad.");
            return;
        }

        const colorData = CLUB_COLORS[selectedColorIndex];
        const newClub: Club = {
            id: Date.now().toString(),
            name: formName,
            description: `Club fundado por ${swimmer.name}`,
            prestige: 0,
            logo: {
                icon: selectedIcon,
                color: colorData.hex,
                bgColor: colorData.bg
            },
            location: {
                countryId: selectedCountry,
                regionId: selectedRegion || undefined,
                zoneId: selectedZone || undefined,
                cityName: selectedCity
            },
            ownerId: swimmer.id
        };

        storageService.saveClub(newClub);

        const updatedSwimmer = { ...swimmer, clubId: newClub.id };
        storageService.savePlayer(updatedSwimmer);
        onUpdateSwimmer(updatedSwimmer);

        setView('current');
    };

    const handleEdit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!currentClub) return;

        const colorData = CLUB_COLORS[selectedColorIndex];
        const updatedClub: Club = {
            ...currentClub,
            name: formName,
            logo: {
                icon: selectedIcon,
                color: colorData.hex,
                bgColor: colorData.bg
            }
            // Cannot edit location after creation (simpler logic to avoid zone hopping exploits)
        };

        storageService.saveClub(updatedClub);
        onUpdateSwimmer(swimmer); 
        setView('current');
    };

    const handleJoin = (club: Club) => {
        const updatedSwimmer = { ...swimmer, clubId: club.id };
        storageService.savePlayer(updatedSwimmer);
        onUpdateSwimmer(updatedSwimmer);
        setView('current');
    };

    const handleLeave = () => {
        if (!currentClub) return;
        const oldClubId = currentClub.id;

        const updatedSwimmer = { ...swimmer, clubId: null };
        storageService.savePlayer(updatedSwimmer);

        const remainingMembers = storageService.getClubMemberCount(oldClubId);
        if (remainingMembers === 0) {
            storageService.deleteClub(oldClubId);
        }

        onUpdateSwimmer(updatedSwimmer);
        setView('list'); 
    };

    // Helper to get zones based on region
    const getAvailableZones = () => {
        const region = SPANISH_GEOGRAPHY.find(r => r.id === selectedRegion);
        return region ? region.zones : [];
    };

    // Helper to get cities based on zone
    const getAvailableCities = () => {
        const region = SPANISH_GEOGRAPHY.find(r => r.id === selectedRegion);
        if (!region) return [];
        const zone = region.zones.find(z => z.id === selectedZone);
        return zone ? zone.cities : [];
    };

    return (
        <div className="space-y-6 animate-fade-in">
            <div className="text-center mb-8">
                <h2 className="text-3xl font-black sport-font text-slate-800 uppercase italic">Sede del Club</h2>
                <p className="text-sm text-slate-600 font-medium">Únete a otros jugadores reales o crea tu legado.</p>
            </div>

            <div className="flex justify-center gap-4 mb-6">
                <button 
                    onClick={() => setView('current')}
                    className={`px-5 py-2 rounded-full text-sm font-bold transition-all border ${view === 'current' ? 'bg-blue-600 text-white border-blue-600 shadow-md' : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50'}`}
                >
                    Mi Club
                </button>
                <button 
                    onClick={() => setView('list')}
                    className={`px-5 py-2 rounded-full text-sm font-bold transition-all border ${view === 'list' ? 'bg-blue-600 text-white border-blue-600 shadow-md' : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50'}`}
                >
                    Buscar Club
                </button>
                {!swimmer.clubId && (
                    <button 
                        onClick={() => { setFormName(''); setView('create'); }}
                        className={`px-5 py-2 rounded-full text-sm font-bold transition-all border ${view === 'create' ? 'bg-blue-600 text-white border-blue-600 shadow-md' : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50'}`}
                    >
                        Fundar Club
                    </button>
                )}
            </div>

            {view === 'current' && (
                <div className="space-y-8 animate-fade-in">
                    <div className="glass-panel p-8 rounded-3xl shadow-lg border border-white/50 text-center max-w-lg mx-auto relative overflow-hidden">
                         <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-blue-400 via-cyan-400 to-blue-400"></div>
                        {currentClub ? (
                            <>
                                <div className={`relative w-28 h-28 rounded-full mx-auto flex items-center justify-center mb-6 text-5xl shadow-2xl border-4 border-white ${currentClub.logo.bgColor}`}>
                                    <span className={currentClub.logo.color}>{currentClub.logo.icon}</span>
                                    <div className="absolute -bottom-2 -right-2 w-10 h-10 bg-white rounded-full flex items-center justify-center shadow-md border-2 border-slate-100 text-xl" title="País">
                                        {COUNTRY_FLAGS[currentClub.location.countryId] || '🏳️'}
                                    </div>
                                </div>
                                <h3 className="text-3xl font-black sport-font text-slate-800 mb-2 leading-none">{currentClub.name}</h3>
                                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-4">
                                    {currentClub.location.cityName} 
                                    {currentClub.location.countryId === 'ES' && ` • ${currentClub.location.regionId}`}
                                </div>

                                <div className="flex justify-center mb-8">
