import React, { useState, useEffect } from 'react';
import { storageService } from '../services/storageService';
import { Swimmer, Club } from '../types';
import { COUNTRY_FLAGS } from '../constants';

interface AuthProps {
    onAuth: (name: string, isRegistering: boolean) => void;
    error: string | null;
    onClearError: () => void;
}

export const Auth: React.FC<AuthProps> = ({ onAuth, error, onClearError }) => {
    const [name, setName] = useState('');
    const [isRegistering, setIsRegistering] = useState(false);
    const [existingPlayers, setExistingPlayers] = useState<Swimmer[]>([]);
    const [clubs, setClubs] = useState<Club[]>([]);

    useEffect(() => {
        setExistingPlayers(storageService.getAllPlayers());
        setClubs(storageService.getClubs());
    }, []);

    const formatName = (input: string) => {
        // Replace multiple spaces with single space
        const cleaned = input.replace(/\s+/g, ' ');
        // Capitalize first letter of each word
        return cleaned.toLowerCase().replace(/(?:^|\s)\S/g, (a) => a.toUpperCase());
    };

    const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        setName(formatName(e.target.value));
        if (error) onClearError();
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (name.trim().length > 0) {
            onAuth(name.trim(), isRegistering);
        }
    };

    const toggleMode = () => {
        setIsRegistering(!isRegistering);
        if (error) onClearError();
    };

    // Grouping Logic
    const playersByClub: Record<string, Swimmer[]> = {};
    const freeAgents: Swimmer[] = [];

    existingPlayers.forEach(p => {
        if (p.clubId) {
            if (!playersByClub[p.clubId]) playersByClub[p.clubId] = [];
            playersByClub[p.clubId].push(p);
        } else {
            freeAgents.push(p);
        }
    });

    // Sort clubs by prestige for display order
    const sortedClubsWithPlayers = clubs
        .filter(c => playersByClub[c.id] && playersByClub[c.id].length > 0)
        .sort((a, b) => b.prestige - a.prestige);

    return (
        <div className="min-h-screen flex items-center justify-center p-4">
            <div className="bg-white/90 backdrop-blur-md p-8 rounded-2xl shadow-2xl w-full max-w-md border border-white/50 animate-fade-in my-8">
                <div className="text-center mb-8">
                    <div className="inline-block bg-blue-600 text-white p-4 rounded-xl font-bold text-3xl mb-4 shadow-lg">NP</div>
                    <h1 className="text-3xl font-extrabold text-slate-800">NadarPro</h1>
                    <p className="text-slate-500">Simulador de Carrera Profesional</p>
                </div>

                {error && (
                    <div className="bg-red-50 border-l-4 border-red-500 p-4 mb-6 rounded-r">
                        <div className="flex">
                            <div className="flex-shrink-0">
                                <svg className="h-5 w-5 text-red-500" viewBox="0 0 20 20" fill="currentColor">
                                    <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
                                </svg>
                            </div>
                            <div className="ml-3">
                                <p className="text-sm text-red-700 font-bold">{error}</p>
                            </div>
                        </div>
                    </div>
                )}

                {!isRegistering && existingPlayers.length > 0 && (
                    <div className="mb-8">
                        <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-3">Selecciona tu perfil</h3>

                        <div className="max-h-64 overflow-y-auto pr-2 custom-scrollbar space-y-4">

                            {/* Render Clubs */}
                            {sortedClubsWithPlayers.map(club => (
                                <div key={club.id} className="bg-slate-50 rounded-xl border border-slate-200 overflow-hidden">
                                    <div className="bg-slate-100 px-3 py-2 border-b border-slate-200 flex justify-between items-center">
                                        <div className="flex items-center gap-2">
                                            <div className={`w-6 h-6 rounded-full flex items-center justify-center text-xs border border-white ${club.logo.bgColor}`}>
                                                <span className={club.logo.color}>{club.logo.icon}</span>
                                            </div>
                                            <span className="font-bold text-slate-700 text-sm">{club.name}</span>
                                        </div>
                                        <span className="text-xs">{COUNTRY_FLAGS[club.location.countryId]}</span>
                                    </div>
                                    <div className="divide-y divide-slate-100">
                                        {playersByClub[club.id].map(player => (
                                            <button
                                                key={player.id}
                                                onClick={() => onAuth(player.name, false)}
                                                className="w-full flex items-center gap-3 p-3 hover:bg-blue-50 transition-colors text-left group"
                                            >
                                                <div className="w-8 h-8 bg-white border border-slate-200 rounded-full flex items-center justify-center font-bold text-xs text-slate-600 group-hover:text-blue-600 group-hover:border-blue-200">
                                                    {player.name.charAt(0)}
                                                </div>
                                                <div className="flex-1">
                                                    <div className="font-bold text-slate-700 text-sm group-hover:text-blue-700">{player.name}</div>
                                                    <div className="text-[10px] text-slate-400">Nivel {player.level}</div>
                                                </div>
                                                <div className="text-slate-300 group-hover:text-blue-400 text-sm">➜</div>
                                            </button>
                                        ))}
                                    </div>
                                </div>
                            ))}

                            {/* Render Free Agents */}
                            {freeAgents.length > 0 && (
                                <div className="bg-slate-50 rounded-xl border border-slate-200 overflow-hidden">
                                     <div className="bg-slate-100 px-3 py-2 border-b border-slate-200 flex items-center gap-2">
                                        <span className="text-sm">🏚️</span>
                                        <span className="font-bold text-slate-500 text-sm uppercase tracking-wide">Agentes Libres</span>
                                     </div>
                                     <div className="divide-y divide-slate-100">
                                        {freeAgents.map(player => (
                                            <button
                                                key={player.id}
                                                onClick={() => onAuth(player.name, false)}
                                                className="w-full flex items-center gap-3 p-3 hover:bg-blue-50 transition-colors text-left group"
                                            >
                                                <div className="w-8 h-8 bg-white border border-slate-200 rounded-full flex items-center justify-center font-bold text-xs text-slate-600 group-hover:text-blue-600 group-hover:border-blue-200">
                                                    {player.name.charAt(0)}
                                                </div>
                                                <div className="flex-1">
                                                    <div className="font-bold text-slate-700 text-sm group-hover:text-blue-700">{player.name}</div>
                                                    <div className="text-[10px] text-slate-400">Nivel {player.level}</div>
                                                </div>
                                                <div className="text-slate-300 group-hover:text-blue-400 text-sm">➜</div>
                                            </button>
                                        ))}
                                     </div>
                                </div>
                            )}
                        </div>

                        <div className="relative flex py-5 items-center">
                            <div className="flex-grow border-t border-slate-200"></div>
                            <span className="flex-shrink-0 mx-4 text-slate-400 text-xs font-medium">O inicia sesión manualmente</span>
                            <div className="flex-grow border-t border-slate-200"></div>
                        </div>
                    </div>
                )}

                <form onSubmit={handleSubmit} className="space-y-6">
                    <div>
                        <label className="block text-sm font-bold text-slate-700 mb-2">
                            {isRegistering ? 'Crear Nuevo Nadador' : 'Nombre de Usuario'}
                        </label>
                        <input
                            type="text"
                            value={name}
                            onChange={handleChange}
                            className={`w-full px-4 py-3 rounded-lg border ${error ? 'border-red-300 ring-red-200' : 'border-slate-300 focus:ring-blue-500 focus:border-blue-500'} focus:ring-2 outline-none transition-all`}
                            placeholder="Ej. Michael Phelps"
                            required
                        />
                        {isRegistering && (
                            <p className="text-xs text-slate-400 mt-1">
                                Se capitalizará automáticamente (Ej. "michael phelps" -> "Michael Phelps")
                            </p>
                        )}
                    </div>

                    <button
                        type="submit"
                        className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 px-6 rounded-lg shadow-md hover:shadow-lg transition-all transform hover:-translate-y-0.5"
                    >
                        {isRegistering ? 'Crear Cuenta' : 'Iniciar Sesión'}
                    </button>
                </form>

                <div className="mt-6 text-center">
                    <button
                        onClick={toggleMode}
                        className="text-sm text-blue-600 hover:text-blue-800 font-semibold"
                    >
                        {isRegistering ? '¿Ya tienes cuenta? Volver al inicio' : '¿Nuevo nadador? Regístrate'}
                    </button>
                </div>
            </div>
        </div>
    );
};

