import { Stats, Attribute, Stroke, StartListEntry } from '../types';

// Helper to format time
export const formatTime = (seconds: number): string => {
    if (seconds >= 3599) return "59:59.99";

    const min = Math.floor(seconds / 60);
    const sec = Math.floor(seconds % 60);
    const ms = Math.floor((seconds - Math.floor(seconds)) * 100);
    return `${min > 0 ? `${min}:` : ''}${sec.toString().padStart(2, '0')}.${ms.toString().padStart(2, '0')}`;
};

// Physics Constants for simulation
const WORLD_RECORDS: Record<number, number> = { 50: 20.91, 100: 46.80, 200: 102.00 };
const BASE_TIMES: Record<number, number> = { 50: 45.0, 100: 105.0, 200: 240.0 }; // Times for a novice (stats ~10)

// Attribute Weights per Distance
// This defines the "DNA" of each race type
const DISTANCE_WEIGHTS: Record<number, Partial<Record<Attribute, number>>> = {
    50: {
        [Attribute.Strength]: 0.30,  // Explosive start & power
        [Attribute.Speed]: 0.30,     // Stroke rate
        [Attribute.Technique]: 0.15, // Efficiency
        [Attribute.StartTurn]: 0.20, // Huge impact on 50m (start is 20% of race)
        [Attribute.Stamina]: 0.05,   // Barely matters
    },
    100: {
        [Attribute.Strength]: 0.15,
        [Attribute.Speed]: 0.20,
        [Attribute.Technique]: 0.30, // Technique becomes vital
        [Attribute.StartTurn]: 0.15, // Still important (1 turn + start)
        [Attribute.Stamina]: 0.20,   // Endurance starts to matter
    },
    200: {
        [Attribute.Strength]: 0.05,  // Muscle bulk can be drag
        [Attribute.Speed]: 0.10,
        [Attribute.Technique]: 0.35, // Efficiency is king
        [Attribute.Stamina]: 0.40,   // Aerobic capacity is queen
        [Attribute.StartTurn]: 0.10, // 3 turns, but smaller % of total time
    }
};

export const calculateTime = (stats: Stats, distance: number, stroke: Stroke): number => {
    const weights = DISTANCE_WEIGHTS[distance] || DISTANCE_WEIGHTS[100];
    const baseTime = BASE_TIMES[distance] || 120;
    const minTime = WORLD_RECORDS[distance] || 50;

    // 1. Calculate Weighted Performance Score
    // We treat stats as if 100 is "Elite". The game allows going higher, which beats records.
    let performanceScore = 0;

    // Ensure StartTurn has a default if missing from legacy saves in logic
    const startTurnVal = stats[Attribute.StartTurn] || 10;
    const statsWithDefaults = { ...stats, [Attribute.StartTurn]: startTurnVal };

    performanceScore += (statsWithDefaults[Attribute.Strength] * (weights[Attribute.Strength] || 0));
    performanceScore += (statsWithDefaults[Attribute.Speed] * (weights[Attribute.Speed] || 0));
    performanceScore += (statsWithDefaults[Attribute.Technique] * (weights[Attribute.Technique] || 0));
    performanceScore += (statsWithDefaults[Attribute.Stamina] * (weights[Attribute.Stamina] || 0));
    performanceScore += (statsWithDefaults[Attribute.StartTurn] * (weights[Attribute.StartTurn] || 0));

    // 2. Mental Stat Logic (Variance)
    // High Mental = Consistent times close to your potential.
    // Low Mental = High volatility (could be great, usually bad).
    const mentalStat = statsWithDefaults[Attribute.Mental];
    const mentalFactor = Math.min(1, mentalStat / 100); // 0 to 1

    // Base variance is +/- 3% of the time for a novice, decreasing to +/- 0.5% for a pro
    const maxVariancePct = 0.05 - (mentalFactor * 0.04); 
    const randomVariance = (Math.random() * 2 - 1) * maxVariancePct; // -0.05 to +0.05

    // "In The Zone" Bonus: Very small chance to get a massive boost if Mental is high
    let zoneBonus = 0;
    if (Math.random() < (mentalStat / 500)) { // e.g. 50 Mental = 10% chance
        zoneBonus = 0.02; // 2% faster
    }

    // 3. Map Score to Time
    // We use a logarithmic decay curve. Gaining stats at low level helps A LOT.
    // Gaining stats at high level helps a little.

    // Normalize score roughly relative to 100.
    // If score is 10, improvement is small. If score is 100, improvement is huge.
    // Formula: Time = Base - (Diff * (1 - 1/(1 + k*Score)))
    // Where Diff = Base - Min
    const maxImprovement = baseTime - minTime;

    // Curve factor 'k'. 
    // If Score = 10, we want time to be approx Base.
    // If Score = 100, we want time to be approx Min.
    const k = 0.025; 
    const improvementRatio = 1 - (1 / (1 + (k * performanceScore)));

    let calculatedTime = baseTime - (maxImprovement * improvementRatio);

    // Apply Variance & Bonus
    calculatedTime = calculatedTime * (1 + randomVariance - zoneBonus);

    // Hard floor just in case (World Record - 10%)
    const hardFloor = minTime * 0.9;
    if (calculatedTime < hardFloor) calculatedTime = hardFloor + Math.random();

    return calculatedTime;
};

// Generate Heat Sheets with Spearhead seeding (Center lanes are fastest)
export const organizeHeats = (entries: StartListEntry[]): { heat: number, lane: number, entry: StartListEntry }[] => {
    // 1. Sort by entry time (Fastest to Slowest)
    const sorted = [...entries].sort((a, b) => a.entryTime - b.entryTime);

    // 2. Chunk into heats of 8
    const heats: StartListEntry[][] = [];
    for (let i = 0; i < sorted.length; i += 8) {
        heats.push(sorted.slice(i, i + 8));
    }

    // 3. Reverse heats so fastest heat is last
    heats.reverse();

    const result: { heat: number, lane: number, entry: StartListEntry }[] = [];
    const laneOrder = [4, 5, 3, 6, 2, 7, 1, 8]; // 1-based index

    heats.forEach((heatEntries, heatIndex) => {
        // heatEntries are sorted fast -> slow.
        // Assign to laneOrder.
        heatEntries.forEach((entry, idx) => {
            result.push({
                heat: heatIndex + 1,
                lane: laneOrder[idx],
                entry
            });
        });
    });

    return result;
};

import { Club, Swimmer, CompetitionTier, StartListEntry, RaceResult, Stroke, RecordHolder } from '../types';
import { calculateTime } from './gameLogic';
import { PRESTIGE_REWARDS, DEFAULT_TIME, CASH_REWARDS, CONTINENTS } from '../constants';

const DB_KEY = 'NADARPRO_DB_V2';

interface Database {
    players: Record<string, Swimmer>;
    clubs: Record<string, Club>;
    raceEntries: Record<string, StartListEntry[]>; 
    raceResults: Record<string, RaceResult[]>;
    records: Record<string, RecordHolder>; // Key: "Scope-Distance" e.g. "WORLD-50", "ES-100"
}

const getDB = (): Database => {
    const raw = localStorage.getItem(DB_KEY);
    if (!raw) {
        return { players: {}, clubs: {}, raceEntries: {}, raceResults: {}, records: {} };
    }
    const db = JSON.parse(raw);
    if (!db.raceResults) db.raceResults = {};
    if (!db.records) db.records = {};
    return db;
};

const saveDB = (db: Database) => {
    localStorage.setItem(DB_KEY, JSON.stringify(db));
};

// Helper to determine continent key
const getContinentKey = (countryId: string): string => {
    if (CONTINENTS.EUROPE.includes(countryId)) return 'EU';
    if (CONTINENTS.ASIA.includes(countryId)) return 'AS';
    if (CONTINENTS.AMERICA_OCEANIA.includes(countryId)) return 'AO';
    return 'OTHER';
};

export const storageService = {
    // Player Methods
    getPlayer: (name: string): Swimmer | null => {
        const db = getDB();
        const player = Object.values(db.players).find(p => p.name.toLowerCase() === name.toLowerCase());
        return player || null;
    },

    getAllPlayers: (): Swimmer[] => {
        const db = getDB();
        return Object.values(db.players);
    },

    savePlayer: (swimmer: Swimmer) => {
        const db = getDB();
        db.players[swimmer.id] = swimmer;
        saveDB(db);
    },

    updatePlayerFields: (id: string, fields: Partial<Swimmer>) => {
        const db = getDB();
        if (db.players[id]) {
            db.players[id] = { ...db.players[id], ...fields };
            saveDB(db);
        }
    },

    // Club Methods
    getClubs: (): Club[] => {
        const db = getDB();
        return Object.values(db.clubs);
    },

    getClub: (id: string): Club | null => {
        const db = getDB();
        return db.clubs[id] || null;
    },

    saveClub: (club: Club) => {
        const db = getDB();
        db.clubs[club.id] = club;
        saveDB(db);
    },

    deleteClub: (clubId: string) => {
        const db = getDB();
        if (db.clubs[clubId]) {
            delete db.clubs[clubId];
            saveDB(db);
        }
    },

    getClubMemberCount: (clubId: string): number => {
        const db = getDB();
        return Object.values(db.players).filter(p => p.clubId === clubId).length;
    },

    getClubMembers: (clubId: string): Swimmer[] => {
        const db = getDB();
        return Object.values(db.players).filter(p => p.clubId === clubId);
    },

    // Helper to generate geographic keys
    getRaceKey: (tier: CompetitionTier, distance: number, startTime: number, club?: Club | null): string => {
        let suffix = '';

        if (club) {
            if (tier === CompetitionTier.Provincial) {
                // Key: Provincial-Z1-50-123456
                suffix = club.location.countryId === 'ES' && club.location.zoneId ? `-${club.location.zoneId}` : '-GEN'; 
            } else if (tier === CompetitionTier.Regional) {
                // Key: Regional-CLM-50-123456
                suffix = club.location.countryId === 'ES' && club.location.regionId ? `-${club.location.regionId}` : '-GEN';
            } else if (tier === CompetitionTier.National) {
                // Key: National-ES-50-123456
                suffix = `-${club.location.countryId}`;
            } else if (tier === CompetitionTier.European) {
                // Logic: Continental Split
                const cont = getContinentKey(club.location.countryId);
                suffix = `-${cont}`;
            }
        } else {
             // Fallback for players without club
             if ([CompetitionTier.Provincial, CompetitionTier.Regional, CompetitionTier.National, CompetitionTier.European].includes(tier)) {
                 suffix = '-OPEN';
             }
        }

        // International Club Cup and others are global
        return `${tier}${suffix}-${distance}-${startTime}`;
    },

    // Competition Methods
    registerForRace: (tier: CompetitionTier, distance: number, startTime: number, entry: StartListEntry) => {
        const db = getDB();

        // Find player club to determine location key
        const player = db.players[entry.playerId];
        const club = player && player.clubId ? db.clubs[player.clubId] : null;

        const raceKey = storageService.getRaceKey(tier, distance, startTime, club);

        if (!db.raceEntries[raceKey]) {
            db.raceEntries[raceKey] = [];
        }

        db.raceEntries[raceKey] = db.raceEntries[raceKey].filter(e => e.playerId !== entry.playerId);
        db.raceEntries[raceKey].push(entry);

        saveDB(db);
    },

    unregisterFromRace: (tier: CompetitionTier, distance: number, startTime: number, playerId: string) => {
        const db = getDB();

        // We need to reconstruct the key. Assuming the player is still in the same club.
        const player = db.players[playerId];
        const club = player && player.clubId ? db.clubs[player.clubId] : null;
        const raceKey = storageService.getRaceKey(tier, distance, startTime, club);

        if (db.raceEntries[raceKey]) {
            db.raceEntries[raceKey] = db.raceEntries[raceKey].filter(e => e.playerId !== playerId);
            saveDB(db);
        }
    },

    getRaceEntries: (tier: CompetitionTier, distance: number, startTime: number, contextClub?: Club | null): StartListEntry[] => {
        const db = getDB();
        // The UI passes the current user's club as context so we know which list to fetch
        const raceKey = storageService.getRaceKey(tier, distance, startTime, contextClub);
        const rawEntries = db.raceEntries[raceKey] || [];

        return rawEntries.map(entry => {
            if (entry.isPlayer && entry.playerId && db.players[entry.playerId]) {
                const player = db.players[entry.playerId];
                const club = player.clubId ? db.clubs[player.clubId] : null;
                const pbKey = `${Stroke.Freestyle}-${distance}`;
                const currentPB = player.personalBests[pbKey] || DEFAULT_TIME;

                return {
                    ...entry,
                    name: player.name,
                    club: club ? club.name : "Sin Club",
                    entryTime: currentPB
                };
            }
            return entry;
        });
    },

    processRaceResults: (tier: CompetitionTier, distance: number, startTime: number, stroke: Stroke, contextClub?: Club | null): RaceResult[] => {
        const db = getDB();
        const raceKey = storageService.getRaceKey(tier, distance, startTime, contextClub);

        if (db.raceResults[raceKey]) {
            return db.raceResults[raceKey];
        }

        const entries = db.raceEntries[raceKey] || [];
        if (entries.length === 0) return [];

        const results: RaceResult[] = entries.map(entry => {
            let raceTime = entry.entryTime;
            let clubName = entry.club;
            const player = db.players[entry.playerId];

            if (player) {
                raceTime = calculateTime(player.stats, distance, stroke);
                if (player.clubId && db.clubs[player.clubId]) {
                    clubName = db.clubs[player.clubId].name;
                } else {
                    clubName = "Sin Club";
                }
            } else {
                if (Math.abs(raceTime - DEFAULT_TIME) < 1) {
                    raceTime = (distance === 50 ? 30 : 65) + (Math.random() * 10 - 5);
                } else {
                    raceTime = entry.entryTime + (Math.random() * 1.5 - 0.75);
                }
            }

            return {
                rank: 0,
                swimmerName: entry.name,
                club: clubName,
                time: raceTime,
                isPlayer: !!player,
                playerId: entry.playerId
            };
        });

        results.sort((a, b) => a.time - b.time);
        results.forEach((r, i) => r.rank = i + 1);

        results.forEach(result => {
            if (result.playerId && db.players[result.playerId]) {
                const p = db.players[result.playerId];
                const pbKey = `${stroke}-${distance}`;
                const currentPB = p.personalBests[pbKey] || DEFAULT_TIME;

                // Update PB
                if (result.time < currentPB) {
                    p.personalBests[pbKey] = result.time;
                }

                // Check for Records
                // Only players in clubs can hold official records (to simplify country logic)
                if (p.clubId && db.clubs[p.clubId]) {
                    const club = db.clubs[p.clubId];
                    const countryId = club.location.countryId;
                    const continentKey = getContinentKey(countryId);

                    // Check World Record
                    const worldKey = `WORLD-${distance}`;
                    const currentWR = db.records[worldKey];
                    if (!currentWR || result.time < currentWR.time) {
                        db.records[worldKey] = {
                            time: result.time,
                            holderId: p.id,
                            holderName: p.name,
                            clubName: club.name,
                            clubCountry: countryId,
                            date: Date.now()
                        };
                        result.recordBroken = 'World';
                        club.prestige += 100; // Major Prestige
                        p.money += 2000; // Bonus Money
                    }

                    // Check Continental Record (European, etc.)
                    const contKey = `${continentKey}-${distance}`;
                    const currentCR = db.records[contKey];
                    if (!currentCR || result.time < currentCR.time) {
                        db.records[contKey] = {
                            time: result.time,
                            holderId: p.id,
                            holderName: p.name,
                            clubName: club.name,
                            clubCountry: countryId,
                            date: Date.now()
                        };
                        if (!result.recordBroken) result.recordBroken = 'European'; // Generalized label
                        club.prestige += 50;
                        p.money += 1000;
                    }

                    // Check National Record
                    const natKey = `${countryId}-${distance}`;
                    const currentNR = db.records[natKey];
                    if (!currentNR || result.time < currentNR.time) {
                        db.records[natKey] = {
                            time: result.time,
                            holderId: p.id,
                            holderName: p.name,
                            clubName: club.name,
                            clubCountry: countryId,
                            date: Date.now()
                        };
                        if (!result.recordBroken) result.recordBroken = 'National';
                        club.prestige += 20;
                        p.money += 500;
                    }
                }

                if (tier !== CompetitionTier.Triangular) {
                    const xpGain = Math.max(10, 110 - (result.rank * 10)) * (
                        tier === CompetitionTier.World ? 5 :
                        tier === CompetitionTier.European ? 3 : 
                        1
                    );

                    p.xp += xpGain;
                    p.level = Math.floor(p.xp / 100) + 1;

                    const rewards = CASH_REWARDS[tier] || [0, 0, 0, 0];
                    let prizeMoney = 0;
                    if (result.rank === 1) prizeMoney = rewards[0];
                    else if (result.rank === 2) prizeMoney = rewards[1];
                    else if (result.rank === 3) prizeMoney = rewards[2];
                    else if (result.rank <= 8) prizeMoney = rewards[3];

                    if (p.money === undefined) p.money = 0;
                    p.money += prizeMoney;

                    // Generate a zone name for history
                    let zoneLabel = "";
                    if (contextClub && tier === CompetitionTier.Provincial) zoneLabel = contextClub.location.zoneId || "";
                    if (contextClub && tier === CompetitionTier.Regional) zoneLabel = contextClub.location.regionId || "";
                    if (contextClub && tier === CompetitionTier.National) zoneLabel = contextClub.location.countryId || "";
                    if (contextClub && tier === CompetitionTier.European) zoneLabel = getContinentKey(contextClub.location.countryId);

                    p.history.unshift({
                        id: raceKey,
                        tier,
                        stroke,
                        distance,
                        time: result.time,
                        rank: result.rank,
                        date: 1, 
                        realTimeDate: Date.now(),
                        zoneName: zoneLabel
                    });

                    if (result.rank === 1) p.medals.gold++;
                    if (result.rank === 2) p.medals.silver++;
                    if (result.rank === 3) p.medals.bronze++;

                    if (result.rank <= 3 && p.clubId && db.clubs[p.clubId]) {
                        const prestigeRewards = PRESTIGE_REWARDS[tier];
                        if (prestigeRewards) {
                            db.clubs[p.clubId].prestige += prestigeRewards[result.rank - 1];
                        }
                    }
                }
            }
        });

        db.raceResults[raceKey] = results;
        saveDB(db);

        return results;
    },

    getOfficialResults: (tier: CompetitionTier, startTime: number, contextClub?: Club | null): { distance: number, results: RaceResult[] }[] => {
        const db = getDB();
        const distances = [50, 100, 200];
        const output: { distance: number, results: RaceResult[] }[] = [];

        distances.forEach(dist => {
            const raceKey = storageService.getRaceKey(tier, dist, startTime, contextClub);
            if (db.raceResults[raceKey]) {
                output.push({ distance: dist, results: db.raceResults[raceKey] });
            }
        });

        return output;
    },

    getRecords: () => {
        const db = getDB();
        return db.records;
    }
};

