    [CompetitionTier.Triangular]: { 50: 999, 100: 999, 200: 999 },
    [CompetitionTier.Provincial]: { 50: 999, 100: 999, 200: 999 },
    [CompetitionTier.Regional]: { 50: 35.42, 100: 80.76, 200: 167.38 }, // 2:47.38
    [CompetitionTier.National]: { 50: 29.88, 100: 70.44, 200: 145.44 }, // 2:25.44
    [CompetitionTier.InternationalClub]: { 50: 28.50, 100: 65.00, 200: 135.00 },
    [CompetitionTier.European]: { 50: 27.13, 100: 59.82, 200: 130.92 }, // 2:10.92
    [CompetitionTier.World]: { 50: 25.05, 100: 55.39, 200: 122.19 }, // 2:02.19
};

import React, { useState, useEffect } from 'react';
import { Attribute, Club, GameState, Stats, PastRace, Swimmer, CompetitionTier } from './types';
import { MAX_ENERGY, ENERGY_RECHARGE_MS, DEFAULT_TIME, PRESTIGE_REWARDS } from './constants';
import { Training } from './components/Training';
import { Competition } from './components/Competition';
import { formatTime } from './services/gameLogic';
import { Auth } from './components/Auth';
import { Profile } from './components/Profile';
import { ClubManager } from './components/ClubManager';
import { Ranking } from './components/Ranking';
import { PlayerModal } from './components/PlayerModal';
import { storageService } from './services/storageService';

const INITIAL_STATS: Stats = {
    [Attribute.Strength]: 10,
    [Attribute.Technique]: 10,
    [Attribute.Stamina]: 10,
    [Attribute.Mental]: 10,
    [Attribute.Speed]: 10,
    [Attribute.StartTurn]: 10 // New Stat
};

const createNewSwimmer = (name: string): Swimmer => ({
    id: Date.now().toString(),
    name,
    clubId: null,
    stats: INITIAL_STATS,
    level: 1,
    xp: 0,
    personalBests: {}, // Empty means DEFAULT_TIME
    history: [],
    medals: { gold: 0, silver: 0, bronze: 0 },
    energy: MAX_ENERGY,
    lastEnergyUpdate: Date.now()
});

const INITIAL_STATE: GameState = {
    day: 1,
    selectedTab: 'dashboard',
    swimmer: null,
    clubs: []
};

export default function App() {
    const [gameState, setGameState] = useState<GameState>(INITIAL_STATE);
    const [refreshTrigger, setRefreshTrigger] = useState(0); // Used to force updates when cloud data changes
    const [authError, setAuthError] = useState<string | null>(null);
    const [viewedPlayerId, setViewedPlayerId] = useState<string | null>(null);

    // Load initial data
    useEffect(() => {
        const clubs = storageService.getClubs();
        setGameState(prev => ({ ...prev, clubs }));
    }, [refreshTrigger]);

    // Poll for club/player updates (Simulate real-time cloud)
    useEffect(() => {
        const interval = setInterval(() => {
             const clubs = storageService.getClubs();
             // Only update non-swimmer specific data to avoid overwriting local energy state being tracked
             setGameState(prev => ({ ...prev, clubs }));
        }, 5000);
        return () => clearInterval(interval);
    }, []);

    // Energy Recharge System (Active)
    useEffect(() => {
        if (!gameState.swimmer) return;

        const timer = setInterval(() => {
            setGameState(prev => {
                if (!prev.swimmer) return prev;

                const swimmer = prev.swimmer;

                // If full, just update timestamp
                if (swimmer.energy >= MAX_ENERGY) {
                     return { 
                        ...prev, 
                        swimmer: { ...swimmer, lastEnergyUpdate: Date.now() } 
                    };
                }

                const now = Date.now();
                const elapsed = now - swimmer.lastEnergyUpdate;

                // Full Recharge Logic: If 30 mins passed, fill ALL bars
                if (elapsed >= ENERGY_RECHARGE_MS) {

                    // SAFE UPDATE: Use partial update to avoid overwriting PBs/History 
                    // if a race finished in the background or during this tick.
                    storageService.updatePlayerFields(swimmer.id, {
                        energy: MAX_ENERGY,
                        lastEnergyUpdate: now
                    });

                    return {
                        ...prev,
                        swimmer: {
                            ...swimmer,
                            energy: MAX_ENERGY,
                            lastEnergyUpdate: now
                        }
                    };
                }
                return prev;
            });
        }, 1000); 

        return () => clearInterval(timer);
    }, [gameState.swimmer?.name]); // Re-bind if user changes

    const handleAuth = (name: string, isRegistering: boolean) => {
        setAuthError(null);
        let swimmer = storageService.getPlayer(name);

        if (isRegistering) {
            // Register flow
            if (swimmer) {
                setAuthError("El nombre de usuario ya existe. Por favor, inicia sesión.");
                return;
            }
            // Create new
            swimmer = createNewSwimmer(name);
            storageService.savePlayer(swimmer);
        } else {
            // Login flow
            if (!swimmer) {
                setAuthError("Usuario no encontrado. Verifica el nombre o regístrate.");
                return;
            }

            // Ensure Migration for StartTurn
            if (swimmer.stats[Attribute.StartTurn] === undefined) {
                swimmer.stats[Attribute.StartTurn] = 10;
            }

            // OFFLINE ENERGY REGEN
            if (swimmer.energy < MAX_ENERGY) {
                // Handle legacy data (if energy is missing)
                const lastUpdate = swimmer.lastEnergyUpdate || Date.now();

                const now = Date.now();
                const elapsed = now - lastUpdate;

                // If enough time passed since last update, Full Recharge
                if (elapsed >= ENERGY_RECHARGE_MS) {
                    swimmer.energy = MAX_ENERGY;
                    swimmer.lastEnergyUpdate = now;
                    storageService.savePlayer(swimmer);
                }
            } else {
                // Ensure legacy swimmers get defaults
                if (swimmer.energy === undefined) swimmer.energy = MAX_ENERGY;
                if (!swimmer.lastEnergyUpdate) swimmer.lastEnergyUpdate = Date.now();
            }
        }

        setGameState(prev => ({
            ...prev,
            swimmer,
            selectedTab: 'dashboard'
        }));
    };

    const handleLogout = () => {
        // Save state one last time
        if (gameState.swimmer) {
            storageService.savePlayer(gameState.swimmer);
        }
        setGameState(prev => ({ ...prev, swimmer: null }));
        setAuthError(null);
    };

    const handleTrain = (stat: Attribute, min: number, max: number) => {
        if (!gameState.swimmer || gameState.swimmer.energy <= 0) return;

        let baseGain = Math.floor(Math.random() * (max - min + 1)) + min;

        // Use updatePlayerFields here as well for safety, though manual triggers are safer.
        // However, we need to update state immediately for UI.

        const updatedSwimmer: Swimmer = {
            ...gameState.swimmer,
            stats: {
                ...gameState.swimmer.stats,
                [stat]: gameState.swimmer.stats[stat] + baseGain
            },
            xp: gameState.swimmer.xp + 10,
            level: Math.floor((gameState.swimmer.xp + 10) / 100) + 1,
            energy: gameState.swimmer.energy - 1,
            // If we use energy, reset the timer for the recharge cycle
            lastEnergyUpdate: Date.now()
        };

        // Safe update
        storageService.updatePlayerFields(updatedSwimmer.id, {
            stats: updatedSwimmer.stats,
            xp: updatedSwimmer.xp,
            level: updatedSwimmer.level,
            energy: updatedSwimmer.energy,
            lastEnergyUpdate: updatedSwimmer.lastEnergyUpdate
        });

        setGameState(prev => ({
            ...prev,
            swimmer: updatedSwimmer
        }));
    };

    const handleRaceComplete = (result: PastRace) => {
        if (!gameState.swimmer) return;

        // Note: storageService.processRaceResults has already updated the database 
        // with the new time, XP, medals, history, etc.

        // We just need to reload the fresh player object from storage to reflect these changes in UI immediately.
        const updatedSwimmer = storageService.getPlayer(gameState.swimmer.name);

        if (updatedSwimmer) {
            setGameState(prev => {
                const clubs = storageService.getClubs(); // Refresh clubs too (prestige changes)
                return { ...prev, swimmer: updatedSwimmer, clubs };
            });
        }
    };

    const handleUpdateSwimmer = (updated: Swimmer) => {
        setGameState(prev => ({ ...prev, swimmer: updated }));
        setRefreshTrigger(t => t + 1); // Trigger club reload
    };

    if (!gameState.swimmer) {
        return <Auth onAuth={handleAuth} error={authError} onClearError={() => setAuthError(null)} />;
    }

    const { swimmer, day, selectedTab, clubs } = gameState;
    const currentClub = clubs.find(c => c.id === swimmer.clubId);

    return (
        <div className="min-h-screen pb-20">
            {viewedPlayerId && (
                <PlayerModal playerId={viewedPlayerId} onClose={() => setViewedPlayerId(null)} />
            )}

            <header className="glass-panel sticky top-0 z-40 border-b border-white/40 px-6 py-4 flex justify-between items-center shadow-lg">
                <div className="flex items-center gap-3">
                    <div className="bg-cyan-500 text-white p-2 rounded-lg font-black text-xl italic shadow-md transform skew-x-[-10deg]">
                        <span className="block transform skew-x-[10deg]">NP</span>
                    </div>
                    <div>
                        <h1 className="font-bold text-slate-800 leading-none text-2xl sport-font tracking-wide">Nadar<span className="text-cyan-600">Pro</span></h1>
                        <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest bg-white/50 px-2 py-0.5 rounded-full">Temporada {day}</span>
                    </div>
                </div>

                <div className="flex items-center gap-6">
                    <div className="flex flex-col items-end">
                        <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-0.5">Energía</span>
                        <div className="flex gap-1">
                            {Array.from({length: MAX_ENERGY}, (_, i) => i + 1).map(i => (
                                <div 
                                    key={i} 
                                    className={`w-2.5 h-6 rounded-sm skew-x-[-10deg] transition-all duration-300 border border-white/50 ${i <= swimmer.energy ? 'bg-cyan-500 shadow-[0_0_8px_rgba(6,182,212,0.8)]' : 'bg-slate-200/50'}`}
                                />
                            ))}
                        </div>
                    </div>
                </div>
            </header>

            <main className="container mx-auto px-4 pt-8 max-w-5xl">
                {/* Stats Summary - Scoreboard Style */}
                <div className="grid grid-cols-2 md:grid-cols-7 gap-0.5 mb-8 bg-slate-900 p-2 rounded-xl shadow-2xl border-b-4 border-slate-700 overflow-hidden">
                    <div className="col-span-2 md:col-span-1 bg-slate-800 p-3 flex flex-col justify-center items-center relative">
                         <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-cyan-500 to-transparent opacity-50"></div>
                        <div className="text-[10px] text-cyan-400 uppercase font-bold tracking-widest mb-1">NIVEL</div>
                        <div className="text-4xl font-black text-white mono-font leading-none">{swimmer.level}</div>
                        <div className="w-full bg-slate-900 h-1.5 rounded-full mt-2 border border-slate-700">
                            <div className="bg-cyan-500 h-full rounded-full shadow-[0_0_10px_#06b6d4]" style={{ width: `${(swimmer.xp % 100)}%` }}></div>
                        </div>
                    </div>
                    {Object.entries(swimmer.stats).map(([key, val], i) => (
                        <div key={key} className={`bg-slate-800/90 p-3 flex flex-col justify-center items-center border-l border-slate-700`}>
                            <div className="text-[9px] md:text-[8px] lg:text-[10px] text-slate-400 uppercase font-bold tracking-wider mb-1 truncate w-full text-center">{key}</div>
                            <div className={`text-2xl font-bold mono-font ${(val as number) > 20 ? 'text-yellow-400' : 'text-white'}`}>{val as number}</div>
                        </div>
                    ))}
                </div>

                <div className="flex justify-center mb-8 overflow-x-auto pb-2">
                    <nav className="glass-panel p-1.5 rounded-full flex gap-1 shadow-lg whitespace-nowrap">
                        {[
                            { id: 'dashboard', label: 'Inicio', icon: '🏠' },
                            { id: 'training', label: 'Entreno', icon: '🏋️' },
                            { id: 'competition', label: 'Competición', icon: '🏊' },
                            { id: 'club', label: 'Club', icon: '🛡️' },
                            { id: 'ranking', label: 'Ranking', icon: '🏆' },
                            { id: 'profile', label: 'Perfil', icon: '👤' },
                        ].map(tab => (
                            <button
                                key={tab.id}
                                onClick={() => setGameState(prev => ({ ...prev, selectedTab: tab.id as any }))}
                                className={`
                                    px-5 py-2.5 rounded-full text-sm font-bold transition-all flex items-center gap-2
                                    ${selectedTab === tab.id 
                                        ? 'bg-gradient-to-br from-cyan-500 to-blue-600 text-white shadow-md transform scale-105' 
                                        : 'text-slate-600 hover:bg-cyan-50 hover:text-cyan-700'}
                                `}
                            >
                                <span className="text-base">{tab.icon}</span>
                                {tab.label}
                            </button>
                        ))}
                    </nav>
                </div>

                <div className="min-h-[400px]">
                    {selectedTab === 'dashboard' && (
                        <div className="animate-fade-in space-y-6">
                            <div className="bg-gradient-to-r from-cyan-600 to-blue-800 rounded-3xl p-8 text-white relative overflow-hidden shadow-xl wet-shine">
                                <h3 className="text-4xl font-black sport-font mb-2 italic">Hola, {swimmer.name}</h3>
                                <p className="opacity-90 font-medium max-w-lg">El agua no sabe tu edad, ni tu historia. El agua solo sabe lo rápido que nadas.</p>
                                <div className="absolute right-0 bottom-0 opacity-10 text-9xl transform translate-x-1/4 translate-y-1/4">🏊</div>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                <div className="glass-panel p-6 rounded-2xl flex items-center gap-4 hover:shadow-lg transition-all cursor-pointer" onClick={() => setGameState(prev => ({...prev, selectedTab: 'club'}))}>
                                     {currentClub ? (
                                         <>
                                            <div className={`w-20 h-20 rounded-full flex items-center justify-center text-3xl shadow-inner border-4 border-white ${currentClub.logo.bgColor}`}>
                                                <span className={currentClub.logo.color}>{currentClub.logo.icon}</span>
                                            </div>
                                            <div>
                                                <h3 className="font-bold text-lg text-slate-800 uppercase tracking-wide opacity-60">Tu Equipo</h3>
                                                <div className="text-2xl font-black text-cyan-700 sport-font leading-none">{currentClub.name}</div>
                                                <div className="text-xs font-bold text-slate-500 mt-2 uppercase tracking-wider bg-slate-100 inline-block px-2 py-1 rounded">Prestigio: {currentClub.prestige}</div>
                                            </div>
                                         </>
                                     ) : (
                                         <div className="text-slate-500 p-2 flex items-center gap-4">
                                             <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center text-2xl">🏚️</div>
                                             <div>
                                                 <h3 className="font-bold text-xl text-slate-800">Agente Libre</h3>
                                                 <p className="text-sm">Únete a un club para competir en ligas.</p>
                                             </div>
                                         </div>
                                     )}
                                </div>

                                <div className="glass-panel p-6 rounded-2xl hover:shadow-lg transition-all">
                                    <h3 className="font-bold text-slate-800 uppercase tracking-wider text-xs mb-3">Último Resultado</h3>
                                    {swimmer.history.length > 0 ? (
                                        <div className="flex items-center gap-4">
                                            <div className={`
                                                w-16 h-16 flex items-center justify-center rounded-2xl font-black text-2xl text-white shadow-md
                                                ${swimmer.history[0].rank === 1 ? 'bg-yellow-400' : 
                                                  swimmer.history[0].rank === 2 ? 'bg-slate-300' : 
                                                  swimmer.history[0].rank === 3 ? 'bg-orange-400' : 'bg-slate-800'}
                                            `}>
                                                {swimmer.history[0].rank}º
                                            </div>
                                            <div>
                                                <div className="font-bold text-lg text-slate-800">{swimmer.history[0].tier}</div>
                                                <div className="text-sm text-slate-600 font-medium">
                                                    {swimmer.history[0].distance}m {swimmer.history[0].stroke}
                                                </div>
                                                <div className="text-xl font-bold text-blue-600 mono-font mt-1">
                                                    {formatTime(swimmer.history[0].time)}
                                                </div>
                                            </div>
                                        </div>
                                    ) : (
                                        <p className="text-slate-400 text-sm py-4">Aún no has competido. ¡Ve a la piscina!</p>
                                    )}
                                </div>
                            </div>
                        </div>
                    )}

                    {selectedTab === 'training' && (
                        <Training 
                            energy={swimmer.energy} 
                            onTrain={handleTrain} 
                            lastEnergyUpdate={swimmer.lastEnergyUpdate} 
                        />
                    )}

                    {selectedTab === 'club' && (
                        <ClubManager 
                            swimmer={swimmer} 
                            availableClubs={gameState.clubs}
                            onUpdateSwimmer={handleUpdateSwimmer}
                            onViewPlayer={setViewedPlayerId}
                        />
                    )}

                    {selectedTab === 'competition' && (
                        <Competition 
                            swimmer={swimmer}
                            day={day} 
                            onRaceComplete={handleRaceComplete} 
                            onUpdateSwimmer={() => setRefreshTrigger(t => t+1)}
                            onViewPlayer={setViewedPlayerId}
                        />
                    )}

                    {selectedTab === 'ranking' && (
                        <Ranking onViewPlayer={setViewedPlayerId} />
                    )}

                    {selectedTab === 'profile' && (
                        <Profile swimmer={swimmer} onLogout={handleLogout} />
                    )}
                </div>
            </main>
        </div>
    );
}

import { Club, Swimmer, CompetitionTier, StartListEntry, RaceResult, Stroke, RecordHolder } from '../types';
import { calculateTime } from './gameLogic';
import { PRESTIGE_REWARDS, DEFAULT_TIME, CONTINENTS } from '../constants';

const DB_KEY = 'NADARPRO_DB_V2';

interface Database {
    players: Record<string, Swimmer>;
    clubs: Record<string, Club>;
    raceEntries: Record<string, StartListEntry[]>; 
    raceResults: Record<string, RaceResult[]>;
    records: Record<string, RecordHolder>; // Key: "Scope-Distance" e.g. "WORLD-50", "ES-100"
}

const getDB = (): Database => {
    const raw = localStorage.getItem(DB_KEY);
    if (!raw) {
        return { players: {}, clubs: {}, raceEntries: {}, raceResults: {}, records: {} };
    }
    const db = JSON.parse(raw);
    if (!db.raceResults) db.raceResults = {};
    if (!db.records) db.records = {};
    return db;
};

const saveDB = (db: Database) => {
    localStorage.setItem(DB_KEY, JSON.stringify(db));
};

// Helper to determine continent key
const getContinentKey = (countryId: string): string => {
    if (CONTINENTS.EUROPE.includes(countryId)) return 'EU';
    if (CONTINENTS.ASIA.includes(countryId)) return 'AS';
    if (CONTINENTS.AMERICA_OCEANIA.includes(countryId)) return 'AO';
    return 'OTHER';
};

export const storageService = {
    // Player Methods
    getPlayer: (name: string): Swimmer | null => {
        const db = getDB();
        const player = Object.values(db.players).find(p => p.name.toLowerCase() === name.toLowerCase());
        return player || null;
    },

    getAllPlayers: (): Swimmer[] => {
        const db = getDB();
        return Object.values(db.players);
    },

    savePlayer: (swimmer: Swimmer) => {
        const db = getDB();
        db.players[swimmer.id] = swimmer;
        saveDB(db);
    },

    updatePlayerFields: (id: string, fields: Partial<Swimmer>) => {
        const db = getDB();
        if (db.players[id]) {
            db.players[id] = { ...db.players[id], ...fields };
            saveDB(db);
        }
    },

    // Club Methods
    getClubs: (): Club[] => {
        const db = getDB();
        return Object.values(db.clubs);
    },

    getClub: (id: string): Club | null => {
        const db = getDB();
        return db.clubs[id] || null;
    },

    saveClub: (club: Club) => {
        const db = getDB();
        db.clubs[club.id] = club;
        saveDB(db);
    },

    deleteClub: (clubId: string) => {
        const db = getDB();
        if (db.clubs[clubId]) {
            delete db.clubs[clubId];
            saveDB(db);
        }
    },

    getClubMemberCount: (clubId: string): number => {
        const db = getDB();
        return Object.values(db.players).filter(p => p.clubId === clubId).length;
    },

    getClubMembers: (clubId: string): Swimmer[] => {
        const db = getDB();
        return Object.values(db.players).filter(p => p.clubId === clubId);
    },

    // Helper to generate geographic keys
    getRaceKey: (tier: CompetitionTier, distance: number, startTime: number, club?: Club | null): string => {
        let suffix = '';

        if (club) {
            if (tier === CompetitionTier.Provincial) {
                // Key: Provincial-Z1-50-123456
                suffix = club.location.countryId === 'ES' && club.location.zoneId ? `-${club.location.zoneId}` : '-GEN'; 
            } else if (tier === CompetitionTier.Regional) {
                // Key: Regional-CLM-50-123456
                suffix = club.location.countryId === 'ES' && club.location.regionId ? `-${club.location.regionId}` : '-GEN';
            } else if (tier === CompetitionTier.National) {
                // Key: National-ES-50-123456
                suffix = `-${club.location.countryId}`;
            } else if (tier === CompetitionTier.European) {
                // Logic: Continental Split
                const cont = getContinentKey(club.location.countryId);
                suffix = `-${cont}`;
            }
        } else {
             // Fallback for players without club
             if ([CompetitionTier.Provincial, CompetitionTier.Regional, CompetitionTier.National, CompetitionTier.European].includes(tier)) {
                 suffix = '-OPEN';
             }
        }

        // International Club Cup and others are global
        return `${tier}${suffix}-${distance}-${startTime}`;
    },

    // Competition Methods
    registerForRace: (tier: CompetitionTier, distance: number, startTime: number, entry: StartListEntry) => {
        const db = getDB();

        // Find player club to determine location key
        const player = db.players[entry.playerId];
        const club = player && player.clubId ? db.clubs[player.clubId] : null;

        const raceKey = storageService.getRaceKey(tier, distance, startTime, club);

        if (!db.raceEntries[raceKey]) {
            db.raceEntries[raceKey] = [];
        }

        db.raceEntries[raceKey] = db.raceEntries[raceKey].filter(e => e.playerId !== entry.playerId);
        db.raceEntries[raceKey].push(entry);

        saveDB(db);
    },

    unregisterFromRace: (tier: CompetitionTier, distance: number, startTime: number, playerId: string) => {
        const db = getDB();

        // We need to reconstruct the key. Assuming the player is still in the same club.
        const player = db.players[playerId];
        const club = player && player.clubId ? db.clubs[player.clubId] : null;
        const raceKey = storageService.getRaceKey(tier, distance, startTime, club);

        if (db.raceEntries[raceKey]) {
            db.raceEntries[raceKey] = db.raceEntries[raceKey].filter(e => e.playerId !== playerId);
            saveDB(db);
        }
    },

    getRaceEntries: (tier: CompetitionTier, distance: number, startTime: number, contextClub?: Club | null): StartListEntry[] => {
        const db = getDB();
        // The UI passes the current user's club as context so we know which list to fetch
        const raceKey = storageService.getRaceKey(tier, distance, startTime, contextClub);
        const rawEntries = db.raceEntries[raceKey] || [];

        return rawEntries.map(entry => {
            if (entry.isPlayer && entry.playerId && db.players[entry.playerId]) {
                const player = db.players[entry.playerId];
                const club = player.clubId ? db.clubs[player.clubId] : null;
                const pbKey = `${Stroke.Freestyle}-${distance}`;
                const currentPB = player.personalBests[pbKey] || DEFAULT_TIME;

                return {
                    ...entry,
                    name: player.name,
                    club: club ? club.name : "Sin Club",
                    entryTime: currentPB
                };
            }
            return entry;
        });
    },

    processRaceResults: (tier: CompetitionTier, distance: number, startTime: number, stroke: Stroke, contextClub?: Club | null): RaceResult[] => {
        const db = getDB();
        const raceKey = storageService.getRaceKey(tier, distance, startTime, contextClub);

        if (db.raceResults[raceKey]) {
            return db.raceResults[raceKey];
        }

        const entries = db.raceEntries[raceKey] || [];
        if (entries.length === 0) return [];

        const results: RaceResult[] = entries.map(entry => {
            let raceTime = entry.entryTime;
            let clubName = entry.club;
            const player = db.players[entry.playerId];

            if (player) {
                raceTime = calculateTime(player.stats, distance, stroke);
                if (player.clubId && db.clubs[player.clubId]) {
                    clubName = db.clubs[player.clubId].name;
                } else {
                    clubName = "Sin Club";
                }
            } else {
                if (Math.abs(raceTime - DEFAULT_TIME) < 1) {
                    raceTime = (distance === 50 ? 30 : 65) + (Math.random() * 10 - 5);
                } else {
                    raceTime = entry.entryTime + (Math.random() * 1.5 - 0.75);
                }
            }

            return {
                rank: 0,
                swimmerName: entry.name,
                club: clubName,
                time: raceTime,
                isPlayer: !!player,
                playerId: entry.playerId
            };
        });

        results.sort((a, b) => a.time - b.time);
        results.forEach((r, i) => r.rank = i + 1);

        results.forEach(result => {
            if (result.playerId && db.players[result.playerId]) {
                const p = db.players[result.playerId];
                const pbKey = `${stroke}-${distance}`;
                const currentPB = p.personalBests[pbKey] || DEFAULT_TIME;

                // Update PB
                if (result.time < currentPB) {
                    p.personalBests[pbKey] = result.time;
                }

                // Check for Records - ALLOW IN ALL TIERS EXCEPT TRIANGULAR
                if (tier !== CompetitionTier.Triangular && p.clubId && db.clubs[p.clubId]) {
                    const club = db.clubs[p.clubId];
                    const countryId = club.location.countryId;
                    const continentKey = getContinentKey(countryId);

                    let recordBrokenType: 'World' | 'European' | 'National' | undefined;

                    // Note: No money or prestige is awarded for record breaking itself, only for race rank.

                    // Check World Record
                    const worldKey = `WORLD-${distance}`;
                    const currentWR = db.records[worldKey];
                    if (!currentWR || result.time < currentWR.time) {
                        db.records[worldKey] = {
                            time: result.time,
                            holderId: p.id,
                            holderName: p.name,
                            clubName: club.name,
                            clubCountry: countryId,
                            date: Date.now()
                        };
                        recordBrokenType = 'World';
                    }

                    // Check Continental Record (Update stats but don't stack bonus if WR broken)
                    const contKey = `${continentKey}-${distance}`;
                    const currentCR = db.records[contKey];
                    if (!currentCR || result.time < currentCR.time) {
                        db.records[contKey] = {
                            time: result.time,
                            holderId: p.id,
                            holderName: p.name,
                            clubName: club.name,
                            clubCountry: countryId,
                            date: Date.now()
                        };
                        if (!recordBrokenType) recordBrokenType = 'European';
                    }

                    // Check National Record
                    const natKey = `${countryId}-${distance}`;
                    const currentNR = db.records[natKey];
                    if (!currentNR || result.time < currentNR.time) {
                        db.records[natKey] = {
                            time: result.time,
                            holderId: p.id,
                            holderName: p.name,
                            clubName: club.name,
                            clubCountry: countryId,
                            date: Date.now()
                        };
                        if (!recordBrokenType) recordBrokenType = 'National';
                    }

                    if (recordBrokenType) {
                        result.recordBroken = recordBrokenType;
                        // NO PRESTIGE/MONEY REWARD FOR RECORDS HERE
                    }
                }

                // Generate a zone name for history
                let zoneLabel = "";
                if (contextClub && tier === CompetitionTier.Provincial) zoneLabel = contextClub.location.zoneId || "";
                if (contextClub && tier === CompetitionTier.Regional) zoneLabel = contextClub.location.regionId || "";
                if (contextClub && tier === CompetitionTier.National) zoneLabel = contextClub.location.countryId || "";
                if (contextClub && tier === CompetitionTier.European) zoneLabel = getContinentKey(contextClub.location.countryId);

                // Add to History
                p.history.unshift({
                    id: raceKey,
                    tier,
                    stroke,
                    distance,
                    time: result.time,
                    rank: result.rank,
                    date: 1, 
                    realTimeDate: Date.now(),
                    zoneName: zoneLabel
                });

                // Apply Rewards ONLY if NOT Triangular
                if (tier !== CompetitionTier.Triangular) {
                    const xpGain = Math.max(10, 110 - (result.rank * 10)) * (
                        tier === CompetitionTier.World ? 5 :
                        tier === CompetitionTier.European ? 3 : 
                        1
                    );

                    p.xp += xpGain;
                    p.level = Math.floor(p.xp / 100) + 1;

                    if (result.rank === 1) p.medals.gold++;
                    if (result.rank === 2) p.medals.silver++;
                    if (result.rank === 3) p.medals.bronze++;

                    // Club Prestige Rewards (Top 3)
                    if (result.rank <= 3 && p.clubId && db.clubs[p.clubId]) {
                        const prestigeRewards = PRESTIGE_REWARDS[tier];
                        if (prestigeRewards) {
                            db.clubs[p.clubId].prestige += prestigeRewards[result.rank - 1];
                        }
                    }
                }
            }
        });

        db.raceResults[raceKey] = results;
        saveDB(db);

        return results;
    },

    getOfficialResults: (tier: CompetitionTier, startTime: number, contextClub?: Club | null): { distance: number, results: RaceResult[] }[] => {
        const db = getDB();
        const distances = [50, 100, 200];
        const output: { distance: number, results: RaceResult[] }[] = [];

        distances.forEach(dist => {
            const raceKey = storageService.getRaceKey(tier, dist, startTime, contextClub);
            if (db.raceResults[raceKey]) {
                output.push({ distance: dist, results: db.raceResults[raceKey] });
            }
        });

        return output;
    },

    getRecords: () => {
        const db = getDB();
        return db.records;
    }
};

import React, { useState, useEffect } from 'react';
import { COMPETITION_CONFIG, DISTANCES, MINIMUM_TIMES, DEFAULT_TIME, CONTINENTS } from '../constants';
import { CompetitionTier, Stroke, RaceResult, PastRace, Swimmer, StartListEntry } from '../types';
import { formatTime, organizeHeats } from '../services/gameLogic';
import { storageService } from '../services/storageService';

interface CompetitionProps {
    swimmer: Swimmer;
    day: number;
    onRaceComplete: (result: PastRace) => void;
    onUpdateSwimmer: () => void;
    onViewPlayer?: (playerId: string) => void;
}

export const Competition: React.FC<CompetitionProps> = ({ swimmer, day, onRaceComplete, onUpdateSwimmer, onViewPlayer }) => {
    const [selectedTier, setSelectedTier] = useState<CompetitionTier | null>(null);
    const [selectedDist, setSelectedDist] = useState<number>(100);
    const selectedStroke = Stroke.Freestyle;

    const [viewMode, setViewMode] = useState<'menu' | 'startList' | 'racing' | 'officialDocs'>('menu');
    const [raceResults, setRaceResults] = useState<RaceResult[] | null>(null);
    const [officialDocs, setOfficialDocs] = useState<{ distance: number, results: RaceResult[] }[]>([]);

    const [now, setNow] = useState(Date.now());
    const [entries, setEntries] = useState<StartListEntry[]>([]);

    useEffect(() => {
        const interval = setInterval(() => setNow(Date.now()), 1000);
        return () => clearInterval(interval);
    }, []);

    const getNextRaceTime = (tierId: CompetitionTier, interval: number) => {
        return Math.ceil(now / interval) * interval;
    };

    const getPrevRaceTime = (tierId: CompetitionTier, interval: number) => {
        return Math.floor(now / interval) * interval;
    };

    const getTimeUntil = (targetTime: number) => {
        const diff = targetTime - now;
        if (diff < 0) return "En curso";
        const hours = Math.floor(diff / 3600000);
        const minutes = Math.floor((diff % 3600000) / 60000);
        const seconds = Math.floor((diff % 60000) / 1000);
        return `${hours}h ${minutes}m ${seconds}s`;
    };

    const hasQualifyingTime = (tier: CompetitionTier, dist: number): boolean => {
        const tierMins = MINIMUM_TIMES[tier];
        if (tierMins[dist] === 999) return true;
        const pb = swimmer.personalBests[`${Stroke.Freestyle}-${dist}`] || DEFAULT_TIME;
        return pb <= tierMins[dist];
    };

    // Logic to determine if user can see/enter this competition based on geography
    const canEnterTier = (tier: CompetitionTier) => {
        if (tier === CompetitionTier.Triangular) return true;
        if (tier === CompetitionTier.World) return true;
        if (tier === CompetitionTier.European) return true; // Everyone can enter their continent's cup

        const clubs = storageService.getClubs();
        const myClub = clubs.find(c => c.id === swimmer.clubId);

        if (!myClub) return false; // Must be in a club for official leagues

        if (tier === CompetitionTier.InternationalClub) {
            return myClub.location.countryId !== 'ES';
        }

        // For Provincial, Regional, National, you must be in Spain (as per current logic structure)
        // If club is Spanish, they can do these.
        if (myClub.location.countryId === 'ES') {
            return true;
        }

        // Non-Spanish clubs skip Provincial/Regional/National and do International Cup instead
        return false;
    };

    const getDisplayTitle = (tier: CompetitionTier) => {
        const clubs = storageService.getClubs();
        const myClub = clubs.find(c => c.id === swimmer.clubId);

        if (!myClub) return tier; // Fallback

        if (tier === CompetitionTier.Provincial) return `${tier} (${myClub.location.zoneId || 'General'})`;
        if (tier === CompetitionTier.Regional) return `${tier} (${myClub.location.regionId || 'General'})`;
        if (tier === CompetitionTier.National) return `${tier} (${myClub.location.countryId})`;
        if (tier === CompetitionTier.European) {
             const cid = myClub.location.countryId;
             if (CONTINENTS.ASIA.includes(cid)) return "Copa Asiática";
             if (CONTINENTS.AMERICA_OCEANIA.includes(cid)) return "Copa Pacífico-América";
             return "Campeonato de Europa"; // Default for Europe or others
        }

        return tier;
    };

    const getRegistrationStatus = (tier: CompetitionTier, dist: number) => {
        const nextStart = getNextRaceTime(tier, COMPETITION_CONFIG.find(c => c.id === tier)!.interval);
        const clubs = storageService.getClubs();
        const myClub = clubs.find(c => c.id === swimmer.clubId);

        const raceEntries = storageService.getRaceEntries(tier, dist, nextStart, myClub);
        return raceEntries.some(e => e.playerId === swimmer.id);
    };

    const getRegisteredCount = (tier: CompetitionTier) => {
        const nextStart = getNextRaceTime(tier, COMPETITION_CONFIG.find(c => c.id === tier)!.interval);
        const clubs = storageService.getClubs();
        const myClub = clubs.find(c => c.id === swimmer.clubId);

        let count = 0;
        DISTANCES.forEach(dist => {
            const raceEntries = storageService.getRaceEntries(tier, dist, nextStart, myClub);
            if (raceEntries.some(e => e.playerId === swimmer.id)) {
                count++;
            }
        });
        return count;
    };

    const handleRegister = (tier: CompetitionTier, dist: number, interval: number) => {
        const currentCount = getRegisteredCount(tier);
        if (currentCount >= 2) {
            alert("Solo puedes inscribirte en un máximo de 2 pruebas por competición.");
            return;
        }

        const myEntryTime = swimmer.personalBests[`${selectedStroke}-${dist}`] || DEFAULT_TIME;
        const nextStart = getNextRaceTime(tier, interval);
        const clubs = storageService.getClubs();
        const myClub = clubs.find(c => c.id === swimmer.clubId);

        const myEntry: StartListEntry = {
            playerId: swimmer.id,
            name: swimmer.name,
            club: myClub ? myClub.name : "Sin Club",
            entryTime: myEntryTime, 
            isPlayer: true
        };

        storageService.registerForRace(tier, dist, nextStart, myEntry);
        onUpdateSwimmer();
    };

    const handleUnregister = (tier: CompetitionTier, dist: number, interval: number) => {
        const nextStart = getNextRaceTime(tier, interval);
        storageService.unregisterFromRace(tier, dist, nextStart, swimmer.id);
        onUpdateSwimmer();
    };

    const openStartList = (tier: CompetitionTier, dist: number) => {
        setSelectedTier(tier);
        setSelectedDist(dist);
        const nextStart = getNextRaceTime(tier, COMPETITION_CONFIG.find(c => c.id === tier)!.interval);

        const clubs = storageService.getClubs();
        const myClub = clubs.find(c => c.id === swimmer.clubId);

        const raceEntries = storageService.getRaceEntries(tier, dist, nextStart, myClub);
        setEntries(raceEntries);
        setViewMode('startList');
    };

    const handleProcessRace = () => {
        if (!selectedTier) return;

        const interval = COMPETITION_CONFIG.find(c => c.id === selectedTier)!.interval;
        const raceTime = getNextRaceTime(selectedTier, interval);

        const clubs = storageService.getClubs();
        const myClub = clubs.find(c => c.id === swimmer.clubId);

        // Pass myClub context so backend knows which zone to process
        const results = storageService.processRaceResults(selectedTier, selectedDist, raceTime, selectedStroke, myClub);

        setRaceResults(results);
        setViewMode('racing');

        const myResult = results.find(r => r.playerId === swimmer.id);
        if (myResult) {
            onRaceComplete({
                id: Date.now().toString(),
                tier: selectedTier,
                stroke: selectedStroke,
                distance: selectedDist,
                time: myResult.time,
                rank: myResult.rank,
                date: day,
                realTimeDate: Date.now(),
                zoneName: myResult.club // Simplified
            });
        }
    };

    const handleViewOfficialDocs = (tier: CompetitionTier) => {
        const interval = COMPETITION_CONFIG.find(c => c.id === tier)!.interval;
        let targetTime = getNextRaceTime(tier, interval);

        if (targetTime - now > 5 * 60 * 1000) {
            targetTime = getPrevRaceTime(tier, interval);
        }

        const clubs = storageService.getClubs();
        const myClub = clubs.find(c => c.id === swimmer.clubId);

        // Process all distances for the specific zone of the user
        [50, 100, 200].forEach(d => storageService.processRaceResults(tier, d, targetTime, Stroke.Freestyle, myClub));

        const docs = storageService.getOfficialResults(tier, targetTime, myClub);
        setOfficialDocs(docs);
        setSelectedTier(tier);
        setViewMode('officialDocs');
    };

    const renderOfficialDocs = () => {
        if (!selectedTier) return null;

        return (
            <div className="glass-panel rounded-2xl shadow-2xl overflow-hidden animate-fade-in max-w-5xl mx-auto border border-white/40">
                <div className="bg-slate-900 p-8 text-white flex justify-between items-center print:hidden relative overflow-hidden">
                    <div className="absolute top-0 right-0 w-64 h-full bg-gradient-to-l from-cyan-900 to-transparent opacity-50"></div>
                    <div className="relative z-10">
                        <div className="uppercase tracking-widest text-xs font-bold text-cyan-400 mb-2">Federación de Natación</div>
                        <h2 className="text-4xl font-black sport-font uppercase">Acta Oficial</h2>
                        <p className="opacity-70 mt-1 font-mono text-sm">{getDisplayTitle(selectedTier)} • {new Date().toLocaleDateString()}</p>
                    </div>
                    <button onClick={() => setViewMode('menu')} className="bg-white/10 backdrop-blur-md text-white px-6 py-2 rounded-lg font-bold hover:bg-white/20 border border-white/20">Cerrar</button>
                </div>

                <div className="p-8 bg-white/90 min-h-[600px] overflow-y-auto">
                    {officialDocs.length === 0 ? (
                        <div className="text-center text-slate-500 py-12">
                            Aún no hay resultados oficiales procesados para este ciclo en tu zona.
                        </div>
                    ) : (
                        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                            {officialDocs.map(doc => (
                                <div key={doc.distance} className="border border-slate-200 rounded-xl p-6 shadow-sm bg-white">
                                    <h3 className="text-xl font-bold border-b pb-4 mb-4 flex justify-between">
                                        <span className="sport-font text-slate-800">{doc.distance}m Libres</span>
                                        <span className="text-xs font-bold bg-slate-100 px-2 py-1 rounded text-slate-500">{doc.results.length} Participantes</span>
                                    </h3>
                                    <table className="w-full text-sm">
                                        <thead>
                                            <tr className="text-slate-400 text-left text-[10px] uppercase font-bold tracking-wider">
                                                <th className="pb-2 w-10">Pos</th>
                                                <th className="pb-2">Nadador</th>
                                                <th className="pb-2 text-right">Tiempo</th>
                                            </tr>
                                        </thead>
                                        <tbody>
                                            {doc.results.map((r) => (
                                                <tr key={r.rank} className={`border-b last:border-0 ${r.playerId === swimmer.id ? 'bg-cyan-50' : ''}`}>
                                                    <td className="py-2 font-mono font-bold text-slate-400">{r.rank}</td>
                                                    <td className="py-2">
                                                        <button 
                                                            onClick={() => r.playerId && onViewPlayer && onViewPlayer(r.playerId)}
                                                            className="font-bold text-slate-700 hover:text-cyan-600 text-left"
                                                        >
                                                            {r.swimmerName}
                                                        </button>
                                                        <div className="text-[10px] text-slate-500 font-bold uppercase">{r.club}</div>
                                                    </td>
                                                    <td className="py-2 text-right font-mono font-bold text-slate-800">{formatTime(r.time)}</td>
                                                </tr>
                                            ))}
                                        </tbody>
                                    </table>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>
        );
    }

    const renderStartList = () => {
        if (!selectedTier) return null;
        const tierConfig = COMPETITION_CONFIG.find(c => c.id === selectedTier)!;
        const nextStart = getNextRaceTime(selectedTier, tierConfig.interval);

        const seededEntries = organizeHeats(entries);
        const heats: Record<number, typeof seededEntries> = {};
        seededEntries.forEach(e => {
            if (!heats[e.heat]) heats[e.heat] = [];
            heats[e.heat].push(e);
        });

        const raceHasStarted = now >= nextStart;

        return (
            <div className="glass-panel rounded-2xl shadow-xl overflow-hidden animate-fade-in max-w-4xl mx-auto border border-white/50">
                <div className="bg-slate-800 p-6 text-white flex justify-between items-center relative overflow-hidden">
                    <div className="relative z-10">
                        <h2 className="text-3xl font-black sport-font uppercase">Listas de Salida</h2>
                        <p className="opacity-80 font-mono text-sm text-cyan-300">{selectedDist}m {selectedStroke} • {getDisplayTitle(selectedTier)}</p>
                    </div>
                    <button onClick={() => setViewMode('menu')} className="text-sm bg-white/10 px-4 py-2 rounded hover:bg-white/20 backdrop-blur-md relative z-10">Cerrar</button>
                </div>

                <div className="p-6 overflow-y-auto max-h-[600px] space-y-8 bg-slate-50/50">
                    {Object.keys(heats).length === 0 && (
                        <div className="text-center text-slate-500 py-8 font-medium">
                            No hay nadadores registrados aún.
                        </div>
                    )}
                    {Object.keys(heats).map(heatNum => {
                        const hEntries = heats[parseInt(heatNum)].sort((a,b) => a.lane - b.lane);
                        return (
                            <div key={heatNum} className="bg-white rounded-xl overflow-hidden shadow-sm border border-slate-200">
                                <div className="bg-slate-100 px-4 py-2 font-bold text-slate-600 border-b text-xs uppercase tracking-widest flex justify-between">
                                    <span>Serie {heatNum}</span>
                                    <span>{hEntries.length} Nadadores</span>
                                </div>
                                <table className="w-full text-left text-sm">
                                    <thead>
                                        <tr className="bg-slate-50 text-slate-400 text-[10px] uppercase font-bold">
                                            <th className="px-4 py-2 w-16 text-center">Calle</th>
                                            <th className="px-4 py-2">Nadador</th>
                                            <th className="px-4 py-2 hidden sm:table-cell">Club</th>
                                            <th className="px-4 py-2 text-right">Marca</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {hEntries.map((row) => (
                                            <tr key={row.lane} className={`border-b last:border-0 ${row.entry.isPlayer ? 'bg-cyan-50' : ''}`}>
                                                <td className="px-4 py-3 font-mono font-bold text-center bg-slate-50/50 border-r text-slate-600">{row.lane}</td>
                                                <td className="px-4 py-3">
                                                    <button 
                                                        onClick={() => row.entry.playerId && onViewPlayer && onViewPlayer(row.entry.playerId)}
                                                        className={`font-bold hover:underline text-left ${row.entry.isPlayer ? 'text-cyan-700' : 'text-slate-700 hover:text-cyan-600'}`}
                                                    >
                                                        {row.entry.name}
                                                    </button>
                                                    <div className="sm:hidden text-xs text-slate-500">{row.entry.club}</div>
                                                </td>
                                                <td className="px-4 py-3 text-slate-500 text-xs uppercase font-bold hidden sm:table-cell">{row.entry.club}</td>
                                                <td className="px-4 py-3 text-right font-mono text-slate-600">{formatTime(row.entry.entryTime)}</td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                        );
                    })}
                </div>
                <div className="p-4 bg-white border-t flex justify-center">
                    {raceHasStarted ? (
                        <button 
                            onClick={handleProcessRace}
                            className="bg-green-600 hover:bg-green-700 text-white font-bold py-4 px-12 rounded-lg shadow-lg animate-pulse uppercase tracking-widest text-sm"
                        >
                            ¡Al Agua! 🔫
                        </button>
                    ) : (
                         <div className="flex flex-col items-center">
                             <div className="text-slate-400 font-bold text-[10px] mb-1 uppercase tracking-widest">Cámara de Llamadas abre en</div>
                             <div className="mono-font text-3xl font-bold text-blue-600">
                                {getTimeUntil(nextStart)}
                             </div>
                         </div>
                    )}
                </div>
            </div>
        );
    };

    if (viewMode === 'officialDocs') return renderOfficialDocs();
    if (viewMode === 'startList') return renderStartList();

    if (viewMode === 'racing' && raceResults) {
        return (
             <div className="max-w-3xl mx-auto glass-panel rounded-2xl shadow-2xl overflow-hidden animate-fade-in border border-white/50">
                <div className="bg-gradient-to-r from-blue-600 to-cyan-500 p-6 text-white text-center shadow-lg relative">
                    <h2 className="text-4xl font-black sport-font mb-2 uppercase italic">Resultados</h2>
                    <p className="opacity-90 font-mono text-cyan-100">{selectedDist}m {selectedStroke} • {getDisplayTitle(selectedTier)}</p>
                </div>
                <div className="p-6 bg-white/80">
                    <div className="overflow-x-auto max-h-[500px]">
                        <table className="w-full text-left">
                            <thead className="sticky top-0 bg-white shadow-sm z-10">
                                <tr className="text-xs text-slate-500 border-b uppercase font-bold tracking-wider">
                                    <th className="py-3 pl-4">Pos</th>
                                    <th className="py-3">Nadador</th>
                                    <th className="py-3 text-right pr-4">Tiempo</th>
                                </tr>
                            </thead>
                            <tbody>
                                {raceResults.map((result) => (
                                    <tr key={result.rank} className={`border-b last:border-0 ${result.isPlayer ? 'bg-cyan-50' : ''}`}>
                                        <td className="py-3 pl-4">
                                            <span className={`inline-flex items-center justify-center w-8 h-8 rounded text-sm font-bold shadow-sm ${result.rank === 1 ? 'bg-yellow-400 text-yellow-900' : result.rank === 2 ? 'bg-slate-300 text-slate-800' : result.rank === 3 ? 'bg-orange-300 text-orange-900' : 'bg-slate-100 text-slate-500'}`}>
                                                {result.rank}
                                            </span>
                                        </td>
                                        <td className="py-3">
                                            <button
                                                onClick={() => result.playerId && onViewPlayer && onViewPlayer(result.playerId)} 
                                                className={`font-bold hover:underline text-left block ${result.isPlayer ? 'text-cyan-800' : 'text-slate-700 hover:text-cyan-600'}`}
                                            >
                                                {result.swimmerName}
                                            </button>
                                            <span className="text-[10px] text-slate-400 font-bold uppercase">{result.club}</span>
                                        </td>
                                        <td className="py-3 text-right font-mono font-bold text-slate-800 pr-4 text-lg">{formatTime(result.time)}</td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                    <button onClick={() => { setRaceResults(null); setViewMode('menu'); setSelectedTier(null); }} className="w-full mt-6 py-4 bg-slate-800 text-white rounded-xl font-bold hover:bg-slate-900 transition-colors uppercase tracking-widest text-xs">Volver al menú</button>
                </div>
            </div>
        );
    }

    return (
        <div className="space-y-8 animate-fade-in">
             <div className="max-w-4xl mx-auto space-y-4">
                {COMPETITION_CONFIG.map((tier) => {
                    const nextRaceStart = getNextRaceTime(tier.id, tier.interval);
                    const registeredCount = getRegisteredCount(tier.id);
                    const isAccessible = canEnterTier(tier.id);
                    const displayTitle = getDisplayTitle(tier.id);

                    if (!isAccessible) return null; // Hide unavailable tiers

                    return (
                        <div key={tier.id} className="w-full text-left p-6 rounded-2xl border relative overflow-hidden bg-white shadow-lg hover:shadow-xl transition-shadow border-slate-100">
                            {/* Decorative accent */}
                            <div className="absolute left-0 top-0 bottom-0 w-2 bg-gradient-to-b from-blue-500 to-cyan-400"></div>

                            <div className="flex flex-col md:flex-row justify-between items-start md:items-center relative z-10 gap-4 pl-4">
                                <div>
                                    <h4 className="font-black sport-font text-2xl text-slate-800 uppercase italic">{displayTitle}</h4>
                                    <div className="text-sm text-slate-500 flex flex-col md:flex-row gap-2 md:gap-4 mt-1">
                                        <span className="font-mono text-cyan-600 font-bold bg-cyan-50 px-2 py-0.5 rounded">Próxima: {getTimeUntil(nextRaceStart)}</span>
                                    </div>
                                    <div className="mt-2 text-xs font-bold text-slate-400 uppercase tracking-widest">
                                        Slots: <span className={registeredCount >= 2 ? 'text-red-500' : 'text-slate-600'}>{registeredCount}/2</span>
                                    </div>
                                    <div className="mt-2">
                                        <button 
                                            onClick={() => handleViewOfficialDocs(tier.id)}
                                            className="text-xs font-bold text-slate-400 hover:text-cyan-600 underline"
                                        >
                                            📄 Ver Resultados Anteriores
                                        </button>
                                    </div>
                                </div>

                                <div className="flex gap-2">
                                    {DISTANCES.map(dist => {
                                        const isUnlocked = hasQualifyingTime(tier.id, dist);
                                        const isRegistered = getRegistrationStatus(tier.id, dist);
                                        const raceHasStarted = isRegistered && now >= nextRaceStart;

                                        return (
                                            <div key={dist} className="flex flex-col items-center">
                                                <span className="text-[10px] font-bold text-slate-400 mb-1">{dist}m</span>
                                                {isUnlocked ? (
                                                     raceHasStarted ? (
                                                        <button onClick={() => openStartList(tier.id, dist)} className="bg-green-500 text-white px-4 py-3 rounded-lg font-bold text-xs animate-pulse shadow-lg hover:bg-green-600 uppercase tracking-wide">
                                                            COMPETIR
                                                        </button>
                                                    ) : isRegistered ? (
                                                        <div className="flex gap-1">
                                                            <button onClick={() => openStartList(tier.id, dist)} className="bg-cyan-50 text-cyan-700 border border-cyan-200 px-3 py-2 rounded-lg font-bold text-xs hover:bg-cyan-100 transition-colors">
                                                                Listas
                                                            </button>
                                                            <button 
                                                                onClick={() => handleUnregister(tier.id, dist, tier.interval)}
                                                                className="bg-red-50 text-red-500 border border-red-100 px-2 py-2 rounded-lg font-bold text-xs hover:bg-red-100"
                                                                title="Cancelar Inscripción"
                                                            >
                                                                ✕
                                                            </button>
                                                        </div>
                                                    ) : (
                                                        <button 
                                                            onClick={() => handleRegister(tier.id, dist, tier.interval)} 
                                                            className={`px-4 py-2 rounded-lg font-bold text-xs text-white uppercase tracking-wide shadow-sm transition-all ${registeredCount >= 2 ? 'bg-slate-300 cursor-not-allowed' : 'bg-slate-800 hover:bg-slate-700 hover:scale-105'}`}
                                                            disabled={registeredCount >= 2}
                                                        >
                                                            Inscribirse
                                                        </button>
                                                    )
                                                ) : (
                                                    <div className="bg-gray-50 text-gray-300 px-4 py-2 rounded-lg font-bold text-[10px] border border-gray-100 text-center w-[100px] select-none">
                                                        🔒 BLOQUEADO<br/>
                                                        <span className="opacity-75 mono-font">{formatTime(MINIMUM_TIMES[tier.id][dist])}</span>
                                                    </div>
                                                )}
                                            </div>
                                        );
                                    })}
                                </div>
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
    );
};

import React from 'react';
import { CompetitionTier, Swimmer } from '../types';
import { formatTime } from '../services/gameLogic';
import { storageService } from '../services/storageService';

interface ProfileProps {
    swimmer: Swimmer;
    onLogout: () => void;
}

export const Profile: React.FC<ProfileProps> = ({ swimmer, onLogout }) => {
    // Fetch club name freshly
    const club = swimmer.clubId ? storageService.getClub(swimmer.clubId) : null;

    // Filter for medals - Exclude Triangulars
    const medalHistory = swimmer.history.filter(race => race.rank <= 3 && race.tier !== CompetitionTier.Triangular);

    // Sort Personal Bests by distance (extracted from key "Stroke-Distance")
    const sortedPBs = Object.entries(swimmer.personalBests).sort((a, b) => {
        const distA = parseInt(a[0].split('-')[1]);
        const distB = parseInt(b[0].split('-')[1]);
        return distA - distB;
    });

    return (
        <div className="space-y-8 animate-fade-in">
            <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100 flex justify-between items-center">
                <div className="flex items-center gap-4">
                    <div className="w-16 h-16 bg-gradient-to-br from-blue-400 to-blue-600 rounded-full flex items-center justify-center text-white text-2xl font-bold shadow-lg">
                        {swimmer.name.charAt(0)}
                    </div>
                    <div>
                        <h2 className="text-2xl font-bold text-slate-800">{swimmer.name}</h2>
                        <p className="text-slate-500">{club ? club.name : 'Agente Libre'}</p>
                    </div>
                </div>
                <button onClick={onLogout} className="text-red-500 hover:text-red-700 font-bold text-sm">
                    Cerrar Sesión
                </button>
            </div>

            {/* Stats Summary Row: Medals */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="bg-gradient-to-br from-yellow-50 to-yellow-100 p-6 rounded-2xl border border-yellow-200 flex items-center gap-4">
                    <div className="text-4xl">🥇</div>
                    <div>
                        <div className="text-3xl font-black text-yellow-700">{swimmer.medals.gold}</div>
                        <div className="text-xs font-bold text-yellow-600 uppercase tracking-wider">Oros</div>
                    </div>
                </div>
                <div className="bg-gradient-to-br from-slate-50 to-slate-100 p-6 rounded-2xl border border-slate-200 flex items-center gap-4">
                    <div className="text-4xl">🥈</div>
                    <div>
                        <div className="text-3xl font-black text-slate-600">{swimmer.medals.silver}</div>
                        <div className="text-xs font-bold text-slate-500 uppercase tracking-wider">Platas</div>
                    </div>
                </div>
                <div className="bg-gradient-to-br from-orange-50 to-orange-100 p-6 rounded-2xl border border-orange-200 flex items-center gap-4">
                    <div className="text-4xl">🥉</div>
                    <div>
                        <div className="text-3xl font-black text-orange-700">{swimmer.medals.bronze}</div>
                        <div className="text-xs font-bold text-orange-600 uppercase tracking-wider">Bronces</div>
                    </div>
                </div>
            </div>

            {/* Detailed Medal List */}
            {medalHistory.length > 0 && (
                <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-8">
                    <h2 className="text-2xl font-bold mb-6 text-slate-800">Vitrina de Trofeos</h2>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 max-h-96 overflow-y-auto pr-2">
                        {medalHistory.map((race) => (
                            <div key={race.id} className={`p-4 rounded-xl border flex items-center gap-4 ${
                                race.rank === 1 ? 'bg-yellow-50 border-yellow-200' :
                                race.rank === 2 ? 'bg-slate-50 border-slate-200' :
                                'bg-orange-50 border-orange-200'
                            }`}>
                                <div className="text-3xl filter drop-shadow-sm">
                                    {race.rank === 1 ? '🥇' : race.rank === 2 ? '🥈' : '🥉'}
                                </div>
                                <div>
                                    <div className="font-bold text-slate-800 leading-tight">{race.tier}</div>
                                    <div className="text-sm font-semibold text-slate-600">
                                        {race.distance}m {race.stroke}
                                    </div>
                                    <div className="text-xs text-slate-500 mt-1 flex gap-2">
                                        <span>📅 {new Date(race.realTimeDate).toLocaleDateString()}</span>
                                        <span className="font-mono font-bold text-blue-600">⏱ {formatTime(race.time)}</span>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-8">
                <h2 className="text-2xl font-bold mb-6 text-slate-800">Mejores Marcas Personales</h2>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                    {sortedPBs.length === 0 && (
                        <p className="text-slate-400">Sin tiempos registrados.</p>
                    )}
                    {sortedPBs.map(([key, time]) => {
                        const [stroke, dist] = key.split('-');
                        return (
                            <div key={key} className="flex justify-between items-center p-4 bg-slate-50 rounded-xl border border-slate-100">
                                <span className="font-bold text-slate-700 capitalize">{dist}m {stroke}</span>
                                <span className="font-mono text-blue-600 font-bold">{formatTime(time as number)}</span>
                            </div>
                        );
                    })}
                </div>
            </div>

            <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-8">
                <h2 className="text-2xl font-bold mb-6 text-slate-800">Historial Reciente</h2>
                <div className="space-y-4 max-h-96 overflow-y-auto pr-2">
                    {swimmer.history.map((race) => (
                        <div key={race.id} className="border-l-4 border-blue-500 bg-slate-50 pl-4 py-3 rounded-r-lg">
                            <div className="flex justify-between">
                                <span className="font-bold text-slate-800">{race.tier}</span>
                                <span className="text-sm text-slate-500">{new Date(race.realTimeDate).toLocaleDateString()}</span>
                            </div>
                            <div className="text-sm text-slate-600 mt-1">
                                {race.distance}m {race.stroke} | <span className="font-mono font-bold">{formatTime(race.time)}</span> | Posición: {race.rank}
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { Attribute, Club, Swimmer } from '../types';
import { CLUB_COLORS, CLUB_ICONS, SPANISH_GEOGRAPHY, INTERNATIONAL_COUNTRIES, COUNTRY_FLAGS } from '../constants';
import { storageService } from '../services/storageService';

interface ClubManagerProps {
    swimmer: Swimmer;
    availableClubs: Club[];
    onUpdateSwimmer: (swimmer: Swimmer) => void;
    onViewPlayer?: (playerId: string) => void;
}

export const ClubManager: React.FC<ClubManagerProps> = ({ swimmer, availableClubs, onUpdateSwimmer, onViewPlayer }) => {
    const [view, setView] = useState<'current' | 'list' | 'create' | 'edit'>('current');
    const [members, setMembers] = useState<Swimmer[]>([]);

    // Form State
    const [formName, setFormName] = useState('');
    const [selectedIcon, setSelectedIcon] = useState(CLUB_ICONS[0]);
    const [selectedColorIndex, setSelectedColorIndex] = useState(0);

    // Geography Form State
    const [selectedCountry, setSelectedCountry] = useState('ES');
    const [selectedRegion, setSelectedRegion] = useState('');
    const [selectedZone, setSelectedZone] = useState('');
    const [selectedCity, setSelectedCity] = useState('');

    const currentClub = availableClubs.find(c => c.id === swimmer.clubId);

    // Initialize edit form
    useEffect(() => {
        if (view === 'edit' && currentClub) {
            setFormName(currentClub.name);
            setSelectedIcon(currentClub.logo.icon);
            const colorIdx = CLUB_COLORS.findIndex(c => c.bg === currentClub.logo.bgColor);
            setSelectedColorIndex(colorIdx >= 0 ? colorIdx : 0);

            // Geography init
            setSelectedCountry(currentClub.location.countryId);
            setSelectedRegion(currentClub.location.regionId || '');
            setSelectedZone(currentClub.location.zoneId || '');
            setSelectedCity(currentClub.location.cityName);
        } else if (view === 'create') {
            // Reset defaults
            setFormName('');
            setSelectedCountry('ES');
            setSelectedRegion('');
            setSelectedZone('');
            setSelectedCity('');
        }
    }, [view, currentClub]);

    // Load members
    useEffect(() => {
        if (view === 'current' && currentClub) {
            setMembers(storageService.getClubMembers(currentClub.id));
        }
    }, [view, currentClub]);

    const handleCreate = (e: React.FormEvent) => {
        e.preventDefault();

        // Validation for Spain
        if (selectedCountry === 'ES' && (!selectedRegion || !selectedZone || !selectedCity)) {
            alert("Debes seleccionar Comunidad, Zona y Ciudad para un club español.");
            return;
        }
        if (selectedCountry !== 'ES' && !selectedCity) {
            alert("Debes escribir una ciudad.");
            return;
        }

        const colorData = CLUB_COLORS[selectedColorIndex];
        const newClub: Club = {
            id: Date.now().toString(),
            name: formName,
            description: `Club fundado por ${swimmer.name}`,
            prestige: 0,
            logo: {
                icon: selectedIcon,
                color: colorData.hex,
                bgColor: colorData.bg
            },
            location: {
                countryId: selectedCountry,
                regionId: selectedRegion || undefined,
                zoneId: selectedZone || undefined,
                cityName: selectedCity
            },
            ownerId: swimmer.id
        };

        storageService.saveClub(newClub);

        const updatedSwimmer = { ...swimmer, clubId: newClub.id };
        storageService.savePlayer(updatedSwimmer);
        onUpdateSwimmer(updatedSwimmer);

        setView('current');
    };

    const handleEdit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!currentClub) return;

        const colorData = CLUB_COLORS[selectedColorIndex];
        const updatedClub: Club = {
            ...currentClub,
            name: formName,
            logo: {
                icon: selectedIcon,
                color: colorData.hex,
                bgColor: colorData.bg
            }
            // Cannot edit location after creation (simpler logic to avoid zone hopping exploits)
        };

        storageService.saveClub(updatedClub);
        onUpdateSwimmer(swimmer); 
        setView('current');
    };

    const handleJoin = (club: Club) => {
        const updatedSwimmer = { ...swimmer, clubId: club.id };
        storageService.savePlayer(updatedSwimmer);
        onUpdateSwimmer(updatedSwimmer);
        setView('current');
    };

    const handleLeave = () => {
        if (!currentClub) return;
        const oldClubId = currentClub.id;

        const updatedSwimmer = { ...swimmer, clubId: null };
        storageService.savePlayer(updatedSwimmer);

        const remainingMembers = storageService.getClubMemberCount(oldClubId);
        if (remainingMembers === 0) {
            storageService.deleteClub(oldClubId);
        }

        onUpdateSwimmer(updatedSwimmer);
        setView('list'); 
    };

    // Helper to get zones based on region
    const getAvailableZones = () => {
        const region = SPANISH_GEOGRAPHY.find(r => r.id === selectedRegion);
        return region ? region.zones : [];
    };

    // Helper to get cities based on zone
    const getAvailableCities = () => {
        const region = SPANISH_GEOGRAPHY.find(r => r.id === selectedRegion);
        if (!region) return [];
        const zone = region.zones.find(z => z.id === selectedZone);
        return zone ? zone.cities : [];
    };

    return (
        <div className="space-y-6 animate-fade-in">
            <div className="text-center mb-8">
                <h2 className="text-3xl font-black sport-font text-slate-800 uppercase italic">Sede del Club</h2>
                <p className="text-sm text-slate-600 font-medium">Únete a otros jugadores reales o crea tu legado.</p>
            </div>

            <div className="flex justify-center gap-4 mb-6">
                <button 
                    onClick={() => setView('current')}
                    className={`px-5 py-2 rounded-full text-sm font-bold transition-all border ${view === 'current' ? 'bg-blue-600 text-white border-blue-600 shadow-md' : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50'}`}
                >
                    Mi Club
                </button>
                <button 
                    onClick={() => setView('list')}
                    className={`px-5 py-2 rounded-full text-sm font-bold transition-all border ${view === 'list' ? 'bg-blue-600 text-white border-blue-600 shadow-md' : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50'}`}
                >
                    Buscar Club
                </button>
                {!swimmer.clubId && (
                    <button 
                        onClick={() => { setFormName(''); setView('create'); }}
                        className={`px-5 py-2 rounded-full text-sm font-bold transition-all border ${view === 'create' ? 'bg-blue-600 text-white border-blue-600 shadow-md' : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50'}`}
                    >
                        Fundar Club
                    </button>
                )}
            </div>

            {view === 'current' && (
                <div className="space-y-8 animate-fade-in">
                    <div className="glass-panel p-8 rounded-3xl shadow-lg border border-white/50 text-center max-w-lg mx-auto relative overflow-hidden">
                         <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-blue-400 via-cyan-400 to-blue-400"></div>
                        {currentClub ? (
                            <>
                                <div className={`relative w-28 h-28 rounded-full mx-auto flex items-center justify-center mb-6 text-5xl shadow-2xl border-4 border-white ${currentClub.logo.bgColor}`}>
                                    <span className={currentClub.logo.color}>{currentClub.logo.icon}</span>
                                    <div className="absolute -bottom-2 -right-2 w-10 h-10 bg-white rounded-full flex items-center justify-center shadow-md border-2 border-slate-100 text-xl" title="País">
                                        {COUNTRY_FLAGS[currentClub.location.countryId] || '🏳️'}
                                    </div>
                                </div>
                                <h3 className="text-3xl font-black sport-font text-slate-800 mb-2 leading-none">{currentClub.name}</h3>
                                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-4">
                                    {currentClub.location.cityName} 
                                    {currentClub.location.countryId === 'ES' && ` • ${currentClub.location.regionId}`}
                                </div>

                                <div className="flex justify-center mb-8">
                                    <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 min-w-[150px]">
                                        <div className="text-xs text-slate-400 uppercase font-bold tracking-wider mb-1">Prestigio</div>
                                        <div className="text-4xl font-black text-slate-800 mono-font">{currentClub.prestige}</div>
                                        <div className="text-[10px] text-slate-400 mt-1 uppercase font-bold">Puntos de Club</div>
                                    </div>
                                </div>

                                <div className="flex gap-4 justify-center">
                                    {swimmer.id === currentClub.ownerId && (
                                        <button 
                                            onClick={() => setView('edit')}
                                            className="px-4 py-2 bg-slate-100 text-slate-700 font-bold rounded-lg hover:bg-slate-200"
                                        >
                                            Editar Logo
                                        </button>
                                    )}
                                    <button 
                                        onClick={handleLeave}
                                        className="px-4 py-2 bg-red-50 text-red-600 font-bold rounded-lg hover:bg-red-100 border border-red-100"
                                    >
                                        Abandonar
                                    </button>
                                </div>
                            </>
                        ) : (
                            <div className="py-12">
                                <p className="text-slate-500 mb-4 font-bold text-lg">No perteneces a ningún club.</p>
                                <button onClick={() => setView('list')} className="bg-blue-600 text-white px-6 py-3 rounded-full font-bold hover:bg-blue-700 shadow-lg">Buscar uno</button>
                            </div>
                        )}
                    </div>

                    {currentClub && members.length > 0 && (
                        <div className="glass-panel rounded-2xl shadow-sm overflow-hidden max-w-2xl mx-auto">
                            <div className="px-6 py-4 bg-slate-50/80 border-b border-slate-200">
                                <h3 className="font-bold text-slate-800 uppercase tracking-wide text-sm">Plantilla del Equipo ({members.length})</h3>
                            </div>
                            <div className="divide-y divide-slate-100">
                                {members.map((member) => (
                                    <div key={member.id} className="p-4 flex items-center justify-between hover:bg-white/50 transition-colors">
                                        <div className="flex items-center gap-4">
                                            <button 
                                                onClick={() => onViewPlayer && onViewPlayer(member.id)}
                                                className="w-12 h-12 bg-gradient-to-br from-blue-400 to-blue-600 rounded-full flex items-center justify-center text-white font-bold shadow-md hover:scale-105 transition-transform border-2 border-white"
                                            >
                                                {member.name.charAt(0)}
                                            </button>
                                            <div>
                                                <button 
                                                    onClick={() => onViewPlayer && onViewPlayer(member.id)}
                                                    className="font-bold text-slate-800 flex items-center gap-2 hover:text-blue-600 text-left"
                                                >
                                                    {member.name}
                                                    {member.id === currentClub.ownerId && <span className="text-[9px] bg-yellow-100 text-yellow-700 px-2 py-0.5 rounded uppercase tracking-wider font-bold">Presidente</span>}
                                                    {member.id === swimmer.id && <span className="text-[9px] bg-blue-100 text-blue-700 px-2 py-0.5 rounded uppercase tracking-wider font-bold">TÚ</span>}
                                                </button>
                                                <div className="text-xs text-slate-500 font-medium">Nivel {member.level}</div>
                                            </div>
                                        </div>
                                        <div className="text-right flex gap-3">
                                            <div>
                                                <div className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">Medallas</div>
                                                <div className="flex gap-2 text-sm bg-slate-50 px-2 py-1 rounded-lg border border-slate-100">
                                                    <span title="Oros">🥇 {member.medals.gold}</span>
                                                    <span title="Platas">🥈 {member.medals.silver}</span>
                                                    <span title="Bronces">🥉 {member.medals.bronze}</span>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}
                </div>
            )}

            {(view === 'create' || view === 'edit') && (
                <form onSubmit={view === 'create' ? handleCreate : handleEdit} className="glass-panel p-8 rounded-3xl shadow-lg max-w-2xl mx-auto">
                    <h3 className="text-2xl font-black sport-font mb-6 text-slate-800">{view === 'create' ? 'Fundar Nuevo Equipo' : 'Editar Equipo'}</h3>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        <div className="space-y-6">
                            <div>
                                <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Nombre del Club</label>
                                <input required value={formName} onChange={e => setFormName(e.target.value)} className="w-full px-4 py-3 border border-slate-300 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 font-bold text-slate-800" placeholder="Ej. Delfines del Sur" />
                            </div>

                            {/* Geography Section - Only editable on Create */}
                            {view === 'create' && (
                                <div className="space-y-4 bg-slate-50 p-4 rounded-xl border border-slate-200">
                                    <div>
                                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">País</label>
                                        <select 
                                            value={selectedCountry} 
                                            onChange={e => {
                                                setSelectedCountry(e.target.value);
                                                setSelectedRegion('');
                                                setSelectedZone('');
                                                setSelectedCity('');
                                            }}
                                            className="w-full px-3 py-2 border border-slate-300 rounded-lg text-sm font-bold text-slate-700"
                                        >
                                            <option value="ES">España 🇪🇸</option>
                                            {INTERNATIONAL_COUNTRIES.map(c => (
                                                <option key={c.id} value={c.id}>{c.name} {COUNTRY_FLAGS[c.id]}</option>
                                            ))}
                                        </select>
                                    </div>

                                    {selectedCountry === 'ES' ? (
                                        <>
                                            <div>
                                                <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Comunidad Autónoma</label>
                                                <select 
                                                    value={selectedRegion} 
                                                    onChange={e => {
                                                        setSelectedRegion(e.target.value);
                                                        setSelectedZone('');
                                                        setSelectedCity('');
                                                    }}
                                                    className="w-full px-3 py-2 border border-slate-300 rounded-lg text-sm"
                                                    disabled={!selectedCountry}
                                                >
                                                    <option value="">Seleccionar...</option>
                                                    {SPANISH_GEOGRAPHY.map(r => (
                                                        <option key={r.id} value={r.id}>{r.name}</option>
                                                    ))}
                                                </select>
                                            </div>

                                            <div>
                                                <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Zona Provincial</label>
                                                <select 
                                                    value={selectedZone} 
                                                    onChange={e => {
                                                        setSelectedZone(e.target.value);
                                                        setSelectedCity('');
                                                    }}
                                                    className="w-full px-3 py-2 border border-slate-300 rounded-lg text-sm"
                                                    disabled={!selectedRegion}
                                                >
                                                    <option value="">Seleccionar...</option>
                                                    {getAvailableZones().map(z => (
                                                        <option key={z.id} value={z.id}>{z.name}</option>
                                                    ))}
                                                </select>
                                            </div>

                                            <div>
                                                <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Ciudad Sede</label>
                                                <select 
                                                    value={selectedCity} 
                                                    onChange={e => setSelectedCity(e.target.value)}
                                                    className="w-full px-3 py-2 border border-slate-300 rounded-lg text-sm"
                                                    disabled={!selectedZone}
                                                >
                                                    <option value="">Seleccionar...</option>
                                                    {getAvailableCities().map(c => (
                                                        <option key={c} value={c}>{c}</option>
                                                    ))}
                                                </select>
                                            </div>
                                        </>
                                    ) : (
                                        <div>
                                            <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Ciudad</label>
                                            <input 
                                                value={selectedCity} 
                                                onChange={e => setSelectedCity(e.target.value)}
                                                className="w-full px-3 py-2 border border-slate-300 rounded-lg text-sm"
                                                placeholder="Ej. París, Londres..."
                                            />
                                        </div>
                                    )}
                                </div>
                            )}
                        </div>

                        <div className="space-y-6">
                             <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider">Diseño del Logo</label>
                             <div className="flex justify-center mb-2">
                                <div className={`relative w-24 h-24 rounded-full flex items-center justify-center text-4xl shadow-xl border-4 border-white transition-all ${CLUB_COLORS[selectedColorIndex].bg}`}>
                                    <span className={CLUB_COLORS[selectedColorIndex].hex}>{selectedIcon}</span>
                                    {/* Preview Flag */}
                                    {view === 'create' && selectedCountry && (
                                        <div className="absolute -bottom-2 -right-2 w-8 h-8 bg-white rounded-full flex items-center justify-center shadow-md border border-slate-100 text-lg">
                                            {COUNTRY_FLAGS[selectedCountry]}
                                        </div>
                                    )}
                                </div>
                             </div>

                             <div>
                                <label className="text-[10px] font-bold text-slate-400 mb-2 block uppercase">Icono</label>
                                <div className="grid grid-cols-5 gap-2">
                                    {CLUB_ICONS.map(icon => (
                                        <button key={icon} type="button" onClick={() => setSelectedIcon(icon)} className={`p-2 rounded-lg hover:bg-slate-100 text-xl transition-all ${selectedIcon === icon ? 'bg-blue-100 ring-2 ring-blue-500 shadow-sm' : ''}`}>{icon}</button>
                                    ))}
                                </div>
                             </div>

                             <div>
                                <label className="text-[10px] font-bold text-slate-400 mb-2 block uppercase">Color</label>
                                <div className="grid grid-cols-5 gap-2">
                                    {CLUB_COLORS.map((c, i) => (
                                        <button key={c.name} type="button" onClick={() => setSelectedColorIndex(i)} className={`w-8 h-8 rounded-full border-2 transition-all ${c.bg} ${selectedColorIndex === i ? 'border-slate-800 scale-110 shadow-md ring-2 ring-offset-2 ring-slate-300' : 'border-transparent'}`} title={c.name}></button>
                                    ))}
                                </div>
                             </div>
                        </div>
                    </div>

                    <div className="flex gap-4 mt-10">
                        <button type="button" onClick={() => setView('current')} className="flex-1 bg-slate-100 text-slate-600 font-bold py-3 rounded-xl hover:bg-slate-200 transition-colors">
                            Cancelar
                        </button>
                        <button type="submit" className="flex-1 bg-gradient-to-r from-blue-600 to-cyan-600 text-white font-bold py-3 rounded-xl hover:shadow-lg hover:scale-[1.02] transition-all shadow-blue-200">
                            {view === 'create' ? 'Crear Club' : 'Guardar Cambios'}
                        </button>
                    </div>
                </form>
            )}

            {view === 'list' && (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {availableClubs.length === 0 && (
                         <div className="col-span-2 text-center py-12 bg-white/80 rounded-xl text-slate-500 font-medium">
                            No hay clubes creados. ¡Sé el primero en fundar uno!
                         </div>
                    )}
                    {availableClubs.map(club => (
                        <div key={club.id} className="glass-panel p-5 rounded-2xl flex items-center gap-4 hover:border-blue-400 transition-all hover:shadow-md cursor-pointer group">
                            <div className={`relative w-14 h-14 rounded-full flex items-center justify-center text-2xl shrink-0 shadow-md border-2 border-white group-hover:scale-110 transition-transform ${club.logo.bgColor}`}>
                                <span className={club.logo.color}>{club.logo.icon}</span>
                                <div className="absolute -bottom-1 -right-1 w-6 h-6 bg-white rounded-full flex items-center justify-center shadow-sm text-xs border border-slate-100">
                                    {COUNTRY_FLAGS[club.location.countryId]}
                                </div>
                            </div>
                            <div className="flex-1">
                                <h4 className="font-bold text-slate-800 text-lg leading-tight group-hover:text-blue-700">{club.name}</h4>
                                <div className="text-xs text-slate-500 mb-1">
                                    {club.location.cityName} {club.location.countryId === 'ES' ? `(${club.location.zoneId})` : ''}
                                </div>
                                <div className="flex justify-between items-center mt-1">
                                    <span className="text-[10px] bg-slate-100 px-2 py-0.5 rounded text-slate-500 font-bold uppercase tracking-wider">Prestigio: {club.prestige}</span>
                                </div>
                            </div>
                            {swimmer.clubId !== club.id ? (
                                <button onClick={() => handleJoin(club)} className="px-4 py-2 bg-slate-800 text-white text-xs font-bold rounded-lg hover:bg-slate-700">Unirse</button>
                            ) : (
                                <span className="text-xs font-bold text-blue-600 bg-blue-50 px-3 py-1.5 rounded-lg border border-blue-100">Tu Club</span>
                            )}
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
};

export enum Attribute {
    Strength = 'Fuerza',
    Technique = 'Técnica',
    Stamina = 'Resistencia',
    Mental = 'Mentalidad',
    Speed = 'Velocidad',
    StartTurn = 'Salidas/Virajes' // New Attribute
}

export enum CompetitionTier {
    Triangular = 'Triangular',
    Provincial = 'Provincial',
    Regional = 'Regional',
    National = 'Nacional',
    InternationalClub = 'Copa Internacional', 
    European = 'Europeo',
    World = 'Mundial'
}

export enum Stroke {
    Freestyle = 'Crol'
}

export interface Stats {
    [Attribute.Strength]: number;
    [Attribute.Technique]: number;
    [Attribute.Stamina]: number;
    [Attribute.Mental]: number;
    [Attribute.Speed]: number;
    [Attribute.StartTurn]: number; // New Attribute
}

export interface ClubLogo {
    icon: string;
    color: string;
    bgColor: string;
}

export interface ClubLocation {
    countryId: string; 
    regionId?: string; 
    zoneId?: string;   
    cityName: string;
}

export interface Club {
    id: string;
    name: string;
    prestige: number;
    description: string;
    logo: ClubLogo;
    location: ClubLocation; 
    ownerId: string; 
}

