}

export interface StartListEntry {
    playerId: string;
    name: string;
    club: string;
    entryTime: number;
    isPlayer: boolean;
}

export interface PastRace {
    id: string;
    tier: CompetitionTier;
    stroke: Stroke;
    distance: number;
    time: number;
    rank: number;
    date: number; 
    realTimeDate: number; 
    zoneName?: string; 
}

